INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS6SG2AJWY0SJ52FEEHD246K','locations','01KS6PG5J7N4GKKA7EVQ375A7Z','{"location_name": "Chesapeake, VA", "address": [{"_type": "block", "_key": "01ks6sg2a34rfhj2ehxtv9awfd", "style": "h3", "children": [{"_type": "span", "_key": "01ks6sg2a3rpvm9sb5ajmyvnck", "text": "1021 Eden Way N #110, Chesapeake, VA 23320, United States", "marks": ["01ks6sg2a30gey44k6kj86y515"]}], "markDefs": [{"_key": "01ks6sg2a30gey44k6kj86y515", "_type": "link", "href": "https://www.google.com/maps/dir//Maico+Audiological+Services,+1021+Eden+Way+N+%23124,+Chesapeake,+VA+23320,+United+States/@36.7764015,-76.224836,17z/data=!3m1!5s0x89babcf620a07109:0x4d5be306d1ca2382!4m16!1m7!3m6!1s0x89babc589e189487:0x63b259b91e1dbb8f!2sMaico+Audiological+Services!8m2!3d36.7764015!4d-76.224836!16s%2Fg%2F1tg3b_hq!4m7!1m0!1m5!1m1!1s0x89babc589e189487:0x63b259b91e1dbb8f!2m2!1d-76.224836!2d36.7764015?entry=ttu&g_ep=EgoyMDI1MTAxMi4wIKXMDSoASAFQAw%3D%3D"}]}], "phone_number": [{"_type": "block", "_key": "01ks6sg2a5jc1743sk2v71ppsr", "style": "h3", "children": [{"_type": "span", "_key": "01ks6sg2a5r6dt7jwmdyfsemvq", "text": "Text or call: (757) 383-8787", "marks": ["01ks6sg2a5ejpz0h2ncrmnmx8m"]}], "markDefs": [{"_key": "01ks6sg2a5ejpz0h2ncrmnmx8m", "_type": "link", "href": "tel:7573838787"}]}], "phone_number_url": "tel:7573838787", "office_hours": "Monday – Friday: 9am-5pm", "map_url": "https://www.google.com/maps/dir//Maico+Audiological+Services,+1021+Eden+Way+N+%23124,+Chesapeake,+VA+23320,+United+States/@36.7764015,-76.224836,17z/data=!3m1!5s0x89babcf620a07109:0x4d5be306d1ca2382!4m16!1m7!3m6!1s0x89babc589e189487:0x63b259b91e1dbb8f!2sMaico+Audiological+Services!8m2!3d36.7764015!4d-76.224836!16s%2Fg%2F1tg3b_hq!4m7!1m0!1m5!1m1!1s0x89babc589e189487:0x63b259b91e1dbb8f!2m2!1d-76.224836!2d36.7764015?entry=ttu&g_ep=EgoyMDI1MTAxMi4wIKXMDSoASAFQAw%3D%3D", "map_widget": "https://maps.app.goo.gl/6uAhBfkPKfAhwFTKA", "location_image_1