INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS71KWK2A7436WQ8X09NRV2D','homepage','01KS6DYPBMTW72P0G8ZF6NNM91','{"hero_intro": "It’s time to hear and be heard.", "hero_cta": "/book-appointment/", "intro_section_title": "AUDIOLOGISTS & HEARING AIDS IN VIRGINIA", "intro_body": [{"_type": "block", "_key": "01ks71kwj4q4cyqsrvz0qs72qc", "style": "h2", "children": [{"_type": "span", "_key": "01ks71kwj4m3eax1spsxep7294", "text": "Virginia Audiologists & Hearing Aids", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj49sjw17w879nv70kd", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj4a14tzft6qj7095m2", "text": "At Maico Audiological Services, our compassionate team is dedicated to restoring your connection to the world around you. Whether you’re struggling in noisy environments, turning up the volume just to follow conversations, or missing the little details that make life vibrant, we provide comprehensive hearing care, from precise testing to personalized hearing aid fittings.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj4v53pea21mdnefrx7", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj4hgb0syrb3s4jrzav", "text": "Experience personalized hearing care you can trust!", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj48834n08a385hr1qq", "style": "h2", "children": [{"_type": "span", "_key": "01ks71kwj4m0n004g8g1wpw6y9", "text": "Maico Audiological Services", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj4jjfqsrg11jqfrdk7", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj4t58wakkjj4zw1kgb", "text": "At Maico Audiological Services, we understand how hearing loss can sneak up on you, making everyday moments harder to enjoy. You might find yourself straining to follow conversations, feeling tired from the effort of listening, or missing out on the sounds that bring joy to your life.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj4axrm10z88tyggqf0", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj4hxkn03qs59yg8qkz", "text": "Let our experienced audiologists and hearing instrument specialist in Virginia help you rediscover clearer hearing and reconnect with the people and moments that matter most.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj4d2ddp2g0vkaz2hg6", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj4qz50t5yxhv9n2mtd", "text": "Let us help you regain the joy of hearing and the quality of life you deserve.", "marks": []}], "markDefs": []}], "badge_1": {"id": "01KS5SV5PQAQMSB7P0BFQCNW9J", "src": "/_emdash/api/media/file/01KS5SV5NRFH2XS3DGWN9EERNM.webp", "alt": "American Academy of Audiology logo with ear and sound wave icon on black background", "width": 340, "height": 240}, "badge_2": {"id": "01KS5SV6JYM3GXH893QNDZR7VX", "src": "/_emdash/api/media/file/01KS5SV6G5XGR80QE1M4ZCVT2B.webp", "alt": "ASHA logo with teal icon showing two profile silhouettes and sound waves on black background", "width": 340, "height": 240}, "badge_3": {"id": "01KS5SXMN63W2Z5H2H0FZD5YD6", "src": "/_emdash/api/media/file/01KS5SXMKSERDQZCEFDEXASTD5.png", "alt": "Google logo with five gold stars and text showing 100+ reviews", "width": 143, "height": 114}, "audiology_services_featured_image": {"id": "01KS5SX9AD75S0E571980ANF51", "src": "/_emdash/api/media/file/01KS5SX93TVJ39PS3A2SPNDHMM.png", "alt": "Audiologist conducting hearing test with patient visible through soundproof booth window", "width": 534, "height": 601}, "audiology_services_body": [{"_type": "block", "_key": "01ks71kwj8kqgmjcjed765khhb", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwj8dcghh8ns5p7bdmb3", "text": "Hearing Evaluations", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj8kg14dp6stvnbwts9", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj8fmsg06cd9gzf0pvb", "text": "At Maico Audiological Services, we offer complete hearing evaluations to better understand your hearing health. Our tests help determine the type and level of hearing loss you may be experiencing, so we can recommend solutions that are tailored to your lifestyle and needs.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj9x7hrc8yy7qtxet2y", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwj9n53tmhtb47b9hgt1", "text": "Sensorineural Hearing Loss Evaluation & Treatment", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj9577n32vf3zpf522y", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj92vwate6f9khah89d", "text": "Sensorineural hearing loss is the most common type of permanent hearing loss, often caused by aging, noise exposure, or inner ear damage. Our experienced hearing instrument specialist will perform a thorough hearing evaluation to determine the degree and type of hearing loss. ", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj905rybckq3nwjqpkh", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwj91g72ry4pbmrthbbf", "text": "Tinnitus Evaluations & Treatment", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj9fj4dv0t8d1jw34yy", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj9cmdkfzc7g38mqydc", "text": "Struggling with ringing, buzzing, or humming in your ears? Our audiologists provide complete tinnitus evaluations to uncover the cause and create a personalized treatment plan. From hearing aids and sound therapy to lifestyle guidance, we’ll help reduce the impact of tinnitus so you can enjoy better focus, sleep, and peace of mind.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj9ypmc6gn8kf2eq032", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj9f1t5qgxj5m1jr90g", "text": "If tinnitus persists or worsens, we may recommend a referral to an ENT (ear, nose, and throat) physician for further evaluation. Working together, we can help ensure you receive the best possible care.”", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj91104j7kjk3jdcac4", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwj98qh5ncdfbssb5xkp", "text": "Hearing Aid Services", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj9kqzgx4g6jce4x9sn", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj9dt4c70m5v2jmk3jq", "text": "From helping you choose the right hearing aid to providing expert fittings, cleanings, and repairs, we’re here for every step of your hearing journey. Our goal is to ensure you always enjoy clear, comfortable sound wherever life takes you.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwj9c31etx7hhyhfh7fq", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwj9xkt06ceaq0c6dswh", "text": "Hearing Aid Fittings", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjab9vzhhdkn1y93j6c", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwja0p2f65yectx1vcmt", "text": "Getting the perfect fit is key to getting the most out of your hearing aids. Our hearing instrument specialist will make sure your devices are properly adjusted for your hearing loss, comfort, and lifestyle, giving you the best hearing experience possible.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjase9x3yg8s3773c43", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwja3z8tj34f9ktphpbk", "text": "Hearing Aid Cleaning and Repair", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwja2w3k39pan3cqwjpv", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwjankaakrhzch7xtn46", "text": "If your hearing aid isn’t working quite right, don’t worry, we can help. We offer fast, reliable cleaning and repair services to keep your devices functioning at their best so you can keep hearing clearly.", "marks": []}], "markDefs": []}], "hearing_aids_protection_solutions_image": {"id": "01KS5SX4QRBXGHD1NQ48WCS28X", "src": "/_emdash/api/media/file/01KS5SX4JJZ84T7F7QHZ058PDZ.jpg", "alt": "", "width": 800, "height": 533}, "hearing_aids_protection_solutions_body": [{"_type": "block", "_key": "01ks71kwjehgxp10xa1m7etjj3", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwjekmbxjkw0ybqbf04t", "text": "Custom Ear Protection", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjftt9t8ct07af1x6q2", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwjfxdremxa3j81zk9pt", "text": "Whether you’re a hunter, musician, swimmer, or work in loud environments, we offer custom-fit earplugs that provide the protection you need. Our audiologists will make sure your ear protection fits comfortably and works effectively.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjfgwt9jxv5bv2fse82", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwjf16fe2phkfze978p0", "text": "Hearing Aids", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjfabsew9xpdr28q639", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwjfxpxhmdsew3sg1kb3", "text": "We carry a wide range of high-quality hearing aids from trusted brands like Phonak, Oticon, ReSound, Unitron, Widex, Starkey, and Signia. We’ll help you find the right solution based on your unique hearing needs, lifestyle, and budget.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjf5h0nrzasy4nb2heq", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwjfvqxpfngt4kae3r20", "text": "Hearing Aid Batteries and Accessories", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjf1qgx4xrtp0193pjs", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwjfpz2vxvf3hy6g6k93", "text": "Keep your hearing aids working their best with our selection of essential accessories. We offer batteries, cleaning kits, drying tools, and more. We make it easy to take care of your hearing aids so you can rely on them every day.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjft8r3yw6w75vf7ch2", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwjf06hzkzksm0myvgg2", "text": "Assistive Listening Devices", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwjfqgcnetd4c473zekn", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwjfxq96g0hp0fd9wd5a", "text": "If you find it hard to hear clearly on the phone, in noisy settings, or while watching TV, our assistive listening devices can help. We offer solutions like CaptionCall phones that display real-time captions, making conversations easier to follow. Enjoy clearer hearing at home, at work, or on the go with ALDs tailored to your needs.", "marks": []}], "markDefs": []}], "hearing_aid_brand_image_1": {"id": "01KS5SV34RXYWJ3C0NZ67YF1GJ", "src": "/_emdash/api/media/file/01KS5SV33P6YKTC1NH9FXWZXKQ.png", "alt": "5d9c3eb94b8bdfdaf3550c8c9eb8ec99ee179a8f", "width": null, "height": null}, "hearing_aid_brand_image_2": {"id": "01KS5SX6QDPJCV8R60M3MAB2V8", "src": "/_emdash/api/media/file/01KS5SX6FFNPS2844KCVW26YE4.png", "alt": "e8e0fa55c783cc5eeb2f48b009e1e095ac8d6e81", "width": null, "height": null}, "hearing_aid_brand_image_3": {"id": "01KS5SV5E7VSNS8SCEENTT5X6B", "src": "/_emdash/api/media/file/01KS5SV5CJ5BN9225CSDEJD9K2.png", "alt": "9630f9ccdd250ed5d95e8dc192ec9ee4edd82d78", "width": null, "height": null}, "hearing_aid_brand_image_4": {"id": "01KS5SV92516N24G10G09YQQA4", "src": "/_emdash/api/media/file/01KS5SV90P99MCQ494D1F920MS.png", "alt": "df20d30b24e0e24425ac05171bd6c1a6fc636e81", "width": null, "height": null}, "hearing_aid_brand_image_5": {"id": "01KS5SV020V66CW6Z79JN1EMRS", "src": "/_emdash/api/media/file/01KS5STZWAV2YFBVDSFK6M3HGS.png", "alt": "0fe542364bad1d04cf43fe57ffe07dbe48c47f61", "width": null, "height": null}, "hearing_aid_brand_image_6": {"id": "01KS5SV4R6X07QJ9322PP06YAQ", "src": "/_emdash/api/media/file/01KS5SV4PZM1JA54ZKPV91GWN6.png", "alt": "88d181692132923dbbbe93e746ab1c04b78c12d1", "width": null, "height": null}, "hearing_aid_brand_image_7": {"id": "01KS5SV74KW7EWEFPGT0CK4424", "src": "/_emdash/api/media/file/01KS5SV73D8F1K871VYA5SD8ZQ.png", "alt": "c9e2e0c48788d7e2452b75bf4158177f9fac0e08", "width": null, "height": null}, "testimonial_section_title": "What Our Patients Are Saying", "testimonial_eyebrow": "Real Reviews & Testimonials", "faq_section_title": "Frequently Asked Questions", "faq_eyebrow": "Find Answers", "faq_description": [{"_type": "block", "_key": "01ks71kwj4evd98wk3x2j57jmt", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwj43922yza3scnc86p1", "text": "Can’t find the answers you’re looking for? ", "marks": []}, {"_type": "span", "_key": "01ks71kwj4qq79zbgtktwrtz5g", "text": "Contact Us.", "marks": ["01ks71kwj43grkpbq6dc33ts96"]}], "markDefs": [{"_key": "01ks71kwj43grkpbq6dc33ts96", "_type": "link", "href": "/contact/"}]}], "faq_content": [{"_type": "block", "_key": "01ks71kwk1kh8mbfbm0khhmb0h", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwk1nhwwg2tdaaaaf6w0", "text": "How do I know if I need a hearing aid?", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwk101vet63ht531sjy1", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwk1agm4p2dqn5a0mh84", "text": "If you’re finding it hard to follow conversations (especially in noisy places) frequently increasing the TV volume, or feeling left out during social gatherings, it may be time for a hearing evaluation. An audiologist at Maico Audiological Services can assess your hearing and determine if a hearing aid is the right solution for you.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwk10sk0c035vd2rhbm9", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwk1r8x9bzv1fr8cd4hn", "text": "What is the difference between hearing aids and personal sound amplification products (PSAPs)?", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwk1676m0c1hfca2w670", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwk1z6135f37ysj41tx0", "text": "Hearing aids are FDA-regulated medical devices designed to treat hearing loss. They are professionally fitted and programmed to your hearing needs. PSAPs, however, are general amplifiers meant for individuals without hearing loss and do not provide the same level of customization, support, or effectiveness.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwk1mgpzh16d2khzptc2", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwk1sx0japkmxs68ghw0", "text": "Can I get a hearing aid without a hearing test?", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwk27k5s21tj5f44d022", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwk2yy4ea5dvfnr87kbm", "text": "Yes, over-the-counter (OTC) hearing aids are available without a hearing test and are designed for adults with mild to moderate hearing loss. However, having a professional hearing evaluation at Maico Audiological Services ensures your hearing aid is matched to your specific needs and helps rule out any underlying medical conditions.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwk2kh76rvst3vs0gm1z", "style": "h3", "children": [{"_type": "span", "_key": "01ks71kwk204nkg9g8gt4wps5z", "text": "How long do hearing aids last?", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks71kwk2w09smj4jnsar8js7", "style": "normal", "children": [{"_type": "span", "_key": "01ks71kwk2hn5t6rfe96gahs01", "text": "Most hearing aids last between 3 to 7 years, depending on the model, how well they’re maintained, and how often they’re used. Regular cleanings, proper storage, and routine check-ups with your audiologist or hearing instrument specialist can help extend the life of your devices. As technology improves, many people choose to upgrade sooner to benefit from the latest features and better performance.", "marks": []}], "markDefs": []}]}','01KS5S2H9D5GVDNPH6HQ00BNCN','2026-05-22 13:13:03');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS722FSKTAXVKZ8QZBD5HDDF','team','01KS70BJZN72S0MH8601TNT9C1','{"name": "Jennifer Flamini, H.I.S, CDP", "team_title": "Hearing Instrument Specialist", "location": "Chesapeake, VA, Smithfield, VA", "biography": [{"_type": "block", "_key": "01ks722fsj9ddgthhqkxrr3rqa", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsj5wf94b0gvnvb1gz7", "text": "Jenny Flamini is a hearing instrument specialist providing hearing tests, hearing aids, and professional hearing services in Smithfield, VA and Chesapeake,VA. ", "marks": ["strong", "em"]}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsjf8352xn3rk4kxyew", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsjbhn5v05dhdj9t53n", "text": "Jennifer Flamini, H.I.S., CDP, is a licensed Hearing Instrument Specialist and Certified Dementia Practitioner at Maico Audiological Services in Smithfield, VA. She is a passionate advocate for hearing health and is dedicated to improving the lives of those experiencing hearing loss.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsj0qwarm01193qbctk", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fsjfm8kv4gpx3194f2b", "text": "Journey into Hearing Healthcare", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsjg84br7zwfykjgrwh", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsjw3he8wg6bbe9gr08", "text": "Jennifer’s interest in hearing care began with her own family and friends. After accompanying loved ones to appointments for hearing loss, she witnessed firsthand the powerful impact hearing aids can have. These personal experiences inspired her to pursue training, licensure, and hands-on work in hearing healthcare, transforming her concern for family into a lifelong passion for helping others hear better.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsjq6thbzmpvyhn9d0g", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fsj3813dagscgcq98dp", "text": "Patient Care Philosophy", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsj8kphxkt2m13mvhk3", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsjjz0b348eqqnbpza2", "text": "Her mission is simple: to help as many people as possible achieve optimal hearing, enhancing their daily lives and strengthening connections with family and friends. She strives to provide a welcoming, supportive environment and the best possible care for each individual she serves.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsjhqq5g3kh6sggpr45", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fsjy3adx9zkh3t1a819", "text": "Personal Interests", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsj1zyajg25y9avezzx", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsjy7q43122n53rned4", "text": "Outside of her professional role, Jennifer enjoys photography, landscaping, DIY home projects, and spending time with her family, friends, and beloved pets.", "marks": []}], "markDefs": []}], "featured_image": {"id": "01KS5SXE8CE2YDYYTQ1H1JVXZ0", "src": "/_emdash/api/media/file/01KS5SXE77YRAEAQ42VRSC5N0Q.webp", "alt": "", "width": 788, "height": 1024}, "meta_title": "Jenny Flamini, H.I.S, CDP | Maico Audiological Services", "meta_description": "Jenny Flamini is a hearing instrument specialist providing hearing tests, hearing aids, and professional hearing services in Smithfield, VA."}','01KS5S2H9D5GVDNPH6HQ00BNCN','2026-05-22 13:21:02');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS722FTTT2R27HCD85H0N8Q1','team','01KS70BK17MFTKKJD2RXDWFV42','{"name": "Stephanie Howard, M.A., CCC-A", "team_title": "Audiologist", "location": "Chesapeake, VA", "biography": [{"_type": "block", "_key": "01ks722ftsf9z6mcqw01j49n9b", "style": "normal", "children": [{"_type": "span", "_key": "01ks722ftstndzvmwnp324rpyv", "text": "Stephanie R. Howard is an audiologist providing hearing tests, hearing aids, sensorineural hearing loss treatment and evaluation, tinnitus evaluation and treatment in Chesapeake, VA.", "marks": ["strong", "em"]}], "markDefs": []}, {"_type": "block", "_key": "01ks722fts9j9w7qm134nr3tca", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fts9xs7zjqd39sc2afb", "text": "Stephanie Howard began her academic journey in audiology at East Carolina University, where she earned her Bachelor of Science degree. She went on to complete her Master of Arts degree in Audiology at the University of Tennessee–Knoxville.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722ftsyeyemt3mc5vvatx4", "style": "h2", "children": [{"_type": "span", "_key": "01ks722ftspa79k4f22fydr1zr", "text": "Professional Credentials", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fts0gwvh5gh3782kx49", "style": "normal", "children": [{"_type": "span", "_key": "01ks722ftsfvhhd5g2d8wf3qx3", "text": "With more than 30 years of professional experience, Stephanie holds multiple credentials that highlight her dedication to the field of audiology:", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722ftskh75j0dvhmey4qbx", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fts6gtgppdmfyyvyc3d", "text": "Certificate of Clinical Competence in Audiology (CCC-A)", "marks": ["strong"]}, {"_type": "span", "_key": "01ks722fts412akbywgf5f8q7b", "text": " from the American Speech-Language-Hearing Association (ASHA)", "marks": []}], "markDefs": [], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "01ks722fts58yfbc20gasec8td", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fts67hj6ey5y5kpn10y", "text": "Licensed Audiologist and Hearing Aid Specialist", "marks": ["strong"]}, {"_type": "span", "_key": "01ks722fts9hhzh24rcn64tez9", "text": " in the Commonwealth of Virginia", "marks": []}], "markDefs": [], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "01ks722ftsvg66kh4w8j337j95", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fts7spyyefw3m1mafz0", "text": "Fellow", "marks": ["strong"]}, {"_type": "span", "_key": "01ks722ftsdxxjabk6azyej68v", "text": " of the American Academy of Audiology (AAA)", "marks": []}], "markDefs": [], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "01ks722fts1w5zx97fzhbtw546", "style": "h2", "children": [{"_type": "span", "_key": "01ks722ftsej5d813f3a45e110", "text": "Career Experience", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fts773kaxp9t582tm52", "style": "normal", "children": [{"_type": "span", "_key": "01ks722ftsrnkkscs5xmbqn4hz", "text": "Stephanie has been serving the Tidewater area for over 25 years, offering expert audiological care and hearing aid services to patients of all ages. Prior to joining MAICO in April 2019, she spent decades working alongside ENT physicians as a clinical audiologist, where she specialized in diagnostic hearing evaluations and advanced hearing aid fittings for infants, children, and adults.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722ftsh2gqneb3nqx19aw0", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fts8fc9c25rb0y51h74", "text": "Commitment to Patient Care", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722ftsjk4gmxdv7788emjf", "style": "normal", "children": [{"_type": "span", "_key": "01ks722ftschbbew8jbpm6vd6c", "text": "With her extensive background and compassionate approach, Stephanie is dedicated to helping patients improve their hearing health and overall quality of life. She combines her technical expertise with genuine care, ensuring each patient receives personalized solutions that meet their unique needs.", "marks": []}], "markDefs": []}], "featured_image": {"id": "01KS5SXFVX4PABGR737S1QKSFF", "src": "/_emdash/api/media/file/01KS5SXFTQ7EBMC2YDMDTGREA0.webp", "alt": "", "width": 683, "height": 1024}, "meta_title": "Stephanie R. Howard, M.A., CCC-A | Maico Audiological Services", "meta_description": "Stephanie R. Howard is an audiologist providing hearing tests, hearing aids, and professional audiology services in Chesapeake, VA."}','01KS5S2H9D5GVDNPH6HQ00BNCN','2026-05-22 13:21:02');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES('01KS722FW1KQAJN4E9A745P9HD','team','01KS70BK2E3KASZK6EV0GGT446','{"name": "Tracey E. Hudson, Au.D., CCC-A", "team_title": "Audiologist", "location": "Newport News, VA", "biography": [{"_type": "block", "_key": "01ks722fw0f0se8xwfe826111a", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fw04gcm5aa2s0d1dvz0", "text": "Tracey E. Hudson is an audiologist providing hearing tests, hearing aids, sensorineural hearing loss treatment and evaluation, tinnitus evaluation and treatment in Newport News, VA.", "marks": ["strong", "em"]}], "markDefs": []}, {"_type": "block", "_key": "01ks722fw0h3wg1drdgbcc4w7f", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fw0g4m2s5r9fc2em9rf", "text": "Tracey E. Hudson, Au.D., CCC-A, began her journey in audiology at East Carolina University in Greenville, North Carolina, where she completed her undergraduate degree. Motivated by her passion for helping others and her growing interest in hearing health, she went on to earn her Doctor of Audiology degree from Texas Tech University Health Sciences Center in 2013.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fw0w6cch7b1c4eaff5w", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fw02cx276eyhknhkz1k", "text": "Professional Commitment", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fw0k5y0amz1c264hq7n", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fw073r95knmm12xwqnh", "text": "As an audiologist and healthcare provider, Dr. Hudson is deeply committed to ensuring her patients never miss the important moments in life because of hearing loss. She believes in providing compassionate, individualized care that improves not only hearing but also overall quality of life.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fw06gzb0jmn1jj9vahz", "style": "h2", "children": [{"_type": "s