INSERT INTO "ec_about" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","featured_image","meta_title","meta_description") VALUES('01KS5QYZHH722CQSR1RWHSHQYG','about','published',NULL,NULL,'2026-05-21T17:05:07.121Z','2026-05-22T06:58:23Z','2026-05-21T17:05:07.121Z',NULL,NULL,1,'826fba5bd2074ad380924eb007245cb5',NULL,'en','01KS5QYZHH722CQSR1RWHSHQYG','About','[{"_type": "block", "_key": "5afda00294ca4e4da656", "style": "normal", "children": [{"_type": "span", "_key": "94345e3eb0604166bc99", "text": "Maico Audiological Services is an audiology and hearing aid clinic with audiologists and a hearing instrument specialist providing hearing tests, sensorineural hearing loss evaluation and treatment, tinnitus treatment, hearing protection and professional hearing services in Newport News, VA, Chesapeake, VA, and Smithfield, VA.", "marks": ["strong", "em"]}], "markDefs": []}, {"_type": "block", "_key": "074507cfbd5249c8bd89", "style": "normal", "children": [{"_type": "span", "_key": "413fd2acd9994347844d", "text": "At Maico Audiological Services, our compassionate team is dedicated to restoring your connection to the world around you. Whether you?re struggling in noisy environments, turning up the volume just to follow conversations, or missing the little details that make life vibrant, we provide comprehensive hearing care, from precise testing to personalized hearing aid fittings.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "80730bdbad0f4bf19bf5", "style": "normal", "children": [{"_type": "span", "_key": "aa754088c2fa4d758af1", "text": "Experience personalized hearing care you can trust!", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "6c9667950b794b32bbc7", "style": "normal", "children": [{"_type": "span", "_key": "d3aa980fe3084ff8b74a", "text": "From our audiologists, hearing instrument specialist to our patient care coordinators, we?ll make sure that you get the best hearing care possible!", "marks": []}], "markDefs": []}]','{"id": "01KS5SXMBB28BC3GFTCXKG1XGH", "src": "/_emdash/api/media/file/01KS5SXM4V1F5BQQBZGXNDZ71T.png", "alt": "White commercial building with gabled roof and green shutters", "width": 352, "height": 236}','About Us | Maico Audiological Services','Maico Audiological Services is an audiology and hearing aid clinic with audiologists and hearing instrument specialists providing professional hearing services in Virginia.');
INSERT INTO "ec_blog_post" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","publish_date","author","category","content","featured_image","meta_title","meta_description") VALUES('01KS5Y1MGSNHKYCBNSBWMMZ9FG','ear-candles-what-you-need-to-know','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1MGST47EBFQNR7BB6EQH',NULL,'en','01KS5Y1MGSNHKYCBNSBWMMZ9FG','Ear Candles: What You Need to Know','November 9, 2025','Tracey E. Hudson, Au.D., CCC-A','Hearing','[{"_type": "block", "_key": "b002365", "style": "normal", "children": [{"_type": "span", "_key": "s002364", "text": "As audiologists and hearing instrument specialists, we are often asked about ear candles. Some patients have seen them online, at health stores, or heard about them from friends. They are sometimes advertised as a natural way to remove earwax or “cleanse” the ear."}]}, {"_type": "block", "_key": "b002370", "style": "normal", "children": [{"_type": "span", "_key": "s002366", "text": "While they may sound interesting, it’s very important to know that ear candles are not safe and do not work the way people think they do. Let’s talk about what they are, why people try them, safer options for ear care, and when to see an audiologist for a"}, {"_type": "span", "_key": "s002368", "text": "hearing test", "marks": ["m002367"]}, {"_type": "span", "_key": "s002369", "text": "."}], "markDefs": [{"_type": "link", "_key": "m002367", "href": "/audiology-services/hearing-tests/"}]}, {"_type": "block", "_key": "b002372", "style": "h2", "children": [{"_type": "span", "_key": "s002371", "text": "What Are Ear Candles?"}]}, {"_type": "block", "_key": "b002374", "style": "normal", "children": [{"_type": "span", "_key": "s002373", "text": "Ear candles are hollow cones made of fabric coated in wax, usually beeswax or paraffin. To use them, one end is placed in the ear canal, and the other end is lit on fire. The idea is that the heat creates suction that pulls earwax and debris out of the ear."}]}, {"_type": "block", "_key": "b002376", "style": "normal", "children": [{"_type": "span", "_key": "s002375", "text": "It sounds simple, but research has shown that this method does not create enough suction to remove earwax. In fact, the material you see inside the candle after burning is not earwax at all. It’s just leftover ash and melted candle wax."}]}, {"_type": "block", "_key": "b002378", "style": "h2", "children": [{"_type": "span", "_key": "s002377", "text": "Why Do People Try Ear Candles?"}]}, {"_type": "block", "_key": "b002380", "style": "normal", "children": [{"_type": "span", "_key": "s002379", "text": "Many people turn to ear candles because they are searching for relief from:"}]}, {"_type": "block", "_key": "b002382", "style": "normal", "children": [{"_type": "span", "_key": "s002381", "text": "Earwax buildup"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002384", "style": "normal", "children": [{"_type": "span", "_key": "s002383", "text": "Ear pressure or fullness"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002386", "style": "normal", "children": [{"_type": "span", "_key": "s002385", "text": "Sinus or allergy issues"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002388", "style": "normal", "children": [{"_type": "span", "_key": "s002387", "text": "Ringing in the ears (tinnitus)"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002390", "style": "normal", "children": [{"_type": "span", "_key": "s002389", "text": "Unfortunately, ear candles don’t solve these problems. In many cases, they make things worse."}]}, {"_type": "block", "_key": "b002392", "style": "h2", "children": [{"_type": "span", "_key": "s002391", "text": "The Risks of Ear Candles"}]}, {"_type": "block", "_key": "b002394", "style": "normal", "children": [{"_type": "span", "_key": "s002393", "text": "Ear candles can be dangerous. Here are some of the most common risks:"}]}, {"_type": "block", "_key": "b002396", "style": "normal", "children": [{"_type": "span", "_key": "s002395", "text": "Burns – Hot wax or the flame can burn the ear, face, or hair."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002398", "style": "normal", "children": [{"_type": "span", "_key": "s002397", "text": "Blockages – Candle wax can drip into the ear canal, harden, and cause more blockage."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002400", "style": "normal", "children": [{"_type": "span", "_key": "s002399", "text": "Injury – Placing objects in the ear can damage the eardrum or ear canal."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002402", "style": "normal", "children": [{"_type": "span", "_key": "s002401", "text": "Delay in Care – Relying on ear candles may keep people from getting proper medical or hearing care when they really need it."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002404", "style": "normal", "children": [{"_type": "span", "_key": "s002403", "text": "The U.S. Food and Drug Administration (FDA) has even issued warnings against ear candling because of these risks."}]}, {"_type": "block", "_key": "b002406", "style": "h2", "children": [{"_type": "span", "_key": "s002405", "text": "Safer Alternatives for Cleaning Ears"}]}, {"_type": "block", "_key": "b002408", "style": "normal", "children": [{"_type": "span", "_key": "s002407", "text": "The good news is that there are safe and effective ways to care for your ears. Some options include:"}]}, {"_type": "block", "_key": "b002411", "style": "normal", "children": [{"_type": "span", "_key": "s002409", "text": "Letting Your Ears Clean Themselves", "marks": ["strong"]}, {"_type": "span", "_key": "s002410", "text": "Most ears naturally push wax out on their own. In many cases, you don’t need to do anything."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002414", "style": "normal", "children": [{"_type": "span", "_key": "s002412", "text": "Gentle Cleaning at Home", "marks": ["strong"]}, {"_type": "span", "_key": "s002413", "text": "Use a soft washcloth to clean only the outer part of your ear. Avoid putting cotton swabs or objects inside your ear canal."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002417", "style": "normal", "children": [{"_type": "span", "_key": "s002415", "text": "Ear Drops", "marks": ["strong"]}, {"_type": "span", "_key": "s002416", "text": "Over-the-counter drops, mineral oil, or baby oil can soften earwax and help it come out naturally."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002423", "style": "normal", "children": [{"_type": "span", "_key": "s002418", "text": "Professional Ear Wax Removal", "marks": ["strong"]}, {"_type": "span", "_key": "s002419", "text": "At Maico Audiological Services, we can safely remove earwax in the office. This process is quick, comfortable, and avoids the risks that come with unsafe methods like ear candling. Contact us to schedule an"}, {"_type": "span", "_key": "s002421", "text": "ear wax removal in Chesapeake, VA", "marks": ["m002420"]}, {"_type": "span", "_key": "s002422", "text": "."}], "markDefs": [{"_type": "link", "_key": "m002420", "href": "/audiologist-hearing-aids-chesapeake-va/"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002425", "style": "h2", "children": [{"_type": "span", "_key": "s002424", "text": "When to See a Professional"}]}, {"_type": "block", "_key": "b002427", "style": "normal", "children": [{"_type": "span", "_key": "s002426", "text": "You should schedule a visit with an audiologist or hearing instrument specialist if you experience:"}]}, {"_type": "block", "_key": "b002429", "style": "normal", "children": [{"_type": "span", "_key": "s002428", "text": "A feeling of fullness or pressure in your ears"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002431", "style": "normal", "children": [{"_type": "span", "_key": "s002430", "text": "Trouble hearing"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002433", "style": "normal", "children": [{"_type": "span", "_key": "s002432", "text": "Ear pain"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002435", "style": "normal", "children": [{"_type": "span", "_key": "s002434", "text": "Ringing in your ears (tinnitus)"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002437", "style": "normal", "children": [{"_type": "span", "_key": "s002436", "text": "These symptoms may mean you have too much earwax or another ear problem. The safest choice is to have your ears checked by a professional."}]}, {"_type": "block", "_key": "b002439", "style": "h2", "children": [{"_type": "span", "_key": "s002438", "text": "Schedule Your Professional Ear Wax Removal in Virginia"}]}, {"_type": "block", "_key": "b002444", "style": "normal", "children": [{"_type": "span", "_key": "s002440", "text": "At"}, {"_type": "span", "_key": "s002442", "text": "Maico Audiological Services", "marks": ["m002441"]}, {"_type": "span", "_key": "s002443", "text": ", we care about your hearing health. While ear candles may look like a simple solution, they are unsafe and ineffective. Your ears are delicate, and they deserve safe care."}], "markDefs": [{"_type": "link", "_key": "m002441", "href": "/"}]}, {"_type": "block", "_key": "b002446", "style": "normal", "children": [{"_type": "span", "_key": "s002445", "text": "If you feel like your ears are clogged or you’re noticing changes in your hearing, don’t take chances with ear candles."}]}, {"_type": "block", "_key": "b002448", "style": "normal", "children": [{"_type": "span", "_key": "s002447", "text": "Call our offices in Newport News, Chesapeake, or Smithfield, VA today to schedule an appointment."}]}]','{"id": "01KS5SX77E9BTVQ9JTJ9JPCXZN", "src": "/_emdash/api/media/file/01KS5SX6ZY1DW6DKHV7CAXM4XP.jpg", "alt": ""}','Ear Candles | Maico Audiological Services','Thinking about trying ear candles? Learn why they’re unsafe and discover safer options from an audiologist. Call today for expert hearing care in Virginia.');
INSERT INTO "ec_blog_post" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","publish_date","author","category","content","featured_image","meta_title","meta_description") VALUES('01KS5Y1MHVADNDT5BMBYJ9CKZT','hearing-aids-for-tinnitus','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21T22:54:19.486Z','2026-05-22T02:51:25.000Z',NULL,NULL,3,'01KS6BYBCMGR7DZN0QER8JRZ38',NULL,'en','01KS5Y1MHVADNDT5BMBYJ9CKZT','Hearing Aids for Tinnitus: How They Help You Find Relief and Hear Better','December 10, 2025','Tracey E. Hudson, Au.D., CCC-A','Hearing','[{"_type":"block","_key":"9u5gqzwvs","style":"normal","children":[{"_type":"span","_key":"nrk2g1672","text":"Tinnitus can sound like ringing, buzzing, or hissing in your ears, and it can make daily life stressful. Hearing aids for tinnitus can help by making real sounds louder, which can make the tinnitus less noticeable. In this article, you’ll learn how tinnitus works, how hearing aids can help, what features to look for, and how Maico Audiology supports patients in Newport News, Smithfield, and Chesapeake, VA.","marks":["strong","em"]}]},{"_type":"block","_key":"yj4fwg3yp","style":"normal","children":[{"_type":"span","_key":"7z5zvyoth","text":"If you are tired of the constant ringing or buzzing in your ears, you may be wondering if hearing aids for tinnitus can help. The answer is often yes, especially when tinnitus is linked to hearing loss, which is very common. "},{"_type":"span","_key":"0pfv7jumt","text":"Hearing aids ","marks":["lp0jzktkz"]},{"_type":"span","_key":"2oklmpnp3","text":"do not “cure” tinnitus, but they can reduce how loud it feels and how much it bothers you. They do this by improving your hearing, lowering listening stress, and sometimes adding special relief sounds."}],"markDefs":[{"_type":"link","_key":"lp0jzktkz","href":"/hearing-aids-products/","blank":false}]},{"_type":"block","_key":"53tg2qe1i","style":"normal","children":[{"_type":"span","_key":"2v3yolk09","text":"At Maico Audiology, we help people of all ages better understand tinnitus and find solutions that fit their daily life. With the right evaluation and a personalized plan, many patients feel calmer, sleep better, and enjoy conversations again."}]},{"_type":"block","_key":"v2sd5f1a4","style":"h2","children":[{"_type":"span","_key":"b7axkj2fm","text":"What Is Tinnitus?"}]},{"_type":"block","_key":"xgvo8n376","style":"normal","children":[{"_type":"span","_key":"c74ffs59o","text":"Tinnitus is when you hear a sound that is not coming from the outside world. Many people describe it as:"}]},{"_type":"block","_key":"xn848olx2","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"kkwdkhv78","text":"Ringing"}]},{"_type":"block","_key":"bpjrkmz6o","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"2d6d1ff7c","text":"Buzzing"}]},{"_type":"block","_key":"ccdzmzfnk","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"zf8dsqnxp","text":"Hissing"}]},{"_type":"block","_key":"6rnz6cn51","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"iqphugcqo","text":"Clicking"}]},{"_type":"block","_key":"lnxmlktfl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"j8pwjlizl","text":"Roaring"}]},{"_type":"block","_key":"0b1ghfy26","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"tdva60thu","text":"Whooshing"}]},{"_type":"block","_key":"ck1o91fg1","style":"normal","children":[{"_type":"span","_key":"rlsvk61hn","text":"Tinnitus can be soft or loud. It can come and go, or it can be there all the time. Some people hear it in one ear, while others hear it in both."}]},{"_type":"block","_key":"y3gv7fn8m","style":"normal","children":[{"_type":"span","_key":"edd3dtacc","text":"Tinnitus is not a disease by itself. It is usually a symptom of something else, like hearing loss, noise exposure, stress, or a medical condition."}]},{"_type":"block","_key":"v02p2pglq","style":"h2","children":[{"_type":"span","_key":"ftyqbx3g3","text":"Why Do People Get Tinnitus?"}]},{"_type":"block","_key":"pqqgeku71","style":"normal","children":[{"_type":"span","_key":"tggse38xh","text":"Tinnitus has many possible causes. Some of the most common include:"}]},{"_type":"block","_key":"8lf1ayk2l","style":"h3","children":[{"_type":"span","_key":"23dwdf3fq","text":"Hearing Loss"}]},{"_type":"block","_key":"7ggzf49n4","style":"normal","children":[{"_type":"span","_key":"dv0eyk0q2","text":"This is the biggest reason tinnitus happens. When the ear does not send strong sound signals to the brain, the brain may “fill in the gaps” with tinnitus sounds."}]},{"_type":"block","_key":"ecot363rf","style":"h3","children":[{"_type":"span","_key":"907py0qo5","text":"Loud Noise Exposure"}]},{"_type":"block","_key":"zyxjgs0of","style":"normal","children":[{"_type":"span","_key":"h70npq21z","text":"Concerts, power tools, firearms, and loud workplaces can damage hearing over time. Even one very loud sound can trigger tinnitus."}]},{"_type":"block","_key":"lj2itjejd","style":"h3","children":[{"_type":"span","_key":"0bmni19o7","text":"Earwax Buildup"}]},{"_type":"block","_key":"wfih8v969","style":"normal","children":[{"_type":"span","_key":"62u65yvy1","text":"A blockage can change how sound travels through the ear, making tinnitus more noticeable."}]},{"_type":"block","_key":"ium2lflv4","style":"h3","children":[{"_type":"span","_key":"5imbl5w5a","text":"Ear Infections or Fluid"}]},{"_type":"block","_key":"c32d460yu","style":"normal","children":[{"_type":"span","_key":"7gge1lkum","text":"Inflammation can irritate the ear and increase tinnitus."}]},{"_type":"block","_key":"d0oiewcn7","style":"h3","children":[{"_type":"span","_key":"5npt6473u","text":"Certain Medications"}]},{"_type":"block","_key":"epyi56l2m","style":"normal","children":[{"_type":"span","_key":"79z2jaua5","text":"Some medicines can affect the inner ear. Never stop medication without talking to your doctor."}]},{"_type":"block","_key":"fpo1vz2ji","style":"h3","children":[{"_type":"span","_key":"0ira6lyc3","text":"Stress and Poor Sleep"}]},{"_type":"block","_key":"2wvjufkek","style":"normal","children":[{"_type":"span","_key":"smil9sq7t","text":"Stress can make tinnitus feel louder. Poor sleep can make it harder to cope."}]},{"_type":"block","_key":"ujtppj2b9","style":"h3","children":[{"_type":"span","_key":"qvyksosuv","text":"Jaw Problems (TMJ)"}]},{"_type":"block","_key":"age1jhm65","style":"normal","children":[{"_type":"span","_key":"akt06wkfn","text":"Jaw tension can sometimes affect the ear and cause tinnitus-like symptoms."}]},{"_type":"block","_key":"oxd75cbtm","style":"normal","children":[{"_type":"span","_key":"7jtrvyind","text":"Because tinnitus can have many causes, the best first step is a professional hearing evaluation."}]},{"_type":"block","_key":"f8fbvzwql","style":"h2","children":[{"_type":"span","_key":"xmrazg5xv","text":"Do Hearing Aids Help Tinnitus?"}]},{"_type":"block","_key":"payrzfhye","style":"normal","children":[{"_type":"span","_key":"4ovy7227e","text":"Yes, for many people, hearing aids for tinnitus are one of the most helpful tools available—especially if you also have hearing loss (even mild hearing loss)."}]},{"_type":"block","_key":"7ymnyeglq","style":"normal","children":[{"_type":"span","_key":"riynaypg6","text":"Here’s why hearing aids often work:"}]},{"_type":"block","_key":"mjzp2u6ha","style":"h3","children":[{"_type":"span","_key":"xrv9klkny","text":"1. They Make Real Sounds Louder"}]},{"_type":"block","_key":"q97mt7cqt","style":"normal","children":[{"_type":"span","_key":"341vyksme","text":"When you hear more of the world around you (voices, footsteps, birds, fans), your tinnitus can fade into the background."}]},{"_type":"block","_key":"2cz9jxq1m","style":"h3","children":[{"_type":"span","_key":"hiaw9wjx8","text":"2. They Reduce Listening Strain"}]},{"_type":"block","_key":"qcpnbrzm9","style":"normal","children":[{"_type":"span","_key":"pmmdqykpw","text":"When your brain works less to “guess” what people are saying, your stress level often goes down. Lower stress can make tinnitus feel quieter."}]},{"_type":"block","_key":"x9kw9vfax","style":"h3","children":[{"_type":"span","_key":"8js7xtx63","text":"3. They Improve Focus"}]},{"_type":"block","_key":"9s01z6ikl","style":"normal","children":[{"_type":"span","_key":"fgfd73dva","text":"Hearing aids help you focus on speech instead of the ringing. This can make tinnitus less distracting in daily life."}]},{"_type":"block","_key":"eqkpuvxdp","style":"h3","children":[{"_type":"span","_key":"6pjlxwaig","text":"4. Many Have Built-In Tinnitus Relief Sounds"}]},{"_type":"block","_key":"0c97fz87g","style":"normal","children":[{"_type":"span","_key":"t6v7eepqg","text":"Some hearing aids can play soft relief sounds, like:"}]},{"_type":"block","_key":"0cfiv6jre","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"jfgu00upc","text":"White noise"}]},{"_type":"block","_key":"qq8ewtmm8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"t9mou8m7h","text":"Ocean-like sounds"}]},{"_type":"block","_key":"dzcf04pxr","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"dp01jsxtk","text":"Gentle static or “shhh” sounds"}]},{"_type":"block","_key":"v8ovv28vo","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"w4g8e0nyi","text":"Nature sounds"}]},{"_type":"block","_key":"11lzy1tus","style":"normal","children":[{"_type":"span","_key":"8bjtlnfuo","text":"These are often called masking sounds or sound therapy features."}]},{"_type":"block","_key":"cgyfod8gb","style":"h2","children":[{"_type":"span","_key":"i4pairlfc","text":"How Hearing Aids Work For Tinnitus"}]},{"_type":"block","_key":"b5zph8gwu","style":"normal","children":[{"_type":"span","_key":"a0369hhrz","text":"Masking does not mean “covering tinnitus so you can’t hear it at all.” Instead, it gives your brain another sound to pay attention to. This can make tinnitus feel less sharp or less annoying."}]},{"_type":"block","_key":"wr46ej4oz","style":"normal","children":[{"_type":"span","_key":"i1jcjxi64","text":"Think of it like this:"}]},{"_type":"block","_key":"tqqquhio2","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"3m56o8h8s","text":"In a silent room, tinnitus may stand out."}]},{"_type":"block","_key":"4cw1cz9lr","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"cspm9e4xz","text":"In a room with calm background sound, tinnitus may blend in."}]},{"_type":"block","_key":"a25tg5fdo","style":"normal","children":[{"_type":"span","_key":"9klr7uchx","text":"Hearing aids for tinnitus aim to create a comfortable sound environment so tinnitus bothers you less."}]},{"_type":"block","_key":"8wayug6x7","style":"h2","children":[{"_type":"span","_key":"8dm54fc5p","text":"Who Is a Good Candidate for Hearing Aids for Tinnitus?"}]},{"_type":"block","_key":"sa0u26uk9","style":"normal","children":[{"_type":"span","_key":"3eul5p7n9","text":"You may be a good match if:"}]},{"_type":"block","_key":"8o7st514k","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ulvo4ljmf","text":"You have tinnitus and also struggle to hear speech clearly"}]},{"_type":"block","_key":"kg78mqbid","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"cnk7pmk96","text":"You turn up the TV more than others do"}]},{"_type":"block","_key":"dmjevhoi6","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"whfoj6ism","text":"You have trouble hearing in restaurants"}]},{"_type":"block","_key":"1xt1b6jzn","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ja367dy8t","text":"You feel tired after conversations"}]},{"_type":"block","_key":"lp9zyqzt3","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"em1q497qc","text":"Your hearing test shows mild, moderate, or greater hearing loss"}]},{"_type":"block","_key":"jyowtws1e","style":"normal","children":[{"_type":"span","_key":"ogdiz51c6","text":"Even if your hearing loss is mild, hearing aids may still help reduce tinnitus stress."}]},{"_type":"block","_key":"1cw1zybgq","style":"normal","children":[{"_type":"span","_key":"loj86dm5y","text":"Not sure? That’s normal. A hearing test can give you clarity."}]},{"_type":"block","_key":"9nxikrtov","style":"h2","children":[{"_type":"span","_key":"a89wdtrc8","text":"What Features Should You Look for in Hearing Aids for Tinnitus?"}]},{"_type":"block","_key":"gevta0xqf","style":"normal","children":[{"_type":"span","_key":"g9jazuujl","text":"If tinnitus relief is a goal, these features can help:"}]},{"_type":"block","_key":"fls94fq7m","style":"h3","children":[{"_type":"span","_key":"n2z1j4wzf","text":"Tinnitus Sound Support / Sound Generator"}]},{"_type":"block","_key":"ix35kdvjh","style":"normal","children":[{"_type":"span","_key":"yfs6uyr71","text":"This feature plays masking sounds or calming tones."}]},{"_type":"block","_key":"c44oz7x1s","style":"h3","children":[{"_type":"span","_key":"8f4z6s6ow","text":"Good Noise Management"}]},{"_type":"block","_key":"3glq8tbyl","style":"normal","children":[{"_type":"span","_key":"u4zqp67od","text":"Background noise can make tinnitus feel worse. Hearing aids with strong noise handling can help speech feel clearer."}]},{"_type":"block","_key":"o8g5qk9ea","style":"h3","children":[{"_type":"span","_key":"6283rn4u3","text":"Directional Microphones"}]},{"_type":"block","_key":"vk8t7bo1o","style":"normal","children":[{"_type":"span","_key":"7x70t3zf0","text":"These help you focus on the person speaking in front of you."}]},{"_type":"block","_key":"k9kvtrxel","style":"h3","children":[{"_type":"span","_key":"sg0igc9wd","text":"Bluetooth Connectivity"}]},{"_type":"block","_key":"hixhu3xx0","style":"normal","children":[{"_type":"span","_key":"zjtjpgsjo","text":"You can stream calming sounds, music, or guided relaxation from your phone."}]},{"_type":"block","_key":"83p24iufi","style":"h3","children":[{"_type":"span","_key":"kayp24n2x","text":"App Controls"}]},{"_type":"block","_key":"36tc81edm","style":"normal","children":[{"_type":"span","_key":"bm5ylw2rj","text":"Many people like adjusting volume or tinnitus settings from a smartphone app."}]},{"_type":"block","_key":"6x29ooegl","style":"h3","children":[{"_type":"span","_key":"gpgxby6ii","text":"Comfortable Fit"}]},{"_type":"block","_key":"f8lncbidb","style":"normal","children":[{"_type":"span","_key":"tpc5y9ezo","text":"If the hearing aid feels uncomfortable, you may not wear it enough. Comfort matters for long-term success."}]},{"_type":"block","_key":"4taif2xkc","style":"normal","children":[{"_type":"span","_key":"draa53ike","text":"At Maico Audiology, we match features to your lifestyle, not just your hearing test."}]},{"_type":"block","_key":"njmzvasre","style":"h2","children":[{"_type":"span","_key":"0jsdkho72","text":"What to Expect at a Tinnitus Appointment"}]},{"_type":"block","_key":"k9hy23str","style":"normal","children":[{"_type":"span","_key":"mrg7t9f96","text":"A tinnitus visit is not just “pick a hearing aid.” The goal is to understand what is happening and build a plan that works for you."}]},{"_type":"block","_key":"e7cuvgrgn","style":"h3","children":[{"_type":"span","_key":"1g8qko11q","text":"Step 1: Getting to Know You"}]},{"_type":"block","_key":"zfp5stboa","style":"normal","children":[{"_type":"span","_key":"94lke2y16","text":"We ask questions like:"}]},{"_type":"block","_key":"ic5qdsbuy","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"blmur0jq4","text":"When did tinnitus start?"}]},{"_type":"block","_key":"regz73pdy","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"hm4yugybq","text":"Is it in one ear or both?"}]},{"_type":"block","_key":"gntdxz4o2","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"34ubvrcrc","text":"Is it constant or off and on?"}]},{"_type":"block","_key":"6o1fo41ak","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"mirqocms5","text":"What makes it worse or better?"}]},{"_type":"block","_key":"cp9pdu8xw","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"knuypv511","text":"How is your sleep?"}]},{"_type":"block","_key":"lh3s11tum","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"nz153fle5","text":"How is your stress?"}]},{"_type":"block","_key":"6e9yepefe","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"pgv0uw28p","text":"Any noise exposure history?"}]},{"_type":"block","_key":"1ycbaatyq","style":"h3","children":[{"_type":"span","_key":"fpgtqmznc","text":"Step 2: Ear Exam"}]},{"_type":"block","_key":"e6ofex585","style":"normal","children":[{"_type":"span","_key":"6cj4rgf5f","text":"We check for:"}]},{"_type":"block","_key":"zfuy72yqj","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ftsmq9f2q","text":"Earwax buildup"}]},{"_type":"block","_key":"fbd0rmu4i","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"jjcfasp4j","text":"Signs of infection"}]},{"_type":"block","_key":"uvbzaj0gl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"5uv471bmg","text":"Blockage or irritation"}]},{"_type":"block","_key":"gdbvk1b5l","style":"h3","children":[{"_type":"span","_key":"tz3enpnk1","text":"Step 3: Hearing Testing"}]},{"_type":"block","_key":"a7h4shojk","style":"normal","children":[{"_type":"span","_key":"k8sm877zp","text":"A hearing test helps us see if hearing loss is part of the picture. This matters because hearing loss is one of the top reasons tinnitus happens."}]},{"_type":"block","_key":"65i2eaxzl","style":"h3","children":[{"_type":"span","_key":"oqqv0u99n","text":"Step 4: A Clear Plan"}]},{"_type":"block","_key":"tbzj56rrt","style":"normal","children":[{"_type":"span","_key":"4ikrf5ywe","text":"If hearing aids are a good fit, we explain options. If something else seems likely, we may recommend medical follow-up, too."}]},{"_type":"block","_key":"auif1jfzu","style":"h2","children":[{"_type":"span","_key":"8d9x5dxgf","text":"How Hearing Aids Are Fitted for Tinnitus"}]},{"_type":"block","_key":"uelyihshp","style":"normal","children":[{"_type":"span","_key":"npaledggh","text":"If you choose hearing aids, fitting is important. Hearing aids must be adjusted to your hearing needs and your comfort."}]},{"_type":"block","_key":"nen2enwk3","style":"normal","children":[{"_type":"span","_key":"19cdumdco","text":"During your fitting, you can expect:"}]},{"_type":"block","_key":"96soz1os9","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"lg7yrsui9","text":"Programming based on your hearing test"}]},{"_type":"block","_key":"bx3re6zjw","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"vn7ph6ign","text":"Comfort checks (so nothing feels too tight)"}]},{"_type":"block","_key":"61myo8sny","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"s8tlddeqk","text":"Feedback checks (to prevent whistling)"}]},{"_type":"block","_key":"yv1tl4o8u","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"csph0ev8h","text":"Tinnitus feature setup if your devices include it"}]},{"_type":"block","_key":"yvqrd72lf","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"0ab7elvmb","text":"Real-life listening tips for home and work"}]},{"_type":"block","_key":"jubu0uokf","style":"normal","children":[{"_type":"span","_key":"wvu89eszp","text":"Then we schedule follow-ups because tinnitus relief and hearing comfort often improve with small fine-tuning changes."}]},{"_type":"block","_key":"a987ftxep","style":"h2","children":[{"_type":"span","_key":"5s63smgjh","text":"How Long Does It Take to Adjust?"}]},{"_type":"block","_key":"762tcoxnv","style":"normal","children":[{"_type":"span","_key":"o7itfk27g","text":"Many people notice changes quickly, sometimes the same day. But adjustment can take time, too."}]},{"_type":"block","_key":"3ox3xn0hp","style":"normal","children":[{"_type":"span","_key":"lt2lizwqe","text":"It is normal if:"}]},{"_type":"block","_key":"8gmfbo9ra","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"m1ha9y0g5","text":"Your own voice sounds different at first"}]},{"_type":"block","_key":"79b4351hr","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"05kxseuhx","text":"Every day sounds seem sharper"}]},{"_type":"block","_key":"e4fdkoox8","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"70zt0dr7l","text":"You need a few follow-ups to fine-tune settings"}]},{"_type":"block","_key":"5trk2prqp","style":"normal","children":[{"_type":"span","_key":"b70mq1hzh","text":"Your brain is learning how to process clearer sound again. With consistent wear, most people adapt well."}]},{"_type":"block","_key":"cl7t5m282","style":"h2","children":[{"_type":"span","_key":"51r1pofj4","text":"Other Helpful Tools Alongside Hearing Aids"}]},{"_type":"block","_key":"il251jykx","style":"normal","children":[{"_type":"span","_key":"p0nlm094l","text":"Hearing aids can be a big help, but tinnitus care often works best as a “toolbox.” Other tools may include:"}]},{"_type":"block","_key":"o43yz0j68","style":"h3","children":[{"_type":"span","_key":"s1xx99f7v","text":"Sound Enrichment at Night"}]},{"_type":"block","_key":"sbs65q1hz","style":"normal","children":[{"_type":"span","_key":"ut7ac9qd3","text":"A fan, white noise machine, or soft sound app can make bedtime easier."}]},{"_type":"block","_key":"fp5t69c6v","style":"h3","children":[{"_type":"span","_key":"nzncrdci4","text":"Stress Management"}]},{"_type":"block","_key":"07ih8t5yw","style":"normal","children":[{"_type":"span","_key":"94e34e2s5","text":"Stress can increase tinnitus. Simple steps like breathing exercises, walking, or gentle stretching can help."}]},{"_type":"block","_key":"ow4ukuw3s","style":"h3","children":[{"_type":"span","_key":"bdxppc4gd","text":"Better Sleep Habits"}]},{"_type":"block","_key":"lvbp9a82g","style":"normal","children":[{"_type":"span","_key":"baa8v55u1","text":"Poor sleep makes tinnitus feel louder. A steady bedtime routine can reduce tinnitus distress."}]},{"_type":"block","_key":"u3eq95pe4","style":"h3","children":[{"_type":"span","_key":"wg7iq4d20","text":"Hearing Protection"}]},{"_type":"block","_key":"qrboda2tb","style":"normal","children":[{"_type":"span","_key":"tzn4imh5z","text":"Protect your ears from loud sounds. Hearing protection is important, but wearing earplugs all day in normal sound can sometimes make tinnitus feel louder. We can guide you on smart use."}]},{"_type":"block","_key":"qnuzx97eh","style":"h3","children":[{"_type":"span","_key":"2d3wfozv0","text":"Medical Referral When Needed"}]},{"_type":"block","_key":"mzezl92ne","style":"normal","children":[{"_type":"span","_key":"pt9hbn7ef","text":"If tinnitus is sudden, only in one ear, comes with dizziness, or seems pulse-like, you should get a medical evaluation. We can help guide you for the next steps."}]},{"_type":"block","_key":"loc3qr2oo","style":"h2","children":[{"_type":"span","_key":"d4l9nv7jy","text":"Common Questions People Ask About Hearing Aids for Tinnitus"}]},{"_type":"block","_key":"jyad8q9xh","style":"h3","children":[{"_type":"span","_key":"nj5asnapk","text":"Will hearing aids stop tinnitus completely?"}]},{"_type":"block","_key":"8le63q9q4","style":"normal","children":[{"_type":"span","_key":"0na2svuzv","text":"Not always. But many people notice tinnitus is less noticeable and less stressful when they hear better and use sound therapy features."}]},{"_type":"block","_key":"6f910bnmv","style":"h3","children":[{"_type":"span","_key":"qgztitidq","text":"What if I only have tinnitus and no hearing loss?"}]},{"_type":"block","_key":"cm78q5trh","style":"normal","children":[{"_type":"span","_key":"xz3j4ykmd","text":"Some people still benefit from sound therapy devices or counseling strategies. A hearing test helps decide the best option."}]},{"_type":"block","_key":"bsxyg84lo","style":"h3","children":[{"_type":"span","_key":"73v4ulx2g","text":"Do I have to wear hearing aids all day for tinnitus relief?"}]},{"_type":"block","_key":"c55cmaefa","style":"normal","children":[{"_type":"span","_key":"9ltkxcfrl","text":"Most people get the best results with regular wear. The more your brain gets steady sound input, the better tinnitus blending usually works."}]},{"_type":"block","_key":"gcng4qlqr","style":"h3","children":[{"_type":"span","_key":"8fyxye4jm","text":"Can hearing aids make tinnitus worse?"}]},{"_type":"block","_key":"t29dm6t1f","style":"normal","children":[{"_type":"span","_key":"lgcr3ij8p","text":"When fitted correctly, they should not. Poor programming or overly loud settings can cause discomfort, which is why professional fitting and follow-up matter."}]},{"_type":"block","_key":"yrwumnjnd","style":"h2","children":[{"_type":"span","_key":"ei8i7crdw","text":"When You Should Get Help Right Away"}]},{"_type":"block","_key":"nikmyke3q","style":"normal","children":[{"_type":"span","_key":"4advdoj9u","text":"While tinnitus is often not dangerous, contact a healthcare provider promptly if you have:"}]},{"_type":"block","_key":"vq9r0srff","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"e004g2gcz","text":"Sudden hearing loss"}]},{"_type":"block","_key":"weq1bs7il","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"92dlbs1sk","text":"Tinnitus in only one ear that is new"}]},{"_type":"block","_key":"prmueowdz","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"a4xgsid61","text":"Severe dizziness or spinning"}]},{"_type":"block","_key":"mrly6bg1i","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"0rbumtnky","text":"Ear pain, drainage, or fever"}]},{"_type":"block","_key":"8oc4hxmvg","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"n1cagos1p","text":"A pulsing sound that matches your heartbeat"}]},{"_type":"block","_key":"eavlv2d70","style":"normal","children":[{"_type":"span","_key":"vwnzomwpe","text":"These symptoms can signal issues that need medical evaluation."}]},{"_type":"block","_key":"nqtqun9fo","style":"h2","children":[{"_type":"span","_key":"xgk1eo2y0","text":"Why Choose Maico Audiology in Virginia?"}]},{"_type":"block","_key":"gwnrdlvpw","style":"normal","children":[{"_type":"span","_key":"h2pc3jfq9","text":"At Maico Audiology, we believe tinnitus care should feel personal, calm, and clear. We help patients:"}]},{"_type":"block","_key":"qq6xhjgvn","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"2wvw327pn","text":"Understand what tinnitus means for their hearing health"}]},{"_type":"block","_key":"gy6ecc05v","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"ljan31al4","text":"Get accurate testing and answers"}]},{"_type":"block","_key":"03oemd77n","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"b34y54vab","text":"Explore hearing aids with tinnitus relief options"}]},{"_type":"block","_key":"6xcwm59kl","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"jr2c0hq94","text":"Learn simple daily strategies that make tinnitus easier to live with"}]},{"_type":"block","_key":"erqu1o6oj","style":"normal","listItem":"bullet","level":1,"children":[{"_type":"span","_key":"gdows5r9d","text":"Get follow-up care and ongoing support"}]},{"_type":"block","_key":"oyl7arxnw","style":"normal","children":[{"_type":"span","_key":"4uyybjw2e","text":"We proudly serve patients in Newport News, Smithfield, and Chesapeake, VA, and we’re here to guide you step by step."}]},{"_type":"block","_key":"7oowsera9","style":"h2","children":[{"_type":"span","_key":"7bsmrlsa4","text":"A Simple Next Step"}]},{"_type":"block","_key":"vmi52te7j","style":"normal","children":[{"_type":"span","_key":"kaghsqnmm","text":"Tinnitus can be exhausting. It can interrupt sleep, make quiet moments feel stressful, and make it harder to focus. The good news is you do not have to figure it out alone. With the right plan, many people feel real improvement."}]},{"_type":"block","_key":"3wbv19qns","style":"normal","children":[{"_type":"span","_key":"jvyisflu0","text":"If you are ready to explore hearing aids for tinnitus, start with a professional hearing evaluation. The right information leads to the right solution. At Maico Audiology, we’ll listen to your concerns, explain your results in a clear way, and help you choose the best path forward."}]},{"_type":"block","_key":"nlv1japd2","style":"normal","children":[{"_type":"span","_key":"gjdx9xmxv","text":"And remember: hearing aids for tinnitus are not just about sound. They are about comfort, confidence, and feeling more like yourself again."},{"_type":"span","_key":"4cism64tg","text":"Schedule an appointment","marks":["pln5pi636"]},{"_type":"span","_key":"d5patua6d","text":"today!"}],"markDefs":[{"_type":"link","_key":"pln5pi636","href":"/book-appointment/","blank":false}]}]','{"id":"01KS5SXCHRG7NVSX295207XD5H","provider":"local","filename":"assets__media__Hearing-Aids-for-Tinnitus-How-They-Help-You-Find-Relief-and-Hear-Better-08101a26a3.jpg","mimeType":"image/jpeg","alt":"","meta":{"storageKey":"01KS5SXCF3QFE8J8R6RRKARNTV.jpg","caption":null,"blurhash":"LiNw1hRj-p%2~Ct7J7jtNbayjFWU","dominantColor":"rgb(194,190,191)"}}','Hearing Aids for Tinnitus | Maico Audiological Services','Hearing aids for tinnitus can improve hearing and help reduce ringing in the ears. Visit Maico Audiology to connect with expert audiologists in Virginia.');
INSERT INTO "ec_blog_post" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","publish_date","author","category","content","featured_image","meta_title","meta_description") VALUES('01KS5Y1MJT1R6MR0DADCRFAQC7','hyperacusis-symptoms-diagnosis-risk-factors','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1MJTESM9M31D2QKW4KJV',NULL,'en','01KS5Y1MJT1R6MR0DADCRFAQC7','Understanding Hyperacusis: When Everyday Sounds Feel Too Loud','January 16, 2026','Tracey E. Hudson, Au.D., CCC-A','Hyperacusis','[{"_type": "block", "_key": "b002762", "style": "normal", "children": [{"_type": "span", "_key": "s002761", "text": "Hyperacusis is a hearing disorder where normal sounds can feel too loud, sharp, or painful, even in a quiet environment."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002764", "style": "normal", "children": [{"_type": "span", "_key": "s002763", "text": "A proper diagnosis and a supportive consultation with a hearing specialist can lead to real relief through safe treatment and adaptation."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002766", "style": "normal", "children": [{"_type": "span", "_key": "s002765", "text": "With the right plan, many people improve sound perception, reduce stress, and feel more in control of daily life."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002768", "style": "normal", "children": [{"_type": "span", "_key": "s002767", "text": "Hyperacusis can make daily sounds feel like they are turned up too high. A spoon clinking in a bowl, a dog barking, or a busy store can cause discomfort. Some people feel pressure in the ear, headaches, or strong stress. Others feel tired after only a short time around noise. If this sounds like you, you are not alone. Hyperacusis is a real condition, and help is available."}]}, {"_type": "block", "_key": "b002773", "style": "normal", "children": [{"_type": "span", "_key": "s002769", "text": "This guide explains what hyperacusis is, what it feels like, what may cause it, and what care can help. We will also explain how a"}, {"_type": "span", "_key": "s002771", "text": "hearing test", "marks": ["m002770"]}, {"_type": "span", "_key": "s002772", "text": "and a full diagnosis can guide the best next steps."}], "markDefs": [{"_type": "link", "_key": "m002770", "href": "/audiology-services/hearing-tests/"}]}, {"_type": "block", "_key": "b002775", "style": "h2", "children": [{"_type": "span", "_key": "s002774", "text": "What Is Hyperacusis?"}]}, {"_type": "block", "_key": "b002777", "style": "normal", "children": [{"_type": "span", "_key": "s002776", "text": "Hyperacusis is a sound sensitivity disorder. It changes how your brain and ears work together. With hyperacusis, sounds that are normal for most people can feel too loud for you. The sound may feel sharp, painful, or hard to tolerate. This is not the same as simply “not liking” noise. It is a change in sound perception."}]}, {"_type": "block", "_key": "b002779", "style": "normal", "children": [{"_type": "span", "_key": "s002778", "text": "The impact of hyperacusis differs per person. People with hyperacusis may still hear quiet sounds. In fact, some people hear very well on a hearing test. The problem is not always about hearing “more.” It is about how the brain reacts to sound."}]}, {"_type": "block", "_key": "b002781", "style": "h2", "children": [{"_type": "span", "_key": "s002780", "text": "What Does Hyperacusis Feel Like?"}]}, {"_type": "block", "_key": "b002783", "style": "normal", "children": [{"_type": "span", "_key": "s002782", "text": "Hyperacusis can feel different from person to person. Common feelings include:"}]}, {"_type": "block", "_key": "b002785", "style": "normal", "children": [{"_type": "span", "_key": "s002784", "text": "Pain or burning in the ear with sound"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002787", "style": "normal", "children": [{"_type": "span", "_key": "s002786", "text": "A strong “startle” reaction to sudden noise"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002789", "style": "normal", "children": [{"_type": "span", "_key": "s002788", "text": "Fullness or pressure in one or both ears"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002791", "style": "normal", "children": [{"_type": "span", "_key": "s002790", "text": "Headaches after sound exposure"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002793", "style": "normal", "children": [{"_type": "span", "_key": "s002792", "text": "Feeling stressed or overwhelmed in noisy places"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002795", "style": "normal", "children": [{"_type": "span", "_key": "s002794", "text": "Trouble focusing when there is background noise"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002797", "style": "normal", "children": [{"_type": "span", "_key": "s002796", "text": "Some people avoid places like restaurants, school events, or church. Over time, this can lead to isolation. If you begin to avoid life because of sound, it is a sign to seek help."}]}, {"_type": "block", "_key": "b002799", "style": "h2", "children": [{"_type": "span", "_key": "s002798", "text": "How Hyperacusis Affects Daily Life"}]}, {"_type": "block", "_key": "b002801", "style": "normal", "children": [{"_type": "span", "_key": "s002800", "text": "Hyperacusis can affect work, school, and relationships. At work, phones, meetings, and office noise may feel too strong. At home, dishes, TV, or kids playing may be hard to handle. In a loud environment, your body may stay on “high alert,” even when you are safe."}]}, {"_type": "block", "_key": "b002803", "style": "normal", "children": [{"_type": "span", "_key": "s002802", "text": "Children can also have hyperacusis. A child may cover their ears, cry in noisy places, or avoid school assemblies. Some children seem “too active” when they are overwhelmed. This can look like hyperactivity, when the real problem is sound stress. A child may not have the words to explain the discomfort, so behavior becomes the message."}]}, {"_type": "block", "_key": "b002805", "style": "h2", "children": [{"_type": "span", "_key": "s002804", "text": "Hyperacusis and Tinnitus"}]}, {"_type": "block", "_key": "b002807", "style": "normal", "children": [{"_type": "span", "_key": "s002806", "text": "Many people with hyperacusis also have tinnitus, which is ringing or buzzing in the ears. Tinnitus and hyperacusis can happen together because they both involve how the brain processes sound. If you have tinnitus and sound sensitivity, an audiologist can help you plan care that supports both problems."}]}, {"_type": "block", "_key": "b002812", "style": "normal", "children": [{"_type": "span", "_key": "s002808", "text": "Maico Audiological Services provides"}, {"_type": "span", "_key": "s002810", "text": "hearing tests in Smithfield, VA", "marks": ["m002809"]}, {"_type": "span", "_key": "s002811", "text": ", Chesapeake, VA, and Newport News, VA."}], "markDefs": [{"_type": "link", "_key": "m002809", "href": "/audiologist-hearing-aids-smithfield-va/"}]}, {"_type": "block", "_key": "b002814", "style": "h2", "children": [{"_type": "span", "_key": "s002813", "text": "The Relationship Between Hyperacusis and Hearing Loss"}]}, {"_type": "block", "_key": "b002816", "style": "normal", "children": [{"_type": "span", "_key": "s002815", "text": "Hyperacusis and hearing loss often appear together, but they are not the same condition. Hearing loss means the ears are not picking up sound as well as they should. Hyperacusis means sounds feel too loud, sharp, or uncomfortable, even when they are at normal levels. A person can have one without the other, but many people experience both at the same time."}]}, {"_type": "block", "_key": "b002818", "style": "normal", "children": [{"_type": "span", "_key": "s002817", "text": "When hearing loss occurs, the brain may try to “turn up the volume” to fill in missing sound. This change in sound processing can increase sound perception and make everyday noises feel overwhelming. As a result, normal sounds like dishes clanking, traffic, or a ringing bell may suddenly feel painful or stressful. This is why hyperacusis is sometimes seen after noise-related hearing damage or age-related hearing changes."}]}, {"_type": "block", "_key": "b002820", "style": "normal", "children": [{"_type": "span", "_key": "s002819", "text": "Another connection involves the auditory nerve and how sound signals travel from the ear to the brain. If hearing loss affects these pathways, the brain may respond by becoming more sensitive to sound. Over time, this can lead to discomfort, anxiety around noise, and avoidance of certain environments."}]}, {"_type": "block", "_key": "b002822", "style": "normal", "children": [{"_type": "span", "_key": "s002821", "text": "It is important to know that treating hearing loss can sometimes help reduce hyperacusis symptoms. Carefully fitted hearing aids, guided by an audiologist, can restore balanced sound input and help the brain relearn safe sound levels. Sound therapy and gradual listening programs are also used to support adaptation and comfort."}]}, {"_type": "block", "_key": "b002824", "style": "normal", "children": [{"_type": "span", "_key": "s002823", "text": "Because hyperacusis and hearing loss can affect each other, a full hearing evaluation is essential. An audiologist can identify whether hearing loss is present, explain how it may relate to sound sensitivity, and recommend safe treatment options that protect hearing while improving quality of life."}]}, {"_type": "block", "_key": "b002826", "style": "h2", "children": [{"_type": "span", "_key": "s002825", "text": "Common Causes and Risk Factors"}]}, {"_type": "block", "_key": "b002828", "style": "normal", "children": [{"_type": "span", "_key": "s002827", "text": "There is not one single cause of hyperacusis. Often, it is a mix of factors. Possible causes and risk factors include:"}]}, {"_type": "block", "_key": "b002830", "style": "normal", "children": [{"_type": "span", "_key": "s002829", "text": "Loud noise exposure (concerts, tools, firearms)"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002832", "style": "normal", "children": [{"_type": "span", "_key": "s002831", "text": "Hearing loss (even mild)"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002834", "style": "normal", "children": [{"_type": "span", "_key": "s002833", "text": "Ear infection or ear inflammation"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002836", "style": "normal", "children": [{"_type": "span", "_key": "s002835", "text": "Head or neck injury"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002838", "style": "normal", "children": [{"_type": "span", "_key": "s002837", "text": "Jaw problems (TMJ) that affect the ear area"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002840", "style": "normal", "children": [{"_type": "span", "_key": "s002839", "text": "Migraine"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002842", "style": "normal", "children": [{"_type": "span", "_key": "s002841", "text": "High stress, anxiety, or poor sleep"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002844", "style": "normal", "children": [{"_type": "span", "_key": "s002843", "text": "Some medicines that can affect the auditory system"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002846", "style": "normal", "children": [{"_type": "span", "_key": "s002845", "text": "Sometimes the cause is not clear. That can feel scary, but it is common. A careful diagnosis is still helpful, because it guides safe treatment and rules out concerns that need medical care."}]}, {"_type": "block", "_key": "b002848", "style": "h2", "children": [{"_type": "span", "_key": "s002847", "text": "Hyperacusis vs. Misophonia vs. Phonophobia"}]}, {"_type": "block", "_key": "b002850", "style": "normal", "children": [{"_type": "span", "_key": "s002849", "text": "Sound sensitivity is a broad topic. Three terms can sound similar, but they are not the same:"}]}, {"_type": "block", "_key": "b002852", "style": "normal", "children": [{"_type": "span", "_key": "s002851", "text": "Hyperacusis: sounds feel physically too loud or painful."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002854", "style": "normal", "children": [{"_type": "span", "_key": "s002853", "text": "Misophonia: certain sounds trigger strong emotions like anger or panic (for example, chewing)."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002856", "style": "normal", "children": [{"_type": "span", "_key": "s002855", "text": "Phonophobia: fear of sound, often linked to migraine or anxiety."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002858", "style": "normal", "children": [{"_type": "span", "_key": "s002857", "text": "A hearing specialist can help sort out which condition you have. Some people have more than one."}]}, {"_type": "block", "_key": "b002860", "style": "h2", "children": [{"_type": "span", "_key": "s002859", "text": "Why Diagnosis Matters"}]}, {"_type": "block", "_key": "b002862", "style": "normal", "children": [{"_type": "span", "_key": "s002861", "text": "A clear diagnosis matters because it helps you choose the right plan. Without it, you may try random fixes that do not help, or you may overuse earplugs and get worse over time. Your diagnosis also helps your care team check for related problems, like hearing loss or tinnitus."}]}, {"_type": "block", "_key": "b002864", "style": "normal", "children": [{"_type": "span", "_key": "s002863", "text": "At Maico Audiological Services, we start with listening. We want to understand your sound triggers, your daily environment, and what you have tried already. Then we choose the right tests."}]}, {"_type": "block", "_key": "b002866", "style": "h2", "children": [{"_type": "span", "_key": "s002865", "text": "How Hyperacusis Is Diagnosed"}]}, {"_type": "block", "_key": "b002868", "style": "normal", "children": [{"_type": "span", "_key": "s002867", "text": "A hyperacusis diagnosis often includes:"}]}, {"_type": "block", "_key": "b002870", "style": "normal", "children": [{"_type": "span", "_key": "s002869", "text": "A full hearing test (also called an audiogram)"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002872", "style": "normal", "children": [{"_type": "span", "_key": "s002871", "text": "Tests that check how you handle sound at different levels"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002874", "style": "normal", "children": [{"_type": "span", "_key": "s002873", "text": "Questions about pain, stress, sleep, and sound triggers"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002876", "style": "normal", "children": [{"_type": "span", "_key": "s002875", "text": "A look in the ear canal to check for wax or irritation"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002878", "style": "normal", "children": [{"_type": "span", "_key": "s002877", "text": "A review of health history and medicines"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002880", "style": "normal", "children": [{"_type": "span", "_key": "s002879", "text": "These steps help your specialist understand your hearing and your sound perception. If needed, we may recommend medical follow-up with a doctor, such as an ENT, especially if you have sudden changes, one-sided pain, drainage, or dizziness."}]}, {"_type": "block", "_key": "b002882", "style": "h2", "children": [{"_type": "span", "_key": "s002881", "text": "Treatment and Management Options"}]}, {"_type": "block", "_key": "b002884", "style": "normal", "children": [{"_type": "span", "_key": "s002883", "text": "There is no one “quick cure” for hyperacusis. But many people improve with the right management. The goal is to reduce discomfort and help the brain feel safe with sound again."}]}, {"_type": "block", "_key": "b002886", "style": "h3", "children": [{"_type": "span", "_key": "s002885", "text": "1) Sound Therapy"}]}, {"_type": "block", "_key": "b002888", "style": "normal", "children": [{"_type": "span", "_key": "s002887", "text": "Sound therapy uses gentle, steady sound to help the brain adapt. This may include soft noise in the room, calming sound apps, or special devices in some cases. The idea is slow and safe exposure, not forcing loud sound. Over time, many people notice better tolerance and less fear."}]}, {"_type": "block", "_key": "b002890", "style": "h3", "children": [{"_type": "span", "_key": "s002889", "text": "2) Counseling and Education"}]}, {"_type": "block", "_key": "b002892", "style": "normal", "children": [{"_type": "span", "_key": "s002891", "text": "Learning how hyperacusis works can lower stress. When you understand that your system is overreacting, you can stop blaming yourself. Counseling can also help you build coping tools for hard moments, like crowded stores or family events."}]}, {"_type": "block", "_key": "b002894", "style": "h3", "children": [{"_type": "span", "_key": "s002893", "text": "3) Hearing Technology When Needed"}]}, {"_type": "block", "_key": "b002896", "style": "normal", "children": [{"_type": "span", "_key": "s002895", "text": "Some people also have hearing loss. In those cases, hearing aids may help by improving access to normal sound. When the brain gets clearer sound, it may reduce strain. Some devices also offer comfort settings that can be adjusted for busy places."}]}, {"_type": "block", "_key": "b002898", "style": "h3", "children": [{"_type": "span", "_key": "s002897", "text": "4) Healthy Daily Habits"}]}, {"_type": "block", "_key": "b002900", "style": "normal", "children": [{"_type": "span", "_key": "s002899", "text": "Small habits can support recovery:"}]}, {"_type": "block", "_key": "b002902", "style": "normal", "children": [{"_type": "span", "_key": "s002901", "text": "Protect your ears from truly loud sound, like power tools"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002904", "style": "normal", "children": [{"_type": "span", "_key": "s002903", "text": "Avoid complete silence all day"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002906", "style": "normal", "children": [{"_type": "span", "_key": "s002905", "text": "Take quiet breaks when you need them"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002908", "style": "normal", "children": [{"_type": "span", "_key": "s002907", "text": "Practice slow breathing or relaxation skills"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002910", "style": "normal", "children": [{"_type": "span", "_key": "s002909", "text": "Aim for good sleep and hydration"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002912", "style": "normal", "children": [{"_type": "span", "_key": "s002911", "text": "Reduce caffeine if it raises your stress"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002914", "style": "normal", "children": [{"_type": "span", "_key": "s002913", "text": "These steps do not replace care, but they support your body as you heal."}]}, {"_type": "block", "_key": "b002916", "style": "h2", "children": [{"_type": "span", "_key": "s002915", "text": "Should You Use Earplugs?"}]}, {"_type": "block", "_key": "b002918", "style": "normal", "children": [{"_type": "span", "_key": "s002917", "text": "Earplugs can be helpful in truly loud situations. But wearing earplugs all day can train the brain to expect silence. Then normal sound may feel even louder. This can make hyperacusis worse. Your specialist can guide safe earplug use so you get protection without overprotection."}]}, {"_type": "block", "_key": "b002920", "style": "h2", "children": [{"_type": "span", "_key": "s002919", "text": "Hyperacusis in Children"}]}, {"_type": "block", "_key": "b002922", "style": "normal", "children": [{"_type": "span", "_key": "s002921", "text": "Children can experience hyperacusis. Some children have it along with autism, ADHD, anxiety, or migraine, but it can also happen without these. Parents may notice:"}]}, {"_type": "block", "_key": "b002924", "style": "normal", "children": [{"_type": "span", "_key": "s002923", "text": "Covering ears often"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002926", "style": "normal", "children": [{"_type": "span", "_key": "s002925", "text": "Fear of hand dryers or loud toilets"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002928", "style": "normal", "children": [{"_type": "span", "_key": "s002927", "text": "Trouble in the cafeteria or gym"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002930", "style": "normal", "children": [{"_type": "span", "_key": "s002929", "text": "Big reactions to birthday parties"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002932", "style": "normal", "children": [{"_type": "span", "_key": "s002931", "text": "“Meltdowns” in noisy places"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002934", "style": "normal", "children": [{"_type": "span", "_key": "s002933", "text": "A child may also look restless or overly active. Again, this can look like hyperactivity, but it can be a sign that the sound environment feels unsafe. A child-focused plan can help, and it often includes school support."}]}, {"_type": "block", "_key": "b002936", "style": "h2", "children": [{"_type": "span", "_key": "s002935", "text": "How Long Does Improvement Take?"}]}, {"_type": "block", "_key": "b002938", "style": "normal", "children": [{"_type": "span", "_key": "s002937", "text": "Improvement time can vary. Some people feel better in weeks. Others need months. Progress is often small at first. You might notice you can stay in a store longer, or you recover faster after noise. These are real wins."}]}, {"_type": "block", "_key": "b002940", "style": "normal", "children": [{"_type": "span", "_key": "s002939", "text": "Keep a simple journal to track triggers, progress, and wins."}]}, {"_type": "block", "_key": "b002942", "style": "normal", "children": [{"_type": "span", "_key": "s002941", "text": "The key is steady adaptation, not rushing. Your brain needs time to learn that daily sound is safe again."}]}, {"_type": "block", "_key": "b002944", "style": "h2", "children": [{"_type": "span", "_key": "s002943", "text": "When to Schedule a Consultation"}]}, {"_type": "block", "_key": "b002946", "style": "normal", "children": [{"_type": "span", "_key": "s002945", "text": "Consider a consultation if:"}]}, {"_type": "block", "_key": "b002948", "style": "normal", "children": [{"_type": "span", "_key": "s002947", "text": "Normal sounds cause discomfort or pain"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002950", "style": "normal", "children": [{"_type": "span", "_key": "s002949", "text": "You avoid social events because of sound"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002952", "style": "normal", "children": [{"_type": "span", "_key": "s002951", "text": "You have tinnitus plus sound sensitivity"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002954", "style": "normal", "children": [{"_type": "span", "_key": "s002953", "text": "You feel overwhelmed in everyday places"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002956", "style": "normal", "children": [{"_type": "span", "_key": "s002955", "text": "A child struggles in noisy settings"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002958", "style": "normal", "children": [{"_type": "span", "_key": "s002957", "text": "Early care can prevent the problem from growing. It can also reduce fear and help you feel hopeful."}]}, {"_type": "block", "_key": "b002960", "style": "h2", "children": [{"_type": "span", "_key": "s002959", "text": "Frequently Asked Questions"}]}, {"_type": "block", "_key": "b002962", "style": "h3", "children": [{"_type": "span", "_key": "s002961", "text": "Can hyperacusis be cured?"}]}, {"_type": "block", "_key": "b002964", "style": "normal", "children": [{"_type": "span", "_key": "s002963", "text": "There is no single cure for hyperacusis, but many people experience real improvement with the right care. Hyperacusis is not a disease itself, but a sound sensitivity syndrome that affects how the brain and auditory nerve react to everyday sounds. Treatment focuses on reducing symptoms, not forcing silence. With proper treatments such as sound therapy, counseling, and guidance from an audiologist, the brain can slowly relearn that normal noises (like a door closing or a school bell) are not harmful. Over time, many patients notice reduced loudness, less discomfort, and better comfort in daily life."}]}, {"_type": "block", "_key": "b002966", "style": "h3", "children": [{"_type": "span", "_key": "s002965", "text": "Who is at risk for developing hyperacusis?"}]}, {"_type": "block", "_key": "b002968", "style": "normal", "children": [{"_type": "span", "_key": "s002967", "text": "Hyperacusis can affect both children and adults. People may be at higher risk if they have had long-term exposure to loud sounds, hearing loss, tinnitus, migraines, head or neck injuries, or high stress levels. Damage to the inner ear or auditory nerve, certain medications, and conditions affecting the nervous system may also increase risk. In some cases, hyperacusis develops without a clear cause, which is why seeing an audiologist for a full hearing evaluation is important. Early care from trained audiologists can help identify triggers and guide safe management."}]}, {"_type": "block", "_key": "b002970", "style": "h3", "children": [{"_type": "span", "_key": "s002969", "text": "How can you protect your ears if you have hyperacusis?"}]}, {"_type": "block", "_key": "b002972", "style": "normal", "children": [{"_type": "span", "_key": "s002971", "text": "Protecting your ears means using sound protection wisely. Wear earplugs or earmuffs during truly loud situations, such as concerts, power tools, or fireworks, to prevent further damage. Avoid wearing earplugs all day, as constant silence can make sound sensitivity worse. Keep gentle background sounds in your environment, take listening breaks when needed, and manage stress levels. Most importantly, work with an audiologist to create a plan that supports healing, improves tolerance, and helps your ears and brain adapt safely to everyday sounds."}]}, {"_type": "block", "_key": "b002974", "style": "h2", "children": [{"_type": "span", "_key": "s002973", "text": "How Maico Audiological Services Can Help"}]}, {"_type": "block", "_key": "b002976", "style": "normal", "children": [{"_type": "span", "_key": "s002975", "text": "We offer caring, professional support in Newport News, Smithfield, and Chesapeake, VA. Your visit may include testing, education, and a plan that fits your life. We focus on comfort, clear answers, and realistic steps forward."}]}, {"_type": "block", "_key": "b002978", "style": "normal", "children": [{"_type": "span", "_key": "s002977", "text": "You deserve to feel safe in your daily environment. With the right diagnosis, the right tools, and a plan for adaptation, many people with hyperacusis regain confidence and return to the activities they enjoy."}]}, {"_type": "block", "_key": "b002980", "style": "h2", "children": [{"_type": "span", "_key": "s002979", "text": "Schedule An Appointment Today"}]}, {"_type": "block", "_key": "b002982", "style": "normal", "children": [{"_type": "span", "_key": "s002981", "text": "Hyperacusis is a hearing disorder that changes sound perception and makes normal noise feel too intense. It can affect adults and children, and it can even look like anxiety or hyperactivity."}]}, {"_type": "block", "_key": "b002987", "style": "normal", "children": [{"_type": "span", "_key": "s002983", "text": "The good news is that many people improve with proper diagnosis, a supportive consultation, and a step-by-step plan. If hyperacusis is interfering with your life, reach out to"}, {"_type": "span", "_key": "s002985", "text": "Maico Audiological Services", "marks": ["m002984"]}, {"_type": "span", "_key": "s002986", "text": "to schedule a visit and start feeling better."}], "markDefs": [{"_type": "link", "_key": "m002984", "href": "/"}]}]','{"id": "01KS5SXTJSY6NQ2NVBWZNSE6SW", "src": "/_emdash/api/media/file/01KS5SXTGFQVAD4FTJQZ0YZ2KX.jpg", "alt": ""}','Understanding Hyperacusis | Maico Audiological Services','Hyperacusis makes normal sounds feel painful or overwhelming. Schedule a hearing evaluation in Virginia today at Maico Audiological Services.');
INSERT INTO "ec_blog_post" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","publish_date","author","category","content","featured_image","meta_title","meta_description") VALUES('01KS5Y1MKQE0HQXKCK672M68EH','pressure-in-the-ear-causes-care-and-when-to-see-an-audiologist','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1MKQX3WXMA61A64GH91E',NULL,'en','01KS5Y1MKQE0HQXKCK672M68EH','Pressure in the Ear: Causes, Care, and When to See an Audiologist','November 12, 2025','Tracey E. Hudson, Au.D., CCC-A','Hearing','[{"_type": "block", "_key": "b002989", "style": "normal", "children": [{"_type": "span", "_key": "s002988", "text": "Pressure in the ears is a clogged, full, or “underwater” feeling that happens when your ears can’t equalize pressure well or when something blocks the ear canal."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002991", "style": "normal", "children": [{"_type": "span", "_key": "s002990", "text": "Most ear pressure clears on its own, but pressure that lasts, hurts, or changes your hearing can point to earwax buildup, infection, or Eustachian tube dysfunction. A quick exam and hearing test can find the cause and speed up relief."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002993", "style": "normal", "children": [{"_type": "span", "_key": "s002992", "text": "Maico Audiological Services provides evaluations for pressure in the ears, earwax checks, and hearing tests in Chesapeake, VA, Newport News, VA, and Smithfield, VA."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002998", "style": "normal", "children": [{"_type": "span", "_key": "s002994", "text": "As audiologists and hearing instrument specialists, we often meet people who come in saying, “My ears feel full,” or “I feel pressure in my ears.” This is a very common concern, and it can happen to anyone – children, adults, and seniors alike. While it is often temporary and harmless, ear pressure can sometimes signal an underlying issue that needs attention. If ear pressure seems to cause pain or discomfort, you may need to see an audiologist for a check up or a"}, {"_type": "span", "_key": "s002996", "text": "hearing test", "marks": ["m002995"]}, {"_type": "span", "_key": "s002997", "text": "."}], "markDefs": [{"_type": "link", "_key": "m002995", "href": "/audiology-services/hearing-tests/"}]}, {"_type": "block", "_key": "b003000", "style": "h2", "children": [{"_type": "span", "_key": "s002999", "text": "What Causes Pressure in the Ears?"}]}, {"_type": "block", "_key": "b003002", "style": "normal", "children": [{"_type": "span", "_key": "s003001", "text": "The feeling of fullness or pressure in your ears can be caused by several different things:"}]}, {"_type": "block", "_key": "b003004", "style": "h3", "children": [{"_type": "span", "_key": "s003003", "text": "Changes in Air Pressure"}]}, {"_type": "block", "_key": "b003006", "style": "normal", "children": [{"_type": "span", "_key": "s003005", "text": "Have you ever felt your ears “pop” on an airplane or while driving through the mountains? That’s your ears adjusting to changes in air pressure. The Eustachian tube, which connects your middle ear to the back of your nose, helps balance pressure. If it gets blocked, your ears may feel clogged or uncomfortable."}]}, {"_type": "block", "_key": "b003008", "style": "h3", "children": [{"_type": "span", "_key": "s003007", "text": "Earwax Buildup"}]}, {"_type": "block", "_key": "b003010", "style": "normal", "children": [{"_type": "span", "_key": "s003009", "text": "Earwax protects your ears, but too much of it can block the ear canal. When this happens, sound may feel muffled, and you may notice pressure or fullness in your ears."}]}, {"_type": "block", "_key": "b003012", "style": "h3", "children": [{"_type": "span", "_key": "s003011", "text": "Colds, Allergies, or Sinus Infections"}]}, {"_type": "block", "_key": "b003014", "style": "normal", "children": [{"_type": "span", "_key": "s003013", "text": "When you’re sick or dealing with allergies, swelling and congestion can block the Eustachian tube. This makes it harder for your ears to keep pressure balanced."}]}, {"_type": "block", "_key": "b003016", "style": "h3", "children": [{"_type": "span", "_key": "s003015", "text": "Ear Infections"}]}, {"_type": "block", "_key": "b003018", "style": "normal", "children": [{"_type": "span", "_key": "s003017", "text": "Middle ear infections can cause fluid to build up behind the eardrum, leading to pain, pressure, and sometimes hearing loss. Children are especially prone to this."}]}, {"_type": "block", "_key": "b003020", "style": "h3", "children": [{"_type": "span", "_key": "s003019", "text": "Other Health Conditions"}]}, {"_type": "block", "_key": "b003022", "style": "normal", "children": [{"_type": "span", "_key": "s003021", "text": "In some cases, jaw problems (TMJ), high blood pressure, or inner ear disorders may also cause pressure or discomfort."}]}, {"_type": "block", "_key": "b003024", "style": "h2", "children": [{"_type": "span", "_key": "s003023", "text": "When to See a Hearing Professional"}]}, {"_type": "block", "_key": "b003026", "style": "normal", "children": [{"_type": "span", "_key": "s003025", "text": "A little ear pressure from flying or a mild cold usually goes away on its own. But if you notice pressure that doesn’t improve after a few days, is painful, or comes with hearing changes, it’s best to get checked."}]}, {"_type": "block", "_key": "b003031", "style": "normal", "children": [{"_type": "span", "_key": "s003027", "text": "Maico Audiological Services connects you to an expert"}, {"_type": "span", "_key": "s003029", "text": "audiologist in Newport News, VA", "marks": ["m003028"]}, {"_type": "span", "_key": "s003030", "text": ", Chesapeake, VA, and Smithfield, VA."}], "markDefs": [{"_type": "link", "_key": "m003028", "href": "/audiologist-hearing-aids-newport-news-va/"}]}, {"_type": "block", "_key": "b003033", "style": "h2", "children": [{"_type": "span", "_key": "s003032", "text": "Possible Treatments for Ear Pressure"}]}, {"_type": "block", "_key": "b003035", "style": "normal", "children": [{"_type": "span", "_key": "s003034", "text": "Treatment depends on the cause of the problem. Some common solutions include:"}]}, {"_type": "block", "_key": "b003038", "style": "normal", "children": [{"_type": "span", "_key": "s003036", "text": "Earwax Removal:", "marks": ["strong"]}, {"_type": "span", "_key": "s003037", "text": "If earwax is causing the pressure, a professional cleaning can bring almost immediate relief."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b003041", "style": "normal", "children": [{"_type": "span", "_key": "s003039", "text": "Decongestants or Allergy Treatment:", "marks": ["strong"]}, {"_type": "span", "_key": "s003040", "text": "If allergies or sinus problems are the cause, treating those issues often helps the ears feel better."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b003044", "style": "normal", "children": [{"_type": "span", "_key": "s003042", "text": "Medical Care for Infections:", "marks": ["strong"]}, {"_type": "span", "_key": "s003043", "text": "If an infection is present, your doctor may prescribe medication to clear it up."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b003047", "style": "normal", "children": [{"_type": "span", "_key": "s003045", "text": "Hearing Aids or Other Devices:", "marks": ["strong"]}, {"_type": "span", "_key": "s003046", "text": "If hearing loss or inner ear issues are related to your symptoms, hearing aids or other treatments may help reduce discomfort and improve your hearing at the same time."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b003049", "style": "h2", "children": [{"_type": "span", "_key": "s003048", "text": "Tips for Managing Ear Pressure at Home"}]}, {"_type": "block", "_key": "b003051", "style": "normal", "children": [{"_type": "span", "_key": "s003050", "text": "Try yawning, swallowing, or chewing gum during pressure changes, like when flying."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b003053", "style": "normal", "children": [{"_type": "span", "_key": "s003052", "text": "Use saline sprays or steam inhalation to relieve nasal congestion."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b003055", "style": "normal", "children": [{"_type": "span", "_key": "s003054", "text": "Avoid inserting cotton swabs or objects into your ears, as this can push wax deeper or cause injury."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b003057", "style": "normal", "children": [{"_type": "span", "_key": "s003056", "text": "Protect your ears from loud noises to prevent damage that can add to ear problems."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b003059", "style": "h2", "children": [{"_type": "span", "_key": "s003058", "text": "Audiologists and Hearing Instrument Specialists in Virginia"}]}, {"_type": "block", "_key": "b003064", "style": "normal", "children": [{"_type": "span", "_key": "s003060", "text": "At"}, {"_type": "span", "_key": "s003062", "text": "Maico Audiological Services", "marks": ["m003061"]}, {"_type": "span", "_key": "s003063", "text": ", we understand how uncomfortable ear pressure can be. Our audiologists and hearing instrument specialists are here to listen, evaluate, and guide you toward the best solution."}], "markDefs": [{"_type": "link", "_key": "m003061", "href": "/"}]}, {"_type": "block", "_key": "b003066", "style": "normal", "children": [{"_type": "span", "_key": "s003065", "text": "Whether it’s a simple earwax removal, treatment for hearing loss, or a referral for medical care, our goal is to make sure you feel better and hear better."}]}, {"_type": "block", "_key": "b003068", "style": "normal", "children": [{"_type": "span", "_key": "s003067", "text": "If you’ve been struggling with pressure in your ears that won’t go away, don’t ignore it."}]}, {"_type": "block", "_key": "b003070", "style": "normal", "children": [{"_type": "span", "_key": "s003069", "text": "Call our offices in Newport News, Chesapeake, or Smithfield today to schedule an appointment."}]}]','{"id": "01KS5SXJJF13T05Q7FSV2CPN44", "src": "/_emdash/api/media/file/01KS5SXJDNMPNXJ183K8WBEHJN.jpg", "alt": ""}','Pressure in Ears | Maico Audiological Services','Struggling with ear pressure? Our audiologists in Newport News, Chesapeake & Smithfield can help. Call Maico Audiological Services today!');
