"level": 1}, {"_type": "block", "_key": "b001054", "style": "normal", "children": [{"_type": "span", "_key": "s001052", "text": "Tinnitus Relief:", "marks": ["strong"]}, {"_type": "span", "_key": "s001053", "text": "A noise generator is available to provide a sound enrichment source that stimulates the auditory system."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001056", "style": "normal", "children": [{"_type": "span", "_key": "s001055", "text": "**Note: Completely-in-the-canal (CIC) and Invisible-in-the-canal (IIC) models do not offer Bluetooth connectivity due to hearing aid size and space limitations.**", "marks": ["em"]}]}, {"_type": "block", "_key": "b001058", "style": "h2", "children": [{"_type": "span", "_key": "s001057", "text": "Assistive Listening Devices & Technology by Unitron"}]}, {"_type": "block", "_key": "b001060", "style": "normal", "children": [{"_type": "span", "_key": "s001059", "text": "Unitron Partner Mic"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001062", "style": "normal", "children": [{"_type": "span", "_key": "s001061", "text": "Remote Control"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001064", "style": "normal", "children": [{"_type": "span", "_key": "s001063", "text": "TV Connector"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001066", "style": "normal", "children": [{"_type": "span", "_key": "s001065", "text": "IIC Remote"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001068", "style": "h2", "children": [{"_type": "span", "_key": "s001067", "text": "Older Unitron Hearing Aid Models We Support"}]}, {"_type": "block", "_key": "b001070", "style": "normal", "children": [{"_type": "span", "_key": "s001069", "text": "These Unitron hearing aids may still be supported for hearing aid servicing and repair by Maico Audiological Services in Newport News, VA, Smithfield, VA, and Chesapeake, VA. Please contact us for more information.