 "block", "_key": "b001491", "style": "h3", "children": [{"_type": "span", "_key": "s001490", "text": "Frequently Asked Questions About Signia Hearing Aids"}]}, {"_type": "block", "_key": "b001493", "style": "h4", "children": [{"_type": "span", "_key": "s001492", "text": "What is the top-of-the-line Signia hearing aid?"}]}, {"_type": "block", "_key": "b001495", "style": "normal", "children": [{"_type": "span", "_key": "s001494", "text": "The Signia Pure Charge&Go IX, built on the newest Integrated Xperience (IX) platform, is currently the most advanced model. Its RealTime Conversation Enhancement helps follow multiple speakers in real time, making it ideal for busy or noisy places."}]}, {"_type": "block", "_key": "b001497", "style": "h4", "children": [{"_type": "span", "_key": "s001496", "text": "What are the levels of Signia Pure Charge&Go technology?"}]}, {"_type": "block", "_key": "b001499", "style": "normal", "children": [{"_type": "span", "_key": "s001498", "text": "The Pure Charge&Go IX comes in five technology levels: 1 IX, 2 IX, 3 IX, 5 IX, and 7 IX. All provide great sound support, but higher levels include stronger noise reduction, more focus on speech, and advanced streaming options."}]}, {"_type": "block", "_key": "b001501", "style": "h4", "children": [{"_type": "span", "_key": "s001500", "text": "Can I adjust my Signia hearing aid?"}]}, {"_type": "block", "_key": "b001503", "style": "normal", "children": [{"_type": "span", "_key": "s001502", "text": "Yes. With the Signia app, you can easily adjust volume, switch programs, and even fine-tune sound balance between bass and treble, all right from your smartphone."}]}, {"_type": "block", "_key": "b001505", "style": "h2", "children": [{"_type": "span", "_key": "s001504", "text": "Signia Hearing Aids in Virginia"}]}, {"_type": "block", "_key": "b001507", "style": "normal", "children": [{"_type": "span", "_key": "s001506", "text": "Maico Audiological Services is an authorized provider of Signia hearing aids in Newport News, VA, Chesapeake, VA, and Smithfield, VA. Our audiologist or hearing instrument specialist will be glad to help you find the Signia device that matches your hearing needs and lifestyle."}]}, {"_type": "block", "_key": "b001509", "style": "normal", "children": [{"_type": "span", "_key": "s001508", "text": "Schedule your appointment today!"}]}]','Signia Hearing Aids | Maico Audiological Services','Maico Audiological Services is an authorized provider of Signia hearing aids in Virginia. Contact us to learn more!');
INSERT INTO "ec_homepage" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","hero_intro","hero_cta","intro_section_title","intro_body","badge_1","badge_2","badge_3","testimonial_section_title","testimonial_eyebrow","faq_section_title","faq_eyebrow","faq_description","faq_content","audiology_services_featured_image","audiology_services_body","hearing_aids_protection_solutions_image","hearing_aids_protection_solutions_body","hearing_aid_brand_image_1","hearing_aid_brand_image_2","hearing_aid_brand_image_3","hearing_aid_brand_image_4","hearing_aid_brand_image_5","hearing_aid_brand_image_6","hearing_aid_brand_image_7") VALUES('01KS6DYPBMTW72P0G8ZF6NNM91','home','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T07:29:26.000Z','2026-05-22T10:59:22.646Z','2026-05-22T13:13:03.000Z',NULL,NULL,7,'01KS7NDZ96ASAFZTZJTTNXM60K',NULL,'en','01KS6DYPBMTW72P0G8ZF6NNM91','It’s time to hear and be heard.','/book-appointment/','AUDIOLOGISTS & HEARING AIDS IN VIRGINIA','[{"_type":"block","_key":"01ks71kwj4q4cyqsrvz0qs72qc","style":"h2","children":[{"_type":"span","_key":"01ks71kwj4m3eax1spsxep7294","text":"Virginia Audiologists & Hearing Aids","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj49sjw17w879nv70kd","style":"normal","children":[{"_type":"span","_key":"01ks71kwj4a14tzft6qj7095m2","text":"At Maico Audiological Services, our compassionate team is dedicated to restoring your connection to the world around you. Whether you’re struggling in noisy environments, turning up the volume just to follow conversations, or missing the little details that make life vibrant, we provide comprehensive hearing care, from precise testing to personalized hearing aid fittings.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj4v53pea21mdnefrx7","style":"normal","children":[{"_type":"span","_key":"01ks71kwj4hgb0syrb3s4jrzav","text":"Experience personalized hearing care you can trust!","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj48834n08a385hr1qq","style":"h2","children":[{"_type":"span","_key":"01ks71kwj4m0n004g8g1wpw6y9","text":"Maico Audiological Services","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj4jjfqsrg11jqfrdk7","style":"normal","children":[{"_type":"span","_key":"01ks71kwj4t58wakkjj4zw1kgb","text":"At Maico Audiological Services, we understand how hearing loss can sneak up on you, making everyday moments harder to enjoy. You might find yourself straining to follow conversations, feeling tired from the effort of listening, or missing out on the sounds that bring joy to your life.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj4axrm10z88tyggqf0","style":"normal","children":[{"_type":"span","_key":"01ks71kwj4hxkn03qs59yg8qkz","text":"Let our experienced audiologists and hearing instrument specialist in Virginia help you rediscover clearer hearing and reconnect with the people and moments that matter most.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj4d2ddp2g0vkaz2hg6","style":"normal","children":[{"_type":"span","_key":"01ks71kwj4qz50t5yxhv9n2mtd","text":"Let us help you regain the joy of hearing and the quality of life you deserve.","marks":[]}],"markDefs":[]}]','{"id":"01KS5SV5PQAQMSB7P0BFQCNW9J","provider":"local","filename":"assets__media__american-academy-of-audiology-197e3fa696.webp","mimeType":"image/webp","width":340,"height":240,"alt":"American Academy of Audiology logo with ear and sound wave icon on black background","meta":{"storageKey":"01KS5SV5NRFH2XS3DGWN9EERNM.webp","caption":null,"blurhash":null,"dominantColor":null}}','{"id":"01KS5SV6JYM3GXH893QNDZR7VX","provider":"local","filename":"assets__media__asha-61a58f8bb8.webp","mimeType":"image/webp","width":340,"height":240,"alt":"ASHA logo with teal icon showing two profile silhouettes and sound waves on black background","meta":{"storageKey":"01KS5SV6G5XGR80QE1M4ZCVT2B.webp","caption":null,"blurhash":null,"dominantColor":null}}','{"id":"01KS5SXMN63W2Z5H2H0FZD5YD6","provider":"local","filename":"assets__media__Reviews-e6bc9f5ec7.png","mimeType":"image/png","width":143,"height":114,"alt":"Google logo with five gold stars and text showing 100+ reviews","meta":{"storageKey":"01KS5SXMKSERDQZCEFDEXASTD5.png","caption":null,"blurhash":"LAAvRpN#9*Gd-tN#R=Kk03oh%1v|","dominantColor":"rgb(157,133,95)"}}','What Our Patients Are Saying','Real Reviews & Testimonials','Frequently Asked Questions','Find Answers','[{"_type":"block","_key":"01ks71kwj4evd98wk3x2j57jmt","style":"normal","children":[{"_type":"span","_key":"01ks71kwj43922yza3scnc86p1","text":"Can’t find the answers you’re looking for? ","marks":[]},{"_type":"span","_key":"01ks71kwj4qq79zbgtktwrtz5g","text":"Contact Us.","marks":["01ks71kwj43grkpbq6dc33ts96"]}],"markDefs":[{"_key":"01ks71kwj43grkpbq6dc33ts96","_type":"link","href":"/contact/"}]}]','[{"_type":"block","_key":"01ks71kwk1kh8mbfbm0khhmb0h","style":"h3","children":[{"_type":"span","_key":"01ks71kwk1nhwwg2tdaaaaf6w0","text":"How do I know if I need a hearing aid?","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwk101vet63ht531sjy1","style":"normal","children":[{"_type":"span","_key":"01ks71kwk1agm4p2dqn5a0mh84","text":"If you’re finding it hard to follow conversations (especially in noisy places) frequently increasing the TV volume, or feeling left out during social gatherings, it may be time for a hearing evaluation. An audiologist at Maico Audiological Services can assess your hearing and determine if a hearing aid is the right solution for you.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwk10sk0c035vd2rhbm9","style":"h3","children":[{"_type":"span","_key":"01ks71kwk1r8x9bzv1fr8cd4hn","text":"What is the difference between hearing aids and personal sound amplification products (PSAPs)?","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwk1676m0c1hfca2w670","style":"normal","children":[{"_type":"span","_key":"01ks71kwk1z6135f37ysj41tx0","text":"Hearing aids are FDA-regulated medical devices designed to treat hearing loss. They are professionally fitted and programmed to your hearing needs. PSAPs, however, are general amplifiers meant for individuals without hearing loss and do not provide the same level of customization, support, or effectiveness.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwk1mgpzh16d2khzptc2","style":"h3","children":[{"_type":"span","_key":"01ks71kwk1sx0japkmxs68ghw0","text":"Can I get a hearing aid without a hearing test?","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwk27k5s21tj5f44d022","style":"normal","children":[{"_type":"span","_key":"01ks71kwk2yy4ea5dvfnr87kbm","text":"Yes, over-the-counter (OTC) hearing aids are available without a hearing test and are designed for adults with mild to moderate hearing loss. However, having a professional hearing evaluation at Maico Audiological Services ensures your hearing aid is matched to your specific needs and helps rule out any underlying medical conditions.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwk2kh76rvst3vs0gm1z","style":"h3","children":[{"_type":"span","_key":"01ks71kwk204nkg9g8gt4wps5z","text":"How long do hearing aids last?","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwk2w09smj4jnsar8js7","style":"normal","children":[{"_type":"span","_key":"01ks71kwk2hn5t6rfe96gahs01","text":"Most hearing aids last between 3 to 7 years, depending on the model, how well they’re maintained, and how often they’re used. Regular cleanings, proper storage, and routine check-ups with your audiologist or hearing instrument specialist can help extend the life of your devices. As technology improves, many people choose to upgrade sooner to benefit from the latest features and better performance.","marks":[]}],"markDefs":[]}]','{"id":"01KS5SX9AD75S0E571980ANF51","provider":"local","filename":"assets__media__Frame-721-3b058c3295.png","mimeType":"image/png","width":534,"height":601,"alt":"Audiologist conducting hearing test with patient visible through soundproof booth window","meta":{"storageKey":"01KS5SX93TVJ39PS3A2SPNDHMM.png","caption":null,"blurhash":"LGKdPO.95A4;%HrV.8x]tTOu.Tt8","dominantColor":"rgb(163,146,122)"}}','[{"_type":"block","_key":"01ks71kwj8kqgmjcjed765khhb","style":"h3","children":[{"_type":"span","_key":"01ks71kwj8dcghh8ns5p7bdmb3","text":"Hearing Evaluations","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj8kg14dp6stvnbwts9","style":"normal","children":[{"_type":"span","_key":"01ks71kwj8fmsg06cd9gzf0pvb","text":"At Maico Audiological Services, we offer complete hearing evaluations to better understand your hearing health. Our tests help determine the type and level of hearing loss you may be experiencing, so we can recommend solutions that are tailored to your lifestyle and needs.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj9x7hrc8yy7qtxet2y","style":"h3","children":[{"_type":"span","_key":"01ks71kwj9n53tmhtb47b9hgt1","text":"Sensorineural Hearing Loss Evaluation & Treatment","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj9577n32vf3zpf522y","style":"normal","children":[{"_type":"span","_key":"01ks71kwj92vwate6f9khah89d","text":"Sensorineural hearing loss is the most common type of permanent hearing loss, often caused by aging, noise exposure, or inner ear damage. Our experienced hearing instrument specialist will perform a thorough hearing evaluation to determine the degree and type of hearing loss. ","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj905rybckq3nwjqpkh","style":"h3","children":[{"_type":"span","_key":"01ks71kwj91g72ry4pbmrthbbf","text":"Tinnitus Evaluations & Treatment","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj9fj4dv0t8d1jw34yy","style":"normal","children":[{"_type":"span","_key":"01ks71kwj9cmdkfzc7g38mqydc","text":"Struggling with ringing, buzzing, or humming in your ears? Our audiologists provide complete tinnitus evaluations to uncover the cause and create a personalized treatment plan. From hearing aids and sound therapy to lifestyle guidance, we’ll help reduce the impact of tinnitus so you can enjoy better focus, sleep, and peace of mind.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj9ypmc6gn8kf2eq032","style":"normal","children":[{"_type":"span","_key":"01ks71kwj9f1t5qgxj5m1jr90g","text":"If tinnitus persists or worsens, we may recommend a referral to an ENT (ear, nose, and throat) physician for further evaluation. Working together, we can help ensure you receive the best possible care.”","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj91104j7kjk3jdcac4","style":"h3","children":[{"_type":"span","_key":"01ks71kwj98qh5ncdfbssb5xkp","text":"Hearing Aid Services","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj9kqzgx4g6jce4x9sn","style":"normal","children":[{"_type":"span","_key":"01ks71kwj9dt4c70m5v2jmk3jq","text":"From helping you choose the right hearing aid to providing expert fittings, cleanings, and repairs, we’re here for every step of your hearing journey. Our goal is to ensure you always enjoy clear, comfortable sound wherever life takes you.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwj9c31etx7hhyhfh7fq","style":"h3","children":[{"_type":"span","_key":"01ks71kwj9xkt06ceaq0c6dswh","text":"Hearing Aid Fittings","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjab9vzhhdkn1y93j6c","style":"normal","children":[{"_type":"span","_key":"01ks71kwja0p2f65yectx1vcmt","text":"Getting the perfect fit is key to getting the most out of your hearing aids. Our hearing instrument specialist will make sure your devices are properly adjusted for your hearing loss, comfort, and lifestyle, giving you the best hearing experience possible.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjase9x3yg8s3773c43","style":"h3","children":[{"_type":"span","_key":"01ks71kwja3z8tj34f9ktphpbk","text":"Hearing Aid Cleaning and Repair","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwja2w3k39pan3cqwjpv","style":"normal","children":[{"_type":"span","_key":"01ks71kwjankaakrhzch7xtn46","text":"If your hearing aid isn’t working quite right, don’t worry, we can help. We offer fast, reliable cleaning and repair services to keep your devices functioning at their best so you can keep hearing clearly.","marks":[]}],"markDefs":[]}]','{"id":"01KS5SX4QRBXGHD1NQ48WCS28X","provider":"local","filename":"assets__media__DSC07786-1024x682-3c52c58e84.jpg","mimeType":"image/jpeg","width":800,"height":533,"alt":"","meta":{"storageKey":"01KS5SX4JJZ84T7F7QHZ058PDZ.jpg","caption":null,"blurhash":"LdI5MVxvoet7~VIAD$M{tRR+RjtR","dominantColor":"rgb(127,122,118)"}}','[{"_type":"block","_key":"01ks71kwjehgxp10xa1m7etjj3","style":"h3","children":[{"_type":"span","_key":"01ks71kwjekmbxjkw0ybqbf04t","text":"Custom Ear Protection","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjftt9t8ct07af1x6q2","style":"normal","children":[{"_type":"span","_key":"01ks71kwjfxdremxa3j81zk9pt","text":"Whether you’re a hunter, musician, swimmer, or work in loud environments, we offer custom-fit earplugs that provide the protection you need. Our audiologists will make sure your ear protection fits comfortably and works effectively.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjfgwt9jxv5bv2fse82","style":"h3","children":[{"_type":"span","_key":"01ks71kwjf16fe2phkfze978p0","text":"Hearing Aids","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjfabsew9xpdr28q639","style":"normal","children":[{"_type":"span","_key":"01ks71kwjfxpxhmdsew3sg1kb3","text":"We carry a wide range of high-quality hearing aids from trusted brands like Phonak, Oticon, ReSound, Unitron, Widex, Starkey, and Signia. We’ll help you find the right solution based on your unique hearing needs, lifestyle, and budget.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjf5h0nrzasy4nb2heq","style":"h3","children":[{"_type":"span","_key":"01ks71kwjfvqxpfngt4kae3r20","text":"Hearing Aid Batteries and Accessories","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjf1qgx4xrtp0193pjs","style":"normal","children":[{"_type":"span","_key":"01ks71kwjfpz2vxvf3hy6g6k93","text":"Keep your hearing aids working their best with our selection of essential accessories. We offer batteries, cleaning kits, drying tools, and more. We make it easy to take care of your hearing aids so you can rely on them every day.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjft8r3yw6w75vf7ch2","style":"h3","children":[{"_type":"span","_key":"01ks71kwjf06hzkzksm0myvgg2","text":"Assistive Listening Devices","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks71kwjfqgcnetd4c473zekn","style":"normal","children":[{"_type":"span","_key":"01ks71kwjfxq96g0hp0fd9wd5a","text":"If you find it hard to hear clearly on the phone, in noisy settings, or while watching TV, our assistive listening devices can help. We offer solutions like CaptionCall phones that display real-time captions, making conversations easier to follow. Enjoy clearer hearing at home, at work, or on the go with ALDs tailored to your needs.","marks":[]}],"markDefs":[]}]','{"id":"01KS5SV34RXYWJ3C0NZ67YF1GJ","provider":"local","filename":"assets__media__5d9c3eb94b8bdfdaf3550c8c9eb8ec99ee179a8f-a83a7bf292.png","mimeType":"image/png","alt":"5d9c3eb94b8bdfdaf3550c8c9eb8ec99ee179a8f","meta":{"storageKey":"01KS5SV33P6YKTC1NH9FXWZXKQ.png","caption":null,"blurhash":"L~L#2%t7j]t7t7ofj[ju~qj[ayj@","dominantColor":"rgb(78,79,67)"}}','{"id":"01KS5SX6QDPJCV8R60M3MAB2V8","provider":"local","filename":"assets__media__e8e0fa55c783cc5eeb2f48b009e1e095ac8d6e81-14a6944128.png","mimeType":"image/png","alt":"e8e0fa55c783cc5eeb2f48b009e1e095ac8d6e81","meta":{"storageKey":"01KS5SX6FFNPS2844KCVW26YE4.png","caption":null,"blurhash":"LnQ9_@%MWBxuxuayj[of~qfQj[j[","dominantColor":"rgb(66,64,65)"}}','{"id":"01KS5SV5E7VSNS8SCEENTT5X6B","provider":"local","filename":"assets__media__9630f9ccdd250ed5d95e8dc192ec9ee4edd82d78-5f3ed2b78b.png","mimeType":"image/png","alt":"9630f9ccdd250ed5d95e8dc192ec9ee4edd82d78","meta":{"storageKey":"01KS5SV5CJ5BN9225CSDEJD9K2.png","caption":null,"blurhash":"L*PGjXt7oft7t7ofj[ay~qofWBof","dominantColor":"rgb(24,25,25)"}}','{"id":"01KS5SV92516N24G10G09YQQA4","provider":"local","filename":"assets__media__df20d30b24e0e24425ac05171bd6c1a6fc636e81-0808b50979.png","mimeType":"image/png","alt":"df20d30b24e0e24425ac05171bd6c1a6fc636e81","meta":{"storageKey":"01KS5SV90P99MCQ494D1F920MS.png","caption":null,"blurhash":"LNCPbH~B-;%g^+WYNKR-?aWXWER-","dominantColor":"rgb(134,117,70)"}}','{"id":"01KS5SV020V66CW6Z79JN1EMRS","provider":"local","filename":"assets__media__0fe542364bad1d04cf43fe57ffe07dbe48c47f61-7a7a82690d.png","mimeType":"image/png","alt":"0fe542364bad1d04cf43fe57ffe07dbe48c47f61","meta":{"storageKey":"01KS5STZWAV2YFBVDSFK6M3HGS.png","caption":null,"blurhash":"L;OC8Xt7aen*xuj[j[fQ?^aekCoz","dominantColor":"rgb(180,55,76)"}}','{"id":"01KS5SV4R6X07QJ9322PP06YAQ","provider":"local","filename":"assets__media__88d181692132923dbbbe93e746ab1c04b78c12d1-a6cb5ac68e.png","mimeType":"image/png","alt":"88d181692132923dbbbe93e746ab1c04b78c12d1","meta":{"storageKey":"01KS5SV4PZM1JA54ZKPV91GWN6.png","caption":null,"blurhash":"L$O}6;kDfiX9~Ws:s.t6=_f7fQoe","dominantColor":"rgb(16,176,237)"}}','{"id":"01KS5SV74KW7EWEFPGT0CK4424","provider":"local","filename":"assets__media__c9e2e0c48788d7e2452b75bf4158177f9fac0e08-7b273d533b.png","mimeType":"image/png","alt":"c9e2e0c48788d7e2452b75bf4158177f9fac0e08","meta":{"storageKey":"01KS5SV73D8F1K871VYA5SD8ZQ.png","caption":null,"blurhash":"L~P}lft7.mt7=efkOXj[Nua|soj[","dominantColor":"rgb(210,59,61)"}}');
