INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M2MQYEF7VMHFHJ2FX2J','audiology-services','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M2MFN1CS3XF80RT5K9A',NULL,'en','01KS5Y1M2MQYEF7VMHFHJ2FX2J','Audiology Services','[{"_type": "block", "_key": "b001511", "style": "normal", "children": [{"_type": "span", "_key": "s001510", "text": "Maico Audiological Services provides expert hearing care to help you stay connected to the sounds and people that matter most.", "marks": ["em", "strong"]}]}, {"_type": "block", "_key": "b001513", "style": "normal", "children": [{"_type": "span", "_key": "s001512", "text": "From comprehensive hearing evaluations, hearing aid fittings, and excellent after-care services, our Virginia audiologists and hearing instrument specialists are here to support you with compassionate and personalized hearing care."}]}, {"_type": "block", "_key": "b001515", "style": "normal", "children": [{"_type": "span", "_key": "s001514", "text": "Visit us in Newport News, VA, Chesapeake, VA, and Smithfield, VA to experience personalized, expert hearing care designed with your needs in mind."}]}, {"_type": "block", "_key": "b001517", "style": "h2", "children": [{"_type": "span", "_key": "s001516", "text": "Hearing Services in Virginia"}]}, {"_type": "block", "_key": "b001519", "style": "h3", "children": [{"_type": "span", "_key": "s001518", "text": "Hearing Evaluations"}]}, {"_type": "block", "_key": "b001521", "style": "normal", "children": [{"_type": "span", "_key": "s001520", "text": "We offer complete hearing evaluations to better understand your hearing health. Our tests help determine the type and level of hearing loss you may be experiencing, so we can recommend solutions that are tailored to your lifestyle and needs."}]}, {"_type": "block", "_key": "b001523", "style": "h4", "children": [{"_type": "span", "_key": "s001522", "text": "Which hearing test is best for me?"}]}, {"_type": "block", "_key": "b001525", "style": "normal", "children": [{"_type": "span", "_key": "s001524", "text": "The best hearing test depends on your individual needs. A comprehensive hearing evaluation performed by an audiologist is the most accurate way to assess your hearing health. A professional hearing test is the most reliable way to detect hearing loss and find the best solution for your hearing needs."}]}, {"_type": "block", "_key": "b001527", "style": "h4", "children": [{"_type": "span", "_key": "s001526", "text": "Can I test my own hearing at home?"}]}, {"_type": "block", "_key": "b001529", "style": "normal", "children": [{"_type": "span", "_key": "s001528", "text": "You can do a simple self-check by watching for signs like:"}]}, {"_type": "block", "_key": "b001531", "style": "normal", "children": [{"_type": "span", "_key": "s001530", "text": "Struggling to follow conversations"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001533", "style": "normal", "children": [{"_type": "span", "_key": "s001532", "text": "Turning up the volume on your TV or phone"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001535", "style": "normal", "children": [{"_type": "span", "_key": "s001534", "text": "Frequently asking others to repeat themselves"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001537", "style": "normal", "children": [{"_type": "span", "_key": "s001536", "text": "There are also online tools and hearing apps that offer basic screenings. While these may give you a general idea of your hearing ability, please note that they aren’t a substitute for a full evaluation. If you notice any signs of hearing loss, schedule a professional hearing test with an audiologist or hearing aid specialist to get accurate answers."}]}, {"_type": "block", "_key": "b001539", "style": "h4", "children": [{"_type": "span", "_key": "s001538", "text": "Are online hearing tests accurate?"}]}, {"_type": "block", "_key": "b001541", "style": "normal", "children": [{"_type": "span", "_key": "s001540", "text": "Online hearing tests can be a helpful first step, but they have limitations. Most measure your ability to hear tones through headphones or speakers, but they don’t evaluate how well you understand speech, middle or inner ear function, and what’s causing your hearing loss. While online tests may suggest a hearing issue, a professional hearing evaluation is the best way to diagnose the problem and find the right treatment plan."}]}, {"_type": "block", "_key": "b001543", "style": "h3", "children": [{"_type": "span", "_key": "s001542", "text": "Sensorineural Hearing Loss Evaluation & Treatment"}]}, {"_type": "block", "_key": "b001545", "style": "normal", "children": [{"_type": "span", "_key": "s001544", "text": "Our experienced audiologists or hearing instrument specialists at Maico Audiological Services will perform a thorough hearing evaluation to determine the degree and type of hearing loss."}]}, {"_type": "block", "_key": "b001547", "style": "h4", "children": [{"_type": "span", "_key": "s001546", "text": "Can sensorineural hearing loss be treated?"}]}, {"_type": "block", "_key": "b001549", "style": "normal", "children": [{"_type": "span", "_key": "s001548", "text": "While sensorineural hearing loss usually can’t be reversed medically or surgically, it can be effectively managed. The most common treatment is hearing aids, which amplify sound and improve clarity. At Maico Audiological Services, our audiologist or hearing instrument specialist will help find the right hearing aid based on your hearing test results, lifestyle, and communication needs."}]}, {"_type": "block", "_key": "b001551", "style": "h4", "children": [{"_type": "span", "_key": "s001550", "text": "How do I know if I have sensorineural hearing loss?"}]}, {"_type": "block", "_key": "b001553", "style": "normal", "children": [{"_type": "span", "_key": "s001552", "text": "You might notice symptoms like muffled speech, trouble understanding conversations (especially in crowds), or turning up the TV volume often. The only way to know for sure is through a professional hearing evaluation."}]}, {"_type": "block", "_key": "b001555", "style": "h4", "children": [{"_type": "span", "_key": "s001554", "text": "Is sensorineural hearing loss the same in both ears?"}]}, {"_type": "block", "_key": "b001557", "style": "normal", "children": [{"_type": "span", "_key": "s001556", "text": "Not always. Sensorineural hearing loss can affect one ear (unilateral) or both ears (bilateral). It may develop gradually over time or happen suddenly. Some people experience more severe hearing loss in one ear than the other. A comprehensive hearing evaluation at Maico Audiological Services will identify the pattern and severity of your hearing loss, so we can recommend the most effective solution for you."}]}, {"_type": "block", "_key": "b001559", "style": "h3", "children": [{"_type": "span", "_key": "s001558", "text": "Hearing Aid Services"}]}, {"_type": "block", "_key": "b001561", "style": "normal", "children": [{"_type": "span", "_key": "s001560", "text": "From helping you choose the right hearing aid to providing expert fittings, cleanings, and repairs, we’re here for every step of your hearing journey. Our goal is to ensure you always enjoy clear, comfortable sound wherever life takes you."}]}, {"_type": "block", "_key": "b001563", "style": "h4", "children": [{"_type": "span", "_key": "s001562", "text": "How do I know which hearing aid is right for me?"}]}, {"_type": "block", "_key": "b001565", "style": "normal", "children": [{"_type": "span", "_key": "s001564", "text": "Choosing the right hearing aid depends on your level of hearing loss, lifestyle, and personal preferences. During your hearing aid consultation at Maico Audiological Services, our audiologist or hearing instrument specialist will walk you through your options, explain the features of different models, and recommend the best fit for your needs and budget."}]}, {"_type": "block", "_key": "b001567", "style": "h4", "children": [{"_type": "span", "_key": "s001566", "text": "Do hearing aids need to be professionally fitted?"}]}, {"_type": "block", "_key": "b001569", "style": "normal", "children": [{"_type": "span", "_key": "s001568", "text": "Yes. A professional fitting ensures your hearing aids are programmed correctly and sit comfortably in your ears. Our audiologist or hearing instrument specialist will adjust the devices based on your hearing test results and make sure they provide clear, natural sound."}]}, {"_type": "block", "_key": "b001571", "style": "h4", "children": [{"_type": "span", "_key": "s001570", "text": "How long does it take to get used to hearing aids?"}]}, {"_type": "block", "_key": "b001573", "style": "normal", "children": [{"_type": "span", "_key": "s001572", "text": "It can take a few days to several weeks to adjust to new hearing aids. At first, sounds may seem louder or unfamiliar, but your brain will gradually adapt. We’re here to guide you through the adjustment period and make any needed changes to improve your comfort and hearing experience."}]}, {"_type": "block", "_key": "b001575", "style": "h3", "children": [{"_type": "span", "_key": "s001574", "text": "Hearing Aid Fittings"}]}, {"_type": "block", "_key": "b001577", "style": "normal", "children": [{"_type": "span", "_key": "s001576", "text": "Getting the perfect fit is key to getting the most out of your hearing aids. Our audiologist or hearing instrument specialist will make sure your devices are properly adjusted for your hearing loss, comfort, and lifestyle, giving you the best hearing experience possible."}]}, {"_type": "block", "_key": "b001579", "style": "h4", "children": [{"_type": "span", "_key": "s001578", "text": "What happens during a hearing aid fitting?"}]}, {"_type": "block", "_key": "b001581", "style": "normal", "children": [{"_type": "span", "_key": "s001580", "text": "During your fitting, our audiologist or hearing instrument specialist will program your hearing aids based on your hearing test results. We’ll make sure they fit comfortably, explain how to use them, and adjust the settings so you can hear clearly in different environments. You’ll also have time to ask questions and practice using your new devices."}]}, {"_type": "block", "_key": "b001583", "style": "h4", "children": [{"_type": "span", "_key": "s001582", "text": "Why is a proper hearing aid fitting important?"}]}, {"_type": "block", "_key": "b001585", "style": "normal", "children": [{"_type": "span", "_key": "s001584", "text": "A proper fit ensures that your hearing aids provide clear sound without discomfort or feedback (whistling). Everyone’s ears and hearing needs are different, so a custom fitting helps your devices perform their best and makes your adjustment period much easier."}]}, {"_type": "block", "_key": "b001587", "style": "h4", "children": [{"_type": "span", "_key": "s001586", "text": "Will I need follow-up appointments after the fitting?"}]}, {"_type": "block", "_key": "b001589", "style": "normal", "children": [{"_type": "span", "_key": "s001588", "text": "Yes. Follow-up visits are an important part of the process. We’ll check how your hearing aids are working, fine-tune the settings, and make sure you’re comfortable with using and caring for them. These visits help ensure long-term success and satisfaction."}]}, {"_type": "block", "_key": "b001591", "style": "h3", "children": [{"_type": "span", "_key": "s001590", "text": "Hearing Aid Cleaning and Repair"}]}, {"_type": "block", "_key": "b001593", "style": "normal", "children": [{"_type": "span", "_key": "s001592", "text": "If your hearing aid isn’t working quite right, we can help. We offer fast, reliable cleaning and repair services to keep your devices functioning at their best so you can keep hearing clearly."}]}, {"_type": "block", "_key": "b001595", "style": "h4", "children": [{"_type": "span", "_key": "s001594", "text": "How often should I clean my hearing aids?"}]}, {"_type": "block", "_key": "b001597", "style": "normal", "children": [{"_type": "span", "_key": "s001596", "text": "We recommend cleaning your hearing aids daily using a soft, dry cloth and any tools recommended by your hearing aid provider. Regular cleaning helps prevent wax buildup and keeps your devices working properly. We’ll also show you how to care for them during your fitting."}]}, {"_type": "block", "_key": "b001599", "style": "h4", "children": [{"_type": "span", "_key": "s001598", "text": "What are the signs my hearing aids need repair?"}]}, {"_type": "block", "_key": "b001601", "style": "normal", "children": [{"_type": "span", "_key": "s001600", "text": "If your hearing aids sound weak, cut in and out, whistle often, or stop working entirely, they may need repair. Sometimes the issue is as simple as wax buildup or a clogged microphone, but if cleaning doesn’t fix it, bring them in for a professional check."}]}, {"_type": "block", "_key": "b001603", "style": "h4", "children": [{"_type": "span", "_key": "s001602", "text": "Do you offer in-office hearing aid repairs?"}]}, {"_type": "block", "_key": "b001605", "style": "normal", "children": [{"_type": "span", "_key": "s001604", "text": "Yes. Maico Audiological Services offers quick, in-office repairs for common issues like tubing replacements, battery door problems, and filter changes. If your device needs manufacturer repair, we’ll help coordinate that process and keep you updated."}]}, {"_type": "block", "_key": "b001607", "style": "h3", "children": [{"_type": "span", "_key": "s001606", "text": "Custom Ear Protection"}]}, {"_type": "block", "_key": "b001609", "style": "normal", "children": [{"_type": "span", "_key": "s001608", "text": "Whether you’re a hunter, musician, swimmer, or work in loud environments, we offer custom-fit earplugs that provide the protection you need. Our audiologist or hearing instrument specialist will make sure your ear protection fits comfortably and works effectively."}]}, {"_type": "block", "_key": "b001611", "style": "h4", "children": [{"_type": "span", "_key": "s001610", "text": "Who should use custom ear protection?"}]}, {"_type": "block", "_key": "b001613", "style": "normal", "children": [{"_type": "span", "_key": "s001612", "text": "Custom ear protection is helpful for anyone exposed to loud sounds or who needs specialized protection. This includes hunters, musicians, swimmers, construction workers, factory employees, and anyone who wants a secure, comfortable fit for long-term use."}]}, {"_type": "block", "_key": "b001615", "style": "h4", "children": [{"_type": "span", "_key": "s001614", "text": "How is custom ear protection made?"}]}, {"_type": "block", "_key": "b001617", "style": "normal", "children": [{"_type": "span", "_key": "s001616", "text": "Our audiologist or hearing instrument specialist will take an impression of your ear to create a mold that fits you perfectly. This ensures a snug, comfortable fit that offers better protection than standard, one-size earplugs. Once made, your custom ear protection is tailored to your specific needs."}]}, {"_type": "block", "_key": "b001619", "style": "h4", "children": [{"_type": "span", "_key": "s001618", "text": "What are the benefits of custom earplugs over store-bought ones?"}]}, {"_type": "block", "_key": "b001621", "style": "normal", "children": [{"_type": "span", "_key": "s001620", "text": "Unlike generic earplugs, custom ear protection is designed to fit your ear shape exactly, which makes them more comfortable and effective. They provide better noise reduction, last longer, and can be customized for specific uses."}]}]','Audiology Services | Maico Audiological Services','Learn more about our audiology services provided by our expert audiologists and hearing instrument specialists in Virginia.');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M3BR8CGTX5ZVJ2T7K63','audiology-services/hearing-aid-services','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M3B4JZVJVNRBA8C4ZEX',NULL,'en','01KS5Y1M3BR8CGTX5ZVJ2T7K63','Hearing Aid Services','[{"_type": "block", "_key": "b001623", "style": "normal", "children": [{"_type": "span", "_key": "s001622", "text": "Maico Audiological Services provides expert hearing aid services in Newport News, VA, Chesapeake, VA, and Smithfield, VA. Schedule an appointment today!", "marks": ["em", "strong"]}]}, {"_type": "block", "_key": "b001625", "style": "normal", "children": [{"_type": "span", "_key": "s001624", "text": "At Maico Audiological Services, we offer more than just hearing aids. We are dedicated to providing personalized hearing care that helps you hear better and live life to the fullest. Our experienced audiologists and hearing instrument specialist take the time to understand your unique needs and match you with the right hearing solution."}]}, {"_type": "block", "_key": "b001627", "style": "normal", "children": [{"_type": "span", "_key": "s001626", "text": "Whether you’re exploring hearing aids for the first time or looking to improve your current devices, we’ll be with you every step of the way, offering expert guidance, ongoing support, and care you can trust."}]}, {"_type": "block", "_key": "b001629", "style": "h2", "children": [{"_type": "span", "_key": "s001628", "text": "Why Choose Professional Hearing Aid Services?"}]}, {"_type": "block", "_key": "b001631", "style": "normal", "children": [{"_type": "span", "_key": "s001630", "text": "When you choose professional hearing aid services, you’re not just buying a device; you’re getting a partner in your hearing journey. At Maico Audiological Services, our hearing healthcare team will create a custom solution based on your hearing profile, lifestyle, budget, and preferences."}]}, {"_type": "block", "_key": "b001633", "style": "h2", "children": [{"_type": "span", "_key": "s001632", "text": "Our Hearing Aid Services"}]}, {"_type": "block", "_key": "b001635", "style": "normal", "children": [{"_type": "span", "_key": "s001634", "text": "From selecting the best hearing aid for your needs to ensuring proper fittings, cleanings, and repairs, we’re with you through every stage of your hearing journey. Our goal is to keep you enjoying clear, comfortable sound in every moment of your life."}]}, {"_type": "block", "_key": "b001637", "style": "h3", "children": [{"_type": "span", "_key": "s001636", "text": "Hearing Aid Fittings"}]}, {"_type": "block", "_key": "b001639", "style": "normal", "children": [{"_type": "span", "_key": "s001638", "text": "Getting the perfect fit is key to getting the most out of your hearing aids. Our audiologist and hearing instrument specialist will make sure your devices are properly adjusted for your hearing loss, comfort, and lifestyle, giving you the best hearing experience possible."}]}, {"_type": "block", "_key": "b001641", "style": "h3", "children": [{"_type": "span", "_key": "s001640", "text": "Hearing Aid Cleaning and Repair"}]}, {"_type": "block", "_key": "b001643", "style": "normal", "children": [{"_type": "span", "_key": "s001642", "text": "If your hearing aid isn’t working quite right, we can help. We offer fast, reliable cleaning and repair services to keep your devices functioning at their best so you can keep hearing clearly."}]}, {"_type": "block", "_key": "b001645", "style": "h3", "children": [{"_type": "span", "_key": "s001644", "text": "Hearing Aid Batteries and Accessories"}]}, {"_type": "block", "_key": "b001647", "style": "normal", "children": [{"_type": "span", "_key": "s001646", "text": "Keep your hearing aids working their best with our selection of essential accessories. We offer batteries, cleaning kits, drying tools, and more. We make it easy to take care of your hearing aids so you can rely on them every day."}]}, {"_type": "block", "_key": "b001649", "style": "h3", "children": [{"_type": "span", "_key": "s001648", "text": "Assistive Listening Devices"}]}, {"_type": "block", "_key": "b001651", "style": "normal", "children": [{"_type": "span", "_key": "s001650", "text": "If you find it hard to hear clearly on the phone, in noisy settings, or while watching TV, our assistive listening devices can help. We offer solutions like CaptionCall phones that display real-time captions, making conversations easier to follow. Enjoy clearer hearing at home, at work, or on the go with ALDs tailored to your needs."}]}, {"_type": "block", "_key": "b001653", "style": "h2", "children": [{"_type": "span", "_key": "s001652", "text": "Hearing Aid Services in Virginia"}]}, {"_type": "block", "_key": "b001655", "style": "normal", "children": [{"_type": "span", "_key": "s001654", "text": "At Maico Audiological Services, we’re passionate about helping you hear better and live better. From your first visit to hearing aid adjustments, we’re here for you. Trust us to be your source of expert advice, personalized care, and high-quality hearing solutions in Newport News, VA, Chesapeake, VA, and Smithfield, VA."}]}, {"_type": "block", "_key": "b001657", "style": "normal", "children": [{"_type": "span", "_key": "s001656", "text": "Give us a call today to schedule your consultation!"}]}]','Hearing Aid Services | Maico Audiological Services','Maico Audiological Services provides expert hearing aid services in Virginia. Schedule an appointment today!');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M44R8JB7PKX4Q0EQ5RH','audiology-services/hearing-tests','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M448XWJ6ERGG90YEBC4',NULL,'en','01KS5Y1M44R8JB7PKX4Q0EQ5RH','Hearing Tests','[{"_type": "block", "_key": "b001659", "style": "normal", "children": [{"_type": "span", "_key": "s001658", "text": "Maico Audiological Services provides comprehensive hearing tests in Newport News, VA, Chesapeake, VA, and Smithfield, VA.", "marks": ["em", "strong"]}]}, {"_type": "block", "_key": "b001661", "style": "normal", "children": [{"_type": "span", "_key": "s001660", "text": "Hearing tests are one of the best ways to understand your hearing health. They give us a clear picture of how well you hear and help us spot any problems that might be affecting the way you communicate with others."}]}, {"_type": "block", "_key": "b001663", "style": "normal", "children": [{"_type": "span", "_key": "s001662", "text": "At Maico Audiological Services, our audiologists and hearing instrument specialists use advanced tools to check your hearing and create solutions that fit your needs. We’re here to guide you through every step of the process so you can enjoy better hearing with comfort and clarity."}]}, {"_type": "block", "_key": "b001665", "style": "h2", "children": [{"_type": "span", "_key": "s001664", "text": "When Should You Get Your Hearing Tested?"}]}, {"_type": "block", "_key": "b001667", "style": "normal", "children": [{"_type": "span", "_key": "s001666", "text": "Hearing loss often happens slowly, which means you might not notice the changes right away. Early signs can be small but important. You may:"}]}, {"_type": "block", "_key": "b001669", "style": "normal", "children": [{"_type": "span", "_key": "s001668", "text": "Struggle to follow conversations, especially in noisy places"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001671", "style": "normal", "children": [{"_type": "span", "_key": "s001670", "text": "Ask people to repeat themselves more often"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001673", "style": "normal", "children": [{"_type": "span", "_key": "s001672", "text": "Feel like others are mumbling or not speaking clearly"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001675", "style": "normal", "children": [{"_type": "span", "_key": "s001674", "text": "Turn up the TV or radio louder than before"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001677", "style": "normal", "children": [{"_type": "span", "_key": "s001676", "text": "If any of these sound familiar, it’s time to schedule a hearing test. A professional hearing test from our audiologist or hearing instrument specialist gives you answers and peace of mind."}]}, {"_type": "block", "_key": "b001679", "style": "h2", "children": [{"_type": "span", "_key": "s001678", "text": "Hearing Tests We Offer"}]}, {"_type": "block", "_key": "b001681", "style": "normal", "children": [{"_type": "span", "_key": "s001680", "text": "At Maico Audiological Services, we provide a variety of hearing tests to learn more about your hearing health. Some of the common tests include:"}]}, {"_type": "block", "_key": "b001683", "style": "normal", "children": [{"_type": "span", "_key": "s001682", "text": "Pure-Tone Audiometry"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001685", "style": "normal", "children": [{"_type": "span", "_key": "s001684", "text": "Speech Audiometry"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001687", "style": "normal", "children": [{"_type": "span", "_key": "s001686", "text": "Tympanometry"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001689", "style": "normal", "children": [{"_type": "span", "_key": "s001688", "text": "These tests help us build a full picture of your hearing so we can find the best solution for you."}]}, {"_type": "block", "_key": "b001691", "style": "h2", "children": [{"_type": "span", "_key": "s001690", "text": "What to Expect During Your Hearing Test"}]}, {"_type": "block", "_key": "b001693", "style": "normal", "children": [{"_type": "span", "_key": "s001692", "text": "Hearing tests are safe, simple, and painless. They usually take about 30 to 45 minutes. Here’s what happens when you come in:"}]}, {"_type": "block", "_key": "b001695", "style": "normal", "children": [{"_type": "span", "_key": "s001694", "text": "Conversation and history – We’ll talk with you about your hearing, health history, and any concerns you may have."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001697", "style": "normal", "children": [{"_type": "span", "_key": "s001696", "text": "Ear exam – We’ll take a look inside your ears to check for things like earwax buildup or signs of infection."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001699", "style": "normal", "children": [{"_type": "span", "_key": "s001698", "text": "The hearing test – You’ll wear headphones and listen to different tones and words at various volumes and pitches. Your job is to respond whenever you hear them."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001701", "style": "normal", "children": [{"_type": "span", "_key": "s001700", "text": "That’s it! It’s an easy process that gives us powerful information about your hearing."}]}, {"_type": "block", "_key": "b001703", "style": "h2", "children": [{"_type": "span", "_key": "s001702", "text": "Understanding Your Results"}]}, {"_type": "block", "_key": "b001705", "style": "normal", "children": [{"_type": "span", "_key": "s001704", "text": "After the test, an audiologist or hearing instrument specialist will review your results with you using a chart called an audiogram. If we find signs of hearing loss, we’ll explain what it means and discuss the next steps. Treatment options may include:"}]}, {"_type": "block", "_key": "b001707", "style": "normal", "children": [{"_type": "span", "_key": "s001706", "text": "Hearing aids"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001709", "style": "normal", "children": [{"_type": "span", "_key": "s001708", "text": "Assistive listening devices"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001711", "style": "normal", "children": [{"_type": "span", "_key": "s001710", "text": "Custom ear protection"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001713", "style": "normal", "children": [{"_type": "span", "_key": "s001712", "text": "Referrals for medical care if needed"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001715", "style": "normal", "children": [{"_type": "span", "_key": "s001714", "text": "Our goal is simple: to help you hear clearly and enjoy the conversations and sounds that matter most."}]}, {"_type": "block", "_key": "b001717", "style": "h3", "children": [{"_type": "span", "_key": "s001716", "text": "Frequently Asked Questions About Hearing Tests"}]}, {"_type": "block", "_key": "b001719", "style": "h4", "children": [{"_type": "span", "_key": "s001718", "text": "Can I test my own hearing?"}]}, {"_type": "block", "_key": "b001721", "style": "normal", "children": [{"_type": "span", "_key": "s001720", "text": "There are online hearing screenings, but they don’t match the accuracy of a professional test."}]}, {"_type": "block", "_key": "b001723", "style": "h4", "children": [{"_type": "span", "_key": "s001722", "text": "Are hearing tests safe?"}]}, {"_type": "block", "_key": "b001725", "style": "normal", "children": [{"_type": "span", "_key": "s001724", "text": "Yes. Hearing tests are completely safe, painless, and non-invasive."}]}, {"_type": "block", "_key": "b001727", "style": "h4", "children": [{"_type": "span", "_key": "s001726", "text": "Are online hearing tests reliable?"}]}, {"_type": "block", "_key": "b001729", "style": "normal", "children": [{"_type": "span", "_key": "s001728", "text": "They may give you a general idea, but they can’t check things like speech understanding or middle ear function."}]}, {"_type": "block", "_key": "b001731", "style": "h4", "children": [{"_type": "span", "_key": "s001730", "text": "Can I take a hearing test on my phone?"}]}, {"_type": "block", "_key": "b001733", "style": "normal", "children": [{"_type": "span", "_key": "s001732", "text": "Some apps offer simple screenings, but they cannot diagnose hearing loss or find its cause."}]}, {"_type": "block", "_key": "b001735", "style": "h4", "children": [{"_type": "span", "_key": "s001734", "text": "How often should I get a hearing test?"}]}, {"_type": "block", "_key": "b001737", "style": "normal", "children": [{"_type": "span", "_key": "s001736", "text": "If you have normal hearing, every 3 to 5 years is fine. If you already have hearing loss, wear hearing aids, or are exposed to loud sounds often, a yearly test is best."}]}, {"_type": "block", "_key": "b001739", "style": "h2", "children": [{"_type": "span", "_key": "s001738", "text": "Schedule Your Hearing Test in Virginia Today!"}]}, {"_type": "block", "_key": "b001741", "style": "normal", "children": [{"_type": "span", "_key": "s001740", "text": "Getting your hearing tested is the first step toward better hearing."}]}, {"_type": "block", "_key": "b001743", "style": "normal", "children": [{"_type": "span", "_key": "s001742", "text": "At Maico Audiological Services, our audiologist or hearing instrument specialist is here to help you understand your hearing and find the right solution for your needs."}]}, {"_type": "block", "_key": "b001745", "style": "normal", "children": [{"_type": "span", "_key": "s001744", "text": "Call today to schedule your hearing test in Newport News, VA, Chesapeake, VA, or Smithfield, VA."}]}]','Hearing Tests | Maico Audiological Services','Maico Audiological Services provides comprehensive hearing tests in Virginia. Schedule one today!');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M4XZ0N12236WRNYYGVQ','audiology-services/hearing-aid-fittings','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M4XCCYKX4AHT7W5YCR6',NULL,'en','01KS5Y1M4XZ0N12236WRNYYGVQ','Hearing Aid Fittings','[{"_type": "block", "_key": "b001747", "style": "normal", "children": [{"_type": "span", "_key": "s001746", "text": "Maico Audiological Services provides expert hearing aid fittings in Newport News, VA, Chesapeake, VA, and Smithfield, VA.", "marks": ["em", "strong"]}]}, {"_type": "block", "_key": "b001749", "style": "normal", "children": [{"_type": "span", "_key": "s001748", "text": "Hearing aids are not just small devices that make sounds louder. They need to be carefully adjusted so that they match your personal hearing needs. A professional fitting with an audiologist or hearing instrument specialist makes sure your hearing aids sound natural, feel comfortable, and truly improve your everyday life."}]}, {"_type": "block", "_key": "b001751", "style": "normal", "children": [{"_type": "span", "_key": "s001750", "text": "At Maico Audiological Services, our skilled audiologist and hearing instrument specialist use the latest tools and proven methods to set up your hearing aids. We take the time to make sure they fit you properly, so you can enjoy clear and confident hearing."}]}, {"_type": "block", "_key": "b001753", "style": "h2", "children": [{"_type": "span", "_key": "s001752", "text": "Why a Professional Hearing Aid Fitting Matters"}]}, {"_type": "block", "_key": "b001755", "style": "normal", "children": [{"_type": "span", "_key": "s001754", "text": "A good fitting is the difference between “just hearing” and “hearing well.” When your hearing aids are set up the right way, you’ll notice:"}]}, {"_type": "block", "_key": "b001757", "style": "normal", "children": [{"_type": "span", "_key": "s001756", "text": "Clearer speech, even in noisy places"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001759", "style": "normal", "children": [{"_type": "span", "_key": "s001758", "text": "Less strain when listening"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001761", "style": "normal", "children": [{"_type": "span", "_key": "s001760", "text": "Sounds that feel natural instead of too sharp or too dull"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001763", "style": "normal", "children": [{"_type": "span", "_key": "s001762", "text": "Without a proper fitting, hearing aids may feel uncomfortable or sound unbalanced. That’s why professional care is so important."}]}, {"_type": "block", "_key": "b001765", "style": "h3", "children": [{"_type": "span", "_key": "s001764", "text": "What Happens During a Hearing Aid Fitting"}]}, {"_type": "block", "_key": "b001767", "style": "normal", "children": [{"_type": "span", "_key": "s001766", "text": "During your appointment, our audiologist or hearing instrument specialist will:"}]}, {"_type": "block", "_key": "b001769", "style": "normal", "children": [{"_type": "span", "_key": "s001768", "text": "Review your hearing test results and explain how hearing aids can help."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001771", "style": "normal", "children": [{"_type": "span", "_key": "s001770", "text": "Help you choose the style and model that fits your needs and lifestyle."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001773", "style": "normal", "children": [{"_type": "span", "_key": "s001772", "text": "Program your hearing aids using special software designed for your exact hearing loss."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001775", "style": "normal", "children": [{"_type": "span", "_key": "s001774", "text": "Use Real Ear Measurement (REM), a test that places a small microphone in your ear canal. This checks that your hearing aids are giving you the right amount of sound for your unique ear shape."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001777", "style": "normal", "children": [{"_type": "span", "_key": "s001776", "text": "Teach you how to use and care for your hearing aids, including how to put them in, take them out, clean them, and store them safely."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001779", "style": "normal", "children": [{"_type": "span", "_key": "s001778", "text": "Before you leave, you’ll feel confident about how your hearing aids work and what to expect as you adjust to them."}]}, {"_type": "block", "_key": "b001781", "style": "h2", "children": [{"_type": "span", "_key": "s001780", "text": "What to Expect After Your First Fitting"}]}, {"_type": "block", "_key": "b001783", "style": "normal", "children": [{"_type": "span", "_key": "s001782", "text": "The first fitting is just the beginning. It’s normal if sounds seem a little different at first. You may notice things you haven’t heard in years, like footsteps, paper rustling, or clocks ticking. Even your own voice may sound unusual. This is part of the adjustment process as your brain gets used to hearing again."}]}, {"_type": "block", "_key": "b001785", "style": "normal", "children": [{"_type": "span", "_key": "s001784", "text": "We’ll schedule follow-up visits to fine-tune your hearing aids based on your experience. Our goal is to make sure you feel comfortable and happy with your devices."}]}, {"_type": "block", "_key": "b001787", "style": "h2", "children": [{"_type": "span", "_key": "s001786", "text": "Adjusting to Hearing Aids"}]}, {"_type": "block", "_key": "b001789", "style": "normal", "children": [{"_type": "span", "_key": "s001788", "text": "Getting used to hearing aids takes time and patience. Here are a few tips to make the process easier:"}]}, {"_type": "block", "_key": "b001791", "style": "normal", "children": [{"_type": "span", "_key": "s001790", "text": "Wear your hearing aids for a few hours each day at first, then increase the time little by little."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001793", "style": "normal", "children": [{"_type": "span", "_key": "s001792", "text": "Start in quieter settings before moving into louder environments."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001795", "style": "normal", "children": [{"_type": "span", "_key": "s001794", "text": "Remember, it may take a few weeks for your brain to adjust."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001797", "style": "normal", "children": [{"_type": "span", "_key": "s001796", "text": "With daily use and support from our specialists, you’ll soon feel more confident in your hearing."}]}, {"_type": "block", "_key": "b001799", "style": "h2", "children": [{"_type": "span", "_key": "s001798", "text": "Why Real Ear Measurement (REM) Is Important"}]}, {"_type": "block", "_key": "b001801", "style": "normal", "children": [{"_type": "span", "_key": "s001800", "text": "No two ears are exactly the same. Real Ear Measurement makes sure your hearing aids are customized to your ear’s shape and your exact hearing needs. This means:"}]}, {"_type": "block", "_key": "b001803", "style": "normal", "children": [{"_type": "span", "_key": "s001802", "text": "Clearer speech understanding"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001805", "style": "normal", "children": [{"_type": "span", "_key": "s001804", "text": "More natural sound quality"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001807", "style": "normal", "children": [{"_type": "span", "_key": "s001806", "text": "A comfortable fit that works all day"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001809", "style": "normal", "children": [{"_type": "span", "_key": "s001808", "text": "At Maico Audiological Services, we always include REM in your fitting because we want you to get the very best results."}]}, {"_type": "block", "_key": "b001811", "style": "h3", "children": [{"_type": "span", "_key": "s001810", "text": "Hearing Aid Fitting FAQs"}]}, {"_type": "block", "_key": "b001813", "style": "h4", "children": [{"_type": "span", "_key": "s001812", "text": "Are hearing aid fittings covered by insurance?"}]}, {"_type": "block", "_key": "b001815", "style": "normal", "children": [{"_type": "span", "_key": "s001814", "text": "Coverage depends on your plan. Medicare usually does not cover hearing aids, but some private insurance plans or veterans’ benefits may help."}]}, {"_type": "block", "_key": "b001817", "style": "h4", "children": [{"_type": "span", "_key": "s001816", "text": "How long does a hearing aid fitting take?"}]}, {"_type": "block", "_key": "b001819", "style": "normal", "children": [{"_type": "span", "_key": "s001818", "text": "Your first fitting usually lasts about an hour. We’ll also schedule follow-up visits to make adjustments once you’ve had time to use your hearing aids in daily life."}]}, {"_type": "block", "_key": "b001821", "style": "h4", "children": [{"_type": "span", "_key": "s001820", "text": "What if my hearing aids don’t feel comfortable?"}]}, {"_type": "block", "_key": "b001823", "style": "normal", "children": [{"_type": "span", "_key": "s001822", "text": "If your hearing aids don’t feel comfortable, please tell us right away. We can adjust the fit, try different ear tips, or even create custom earmolds to make sure your devices feel and sound right."}]}, {"_type": "block", "_key": "b001825", "style": "h2", "children": [{"_type": "span", "_key": "s001824", "text": "Schedule Your Hearing Aid Fitting in Virginia"}]}, {"_type": "block", "_key": "b001827", "style": "normal", "children": [{"_type": "span", "_key": "s001826", "text": "At Maico Audiological Services, we want to help you hear your best with hearing aids that are fitted just for you. From your first appointment to follow-up care, we’re here to guide you every step of the way."}]}, {"_type": "block", "_key": "b001829", "style": "normal", "children": [{"_type": "span", "_key": "s001828", "text": "Call today to schedule your hearing aid fitting in Newport News, VA, Chesapeake, VA, or Smithfield, VA."}]}]','Hearing Aid Fittings | Maico Audiological Services','Maico Audiological Services provides expert hearing aid fittings in Virginia. Call us to book an appointment!');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M5MHY5C2DACS1B1K99T','audiology-services/real-ear-measurement','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M5M1BXBWCSC7Z9WMM1X',NULL,'en','01KS5Y1M5MHY5C2DACS1B1K99T','Real Ear Measurement','[{"_type": "block", "_key": "b001831", "style": "normal", "children": [{"_type": "span", "_key": "s001830", "text": "Maico Audiological Services provides real ear measurements as part of hearing aid fitting best practices in Newport News, VA, Chesapeake, VA, and Smithfield, VA.", "marks": ["strong", "em"]}]}, {"_type": "block", "_key": "b001833", "style": "normal", "children": [{"_type": "span", "_key": "s001832", "text": "When it comes to hearing aids, getting the right fit is about more than just comfort. It’s also about sound quality. Real Ear Measurement (REM) is one of the most important steps in making sure your hearing aids give you the clearest, most natural sound possible."}]}, {"_type": "block", "_key": "b001837", "style": "normal", "children": [{"_type": "span", "_key": "s001834", "text": "Everyone’s ears are different. Some ear canals are wide, others are narrow, and some have twists and turns. Because of these differences, sound travels through each person’s ears in its own unique way. That’s why using REM is so important. It helps us see exactly how sound behaves inside"}, {"_type": "span", "_key": "s001835", "text": "your", "marks": ["em"]}, {"_type": "span", "_key": "s001836", "text": "ears, not just in a test setting."}]}, {"_type": "block", "_key": "b001839", "style": "normal", "children": [{"_type": "span", "_key": "s001838", "text": "At Maico Audiological Services, our audiologist and hearing instrument specialist use REM to fine-tune your hearing aids so they match your exact needs. This means speech is easier to follow, everyday sounds feel more natural, and noisy places are less overwhelming."}]}, {"_type": "block", "_key": "b001841", "style": "h2", "children": [{"_type": "span", "_key": "s001840", "text": "Why Is Real Ear Measurement Important?"}]}, {"_type": "block", "_key": "b001843", "style": "normal", "children": [{"_type": "span", "_key": "s001842", "text": "REM is often called the “gold standard” in hearing aid fittings. That’s because it makes the fitting process much more accurate than simply using factory settings or a “best guess.”"}]}, {"_type": "block", "_key": "b001845", "style": "normal", "children": [{"_type": "span", "_key": "s001844", "text": "Without REM, hearing aids might sound too loud, too soft, or unbalanced. This can cause frustration, listening fatigue, and the feeling that your hearing aids just don’t work as well as they should. With REM, your hearing aids are adjusted for your exact ears, giving you the clearest and most comfortable results possible."}]}, {"_type": "block", "_key": "b001847", "style": "h3", "children": [{"_type": "span", "_key": "s001846", "text": "How Does Real Ear Measurement Work?"}]}, {"_type": "block", "_key": "b001849", "style": "normal", "children": [{"_type": "span", "_key": "s001848", "text": "The REM process is simple, safe, and painless:"}]}, {"_type": "block", "_key": "b001851", "style": "normal", "children": [{"_type": "span", "_key": "s001850", "text": "A tiny probe microphone is placed gently in your ear canal while you wear your hearing aid. It sits close to your eardrum but doesn’t touch it, so it’s completely comfortable."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001853", "style": "normal", "children": [{"_type": "span", "_key": "s001852", "text": "Test sounds are played through a small speaker. The microphone measures how those sounds behave inside your ear canal."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001855", "style": "normal", "children": [{"_type": "span", "_key": "s001854", "text": "We compare the results to your ideal hearing levels, based on your hearing test."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001857", "style": "normal", "children": [{"_type": "span", "_key": "s001856", "text": "Adjustments are made on the spot to your hearing aids, so they deliver just the right amount of amplification for your ears."}], "listItem": "number", "level": 1}, {"_type": "block", "_key": "b001859", "style": "normal", "children": [{"_type": "span", "_key": "s001858", "text": "Most patients can hear the difference right away. Once everything sounds balanced, we double-check the results to make sure your hearing aids are working at their very best."}]}, {"_type": "block", "_key": "b001861", "style": "h3", "children": [{"_type": "span", "_key": "s001860", "text": "Why REM Is Better Than Automatic Programming"}]}, {"_type": "block", "_key": "b001863", "style": "normal", "children": [{"_type": "span", "_key": "s001862", "text": "Today’s hearing aids come with something called “first fit,” which is a preset program built into the device. While convenient, these automatic settings don’t take into account the unique shape of your ears."}]}, {"_type": "block", "_key": "b001865", "style": "normal", "children": [{"_type": "span", "_key": "s001864", "text": "Think of it like buying shoes in your size without trying them on. They might fit okay, but they probably won’t feel perfect."}]}, {"_type": "block", "_key": "b001867", "style": "normal", "children": [{"_type": "span", "_key": "s001866", "text": "REM, on the other hand, is like having custom-fit shoes made just for you. Instead of relying on averages, it measures sound directly in your ears and adjusts your hearing aids based on real results. That’s what makes the difference between “good enough” and truly great hearing."}]}, {"_type": "block", "_key": "b001869", "style": "h2", "children": [{"_type": "span", "_key": "s001868", "text": "Hearing Aid Fittings at Maico Audiological Services"}]}, {"_type": "block", "_key": "b001871", "style": "normal", "children": [{"_type": "span", "_key": "s001870", "text": "At Maico Audiological Services, we believe every hearing aid fitting should include Real Ear Measurement. Whether you’re getting hearing aids for the first time or upgrading to a new pair, REM ensures you get the most out of your devices."}]}, {"_type": "block", "_key": "b001873", "style": "normal", "children": [{"_type": "span", "_key": "s001872", "text": "Our audiologist and hearing instrument specialist are trained to make precise adjustments so your hearing aids deliver clear, comfortable sound in every situation. We’re here to make sure you feel confident in your hearing and stay connected to the people and moments that matter most."}]}, {"_type": "block", "_key": "b001875", "style": "h2", "children": [{"_type": "span", "_key": "s001874", "text": "Schedule a Hearing Aid Fitting in Virginia"}]}, {"_type": "block", "_key": "b001877", "style": "normal", "children": [{"_type": "span", "_key": "s001876", "text": "Don’t settle for hearing aids that just “sort of work.” With Real Ear Measurement, you can enjoy sound that feels natural, speech that’s easier to follow, and hearing that fits your life, not just your ears."}]}, {"_type": "block", "_key": "b001879", "style": "normal", "children": [{"_type": "span", "_key": "s001878", "text": "Call Maico Audiological Services today to schedule your hearing aid fitting with Real Ear Measurement in Newport News, VA, Chesapeake, VA, and Smithfield, VA."}]}]','Real Ear Measurement | Maico Audiological Services','Maico Audiological Servicesprovides real ear measurements as part of hearing aid fitting best practices in Virginia. Contact us to learn more.');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M6BCANZH7QAEPFGD89A','audiology-services/sensorineural-hearing-loss','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M6B2R6Y20Y31HT77YFS',NULL,'en','01KS5Y1M6BCANZH7QAEPFGD89A','Sensorineural Hearing Loss Evaluation and Treatment','[{"_type": "block", "_key": "b001881", "style": "normal", "children": [{"_type": "span", "_key": "s001880", "text": "Maico Audiological Services provides sensorineural hearing loss evaluation and treatment in Newport News, VA, Chesapeake, VA, and Smithfield, VA.", "marks": ["em", "strong"]}]}, {"_type": "block", "_key": "b001883", "style": "normal", "children": [{"_type": "span", "_key": "s001882", "text": "Sensorineural hearing loss, or SNHL, happens when the inner ear or the hearing nerve is damaged. This type of hearing loss can make soft sounds very hard to hear, while louder sounds may seem unclear, muffled, or fuzzy."}]}, {"_type": "block", "_key": "b001885", "style": "normal", "children": [{"_type": "span", "_key": "s001884", "text": "Inside your inner ear are tiny hair cells that help carry sound to your brain. Once these cells are damaged, they cannot grow back. Because of this, SNHL is usually permanent. But with the right care, many people can manage it well and enjoy a better quality of life."}]}, {"_type": "block", "_key": "b001887", "style": "h2", "children": [{"_type": "span", "_key": "s001886", "text": "Why Getting Treatment Matters"}]}, {"_type": "block", "_key": "b001889", "style": "normal", "children": [{"_type": "span", "_key": "s001888", "text": "Untreated hearing loss can make everyday life harder. It may cause you to miss parts of conversations, avoid social activities, or feel left out with family and friends. Over time, it can also lead to frustration, loneliness, and even problems with memory or focus. The good news is that with early testing and proper treatment, you can improve your hearing and stay connected to the people and activities you love."}]}, {"_type": "block", "_key": "b001891", "style": "normal", "children": [{"_type": "span", "_key": "s001890", "text": "At Maico Audiological Services, our audiologist or hearing instrument specialist in Newport News, VA, Chesapeake, VA, and Smithfield, VA provides complete hearing evaluations and personalized treatment plans for sensorineural hearing loss."}]}, {"_type": "block", "_key": "b001893", "style": "h2", "children": [{"_type": "span", "_key": "s001892", "text": "Signs You May Have Sensorineural Hearing Loss"}]}, {"_type": "block", "_key": "b001895", "style": "normal", "children": [{"_type": "span", "_key": "s001894", "text": "SNHL can develop slowly over time or, in some cases, happen suddenly. Common signs include:"}]}, {"_type": "block", "_key": "b001897", "style": "normal", "children": [{"_type": "span", "_key": "s001896", "text": "Trouble hearing soft voices or whispers"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001899", "style": "normal", "children": [{"_type": "span", "_key": "s001898", "text": "Feeling like people are mumbling"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001901", "style": "normal", "children": [{"_type": "span", "_key": "s001900", "text": "Often asking others to repeat themselves"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001903", "style": "normal", "children": [{"_type": "span", "_key": "s001902", "text": "Difficulty following conversations in noisy places"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001905", "style": "normal", "children": [{"_type": "span", "_key": "s001904", "text": "Hearing ringing, buzzing, or hissing sounds (tinnitus)"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001907", "style": "normal", "children": [{"_type": "span", "_key": "s001906", "text": "Hearing better in one ear than the other"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001909", "style": "normal", "children": [{"_type": "span", "_key": "s001908", "text": "Sounds seem unclear or distant"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001911", "style": "normal", "children": [{"_type": "span", "_key": "s001910", "text": "Trouble hearing high-pitched sounds, like birds or children’s voices"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001913", "style": "normal", "children": [{"_type": "span", "_key": "s001912", "text": "If you notice these changes, it’s important to schedule a hearing test. Maico Audiological Services provides hearing tests in Newport News, VA, Chesapeake, VA, and Smithfield, VA."}]}, {"_type": "block", "_key": "b001915", "style": "h2", "children": [{"_type": "span", "_key": "s001914", "text": "What Causes Sensorineural Hearing Loss?"}]}, {"_type": "block", "_key": "b001917", "style": "normal", "children": [{"_type": "span", "_key": "s001916", "text": "There are many reasons SNHL can happen, such as:"}]}, {"_type": "block", "_key": "b001919", "style": "normal", "children": [{"_type": "span", "_key": "s001918", "text": "Aging – The tiny hair cells in the inner ear wear down over time."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001921", "style": "normal", "children": [{"_type": "span", "_key": "s001920", "text": "Loud noise – Long-term noise exposure, or even one very loud event like a gunshot or explosion, can cause damage."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001923", "style": "normal", "children": [{"_type": "span", "_key": "s001922", "text": "Genetics – Some people are born with hearing problems or develop them earlier due to inherited traits."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001925", "style": "normal", "children": [{"_type": "span", "_key": "s001924", "text": "Certain medications – Some medicines, called ototoxic drugs, can harm hearing. These may include chemotherapy drugs, some antibiotics, or high doses of aspirin."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001927", "style": "normal", "children": [{"_type": "span", "_key": "s001926", "text": "Head injuries – Trauma to the head can damage the inner ear or hearing nerve."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001929", "style": "normal", "children": [{"_type": "span", "_key": "s001928", "text": "Infections – Illnesses like meningitis, measles, or mumps can injure the inner ear."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001931", "style": "h2", "children": [{"_type": "span", "_key": "s001930", "text": "How We Diagnose and Treat SNHL"}]}, {"_type": "block", "_key": "b001933", "style": "normal", "children": [{"_type": "span", "_key": "s001932", "text": "At Maico Audiological Services, we start with a full hearing test to determine the type and degree of hearing loss. If we find sensorineural hearing loss, we’ll discuss solutions that fit your lifestyle and needs. Our audiologist or hearing instrument specialist will help you choose the best option for comfort, clarity, and your daily life."}]}, {"_type": "block", "_key": "b001935", "style": "h3", "children": [{"_type": "span", "_key": "s001934", "text": "Can Sensorineural Hearing Loss Be Cured?"}]}, {"_type": "block", "_key": "b001937", "style": "normal", "children": [{"_type": "span", "_key": "s001936", "text": "Right now, there is no cure for SNHL because the damaged hair cells do not grow back. However, with the right devices and care, you can greatly improve your hearing and continue enjoying conversations, music, and the world around you."}]}, {"_type": "block", "_key": "b001939", "style": "h2", "children": [{"_type": "span", "_key": "s001938", "text": "How to Protect Your Hearing"}]}, {"_type": "block", "_key": "b001941", "style": "normal", "children": [{"_type": "span", "_key": "s001940", "text": "While not all SNHL can be prevented, there are steps you can take to lower your risk:"}]}, {"_type": "block", "_key": "b001943", "style": "normal", "children": [{"_type": "span", "_key": "s001942", "text": "Wear hearing protection (earplugs or earmuffs) around loud sounds."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001945", "style": "normal", "children": [{"_type": "span", "_key": "s001944", "text": "Follow the 60/60 rule: listen at no more than 60% volume for no more than 60 minutes at a time when using earbuds."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001947", "style": "normal", "children": [{"_type": "span", "_key": "s001946", "text": "Take breaks to give your ears time to rest."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001949", "style": "normal", "children": [{"_type": "span", "_key": "s001948", "text": "Ask your doctor if any medications you take could affect your hearing."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001951", "style": "normal", "children": [{"_type": "span", "_key": "s001950", "text": "Schedule regular hearing check-ups for early detection."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001953", "style": "h2", "children": [{"_type": "span", "_key": "s001952", "text": "Sensorineural Hearing Loss Care in Virginia"}]}, {"_type": "block", "_key": "b001955", "style": "normal", "children": [{"_type": "span", "_key": "s001954", "text": "At Maico Audiological Services, we are committed to helping you hear your best. Our audiologist and hearing instrument specialist provide expert testing, clear explanations, and treatment options designed for your needs."}]}, {"_type": "block", "_key": "b001957", "style": "normal", "children": [{"_type": "span", "_key": "s001956", "text": "With the right care, you can enjoy better hearing and stay connected to the people and moments that matter most."}]}, {"_type": "block", "_key": "b001959", "style": "normal", "children": [{"_type": "span", "_key": "s001958", "text": "Call us today to schedule your hearing evaluation in Newport News, VA, Chesapeake, VA, and Smithfield, VA."}]}]','Sensorineural Hearing Loss Evaluation and Treatment | Maico Audiological Services','Maico Audiological Services provides sensorineural hearing loss evaluation and treatment in Virginia. Call us to book an appointment!');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M74XTQTZ96F94DR0YKE','audiology-services/tinnitus-support','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M74WDQ8CZP78Y8JHZ3S',NULL,'en','01KS5Y1M74XTQTZ96F94DR0YKE','Tinnitus Management','[{"_type": "block", "_key": "b001961", "style": "normal", "children": [{"_type": "span", "_key": "s001960", "text": "Maico Audiological Services provides expert Tinnitus Management in Newport News, VA, Chesapeake, VA, and Smithfield, VA.", "marks": ["em", "strong"]}]}, {"_type": "block", "_key": "b001963", "style": "normal", "children": [{"_type": "span", "_key": "s001962", "text": "At Maico Audiological Services, our team of audiologists and hearing instrument specialists is committed to helping patients find relief from tinnitus. Tinnitus is a common condition, but that doesn’t make it any less frustrating."}]}, {"_type": "block", "_key": "b001965", "style": "normal", "children": [{"_type": "span", "_key": "s001964", "text": "For some people, it’s a mild background noise they notice only in quiet rooms. For others, it can be a constant ringing or buzzing that interferes with concentration, sleep, and overall quality of life."}]}, {"_type": "block", "_key": "b001967", "style": "h2", "children": [{"_type": "span", "_key": "s001966", "text": "What is Tinnitus?"}]}, {"_type": "block", "_key": "b001969", "style": "normal", "children": [{"_type": "span", "_key": "s001968", "text": "Tinnitus is the perception of sound in your ears when there is no external noise present. People describe it in different ways: ringing, buzzing, hissing, clicking, or even roaring. The sound may come and go, or it may be persistent. For many, tinnitus is linked to hearing loss, but it can also be connected to other health issues."}]}, {"_type": "block", "_key": "b001971", "style": "h2", "children": [{"_type": "span", "_key": "s001970", "text": "What Causes Tinnitus?"}]}, {"_type": "block", "_key": "b001973", "style": "normal", "children": [{"_type": "span", "_key": "s001972", "text": "Tinnitus can develop for several reasons. Some of the most common causes include:"}]}, {"_type": "block", "_key": "b001975", "style": "normal", "children": [{"_type": "span", "_key": "s001974", "text": "Hearing Loss – When the brain isn’t receiving normal sound signals, it may generate its own noises."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001977", "style": "normal", "children": [{"_type": "span", "_key": "s001976", "text": "Exposure to Loud Sounds – Prolonged exposure to loud music, machinery, or concerts can damage hearing and lead to tinnitus."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001979", "style": "normal", "children": [{"_type": "span", "_key": "s001978", "text": "Earwax Buildup – Too much earwax can block the ear canal and create pressure or ringing sounds."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001981", "style": "normal", "children": [{"_type": "span", "_key": "s001980", "text": "Medications – Certain drugs list tinnitus as a side effect."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001983", "style": "normal", "children": [{"_type": "span", "_key": "s001982", "text": "Health Conditions – High blood pressure, TMJ disorders, ear infections, or other medical issues may contribute."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001985", "style": "normal", "children": [{"_type": "span", "_key": "s001984", "text": "Since there are many potential causes, the first step in managing tinnitus is always a thorough evaluation."}]}, {"_type": "block", "_key": "b001987", "style": "h2", "children": [{"_type": "span", "_key": "s001986", "text": "Tinnitus Evaluations"}]}, {"_type": "block", "_key": "b001989", "style": "normal", "children": [{"_type": "span", "_key": "s001988", "text": "If you’re experiencing tinnitus, our audiologists will perform a detailed evaluation to better understand your symptoms and identify possible causes. This process may include:"}]}, {"_type": "block", "_key": "b001991", "style": "normal", "children": [{"_type": "span", "_key": "s001990", "text": "Reviewing Your Symptoms – When did it start? Is it constant or occasional?"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001993", "style": "normal", "children": [{"_type": "span", "_key": "s001992", "text": "Physical Ear Examination – To check for earwax buildup, infection, or other blockages."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001995", "style": "normal", "children": [{"_type": "span", "_key": "s001994", "text": "Hearing Tests – Many patients with tinnitus also have some degree of hearing loss."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001997", "style": "normal", "children": [{"_type": "span", "_key": "s001996", "text": "Tinnitus Matching – You may listen to tones or sounds so we can compare and document what you’re hearing."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b001999", "style": "h2", "children": [{"_type": "span", "_key": "s001998", "text": "Tinnitus Support Options"}]}, {"_type": "block", "_key": "b002001", "style": "normal", "children": [{"_type": "span", "_key": "s002000", "text": "Although there is currently no permanent cure for tinnitus, there are many ways to reduce symptoms and improve your quality of life. At Maico Audiological Services, we offer:"}]}, {"_type": "block", "_key": "b002003", "style": "h3", "children": [{"_type": "span", "_key": "s002002", "text": "Hearing Aids"}]}, {"_type": "block", "_key": "b002005", "style": "normal", "children": [{"_type": "span", "_key": "s002004", "text": "If you also have hearing loss, hearing aids can make a significant difference. By amplifying surrounding sounds, they reduce the contrast between environmental noise and the internal ringing. Many modern hearing aids offer tinnitus support, with apps and features which play soothing background sounds to help shift focus away from tinnitus."}]}, {"_type": "block", "_key": "b002007", "style": "h3", "children": [{"_type": "span", "_key": "s002006", "text": "Lifestyle Changes"}]}, {"_type": "block", "_key": "b002009", "style": "normal", "children": [{"_type": "span", "_key": "s002008", "text": "Simple lifestyle adjustments can help reduce tinnitus severity:"}]}, {"_type": "block", "_key": "b002011", "style": "normal", "children": [{"_type": "span", "_key": "s002010", "text": "Limit caffeine and alcohol intake"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002013", "style": "normal", "children": [{"_type": "span", "_key": "s002012", "text": "Protect your ears in noisy environments"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002015", "style": "normal", "children": [{"_type": "span", "_key": "s002014", "text": "Practice relaxation or stress management techniques"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002017", "style": "normal", "children": [{"_type": "span", "_key": "s002016", "text": "Keep a consistent sleep routine"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002019", "style": "h3", "children": [{"_type": "span", "_key": "s002018", "text": "Additional Care"}]}, {"_type": "block", "_key": "b002021", "style": "normal", "children": [{"_type": "span", "_key": "s002020", "text": "If tinnitus persists or worsens, we may recommend a referral to an ENT (ear, nose, and throat) physician for further evaluation. Working together, we can help ensure you receive the best possible care."}]}, {"_type": "block", "_key": "b002023", "style": "h3", "children": [{"_type": "span", "_key": "s002022", "text": "Frequently Asked Questions About Tinnitus"}]}, {"_type": "block", "_key": "b002025", "style": "h4", "children": [{"_type": "span", "_key": "s002024", "text": "Will tinnitus go away on its own?"}]}, {"_type": "block", "_key": "b002027", "style": "normal", "children": [{"_type": "span", "_key": "s002026", "text": "Sometimes tinnitus improves over time, especially if it’s caused by temporary factors such as noise exposure or earwax. However, if it lasts more than a few weeks, an evaluation is recommended."}]}, {"_type": "block", "_key": "b002029", "style": "h4", "children": [{"_type": "span", "_key": "s002028", "text": "Can stress make tinnitus worse?"}]}, {"_type": "block", "_key": "b002031", "style": "normal", "children": [{"_type": "span", "_key": "s002030", "text": "Yes. Stress and anxiety can heighten your awareness of tinnitus, making it seem louder. Relaxation techniques and stress management can often help reduce its impact."}]}, {"_type": "block", "_key": "b002033", "style": "h4", "children": [{"_type": "span", "_key": "s002032", "text": "Is tinnitus always related to hearing loss?"}]}, {"_type": "block", "_key": "b002035", "style": "normal", "children": [{"_type": "span", "_key": "s002034", "text": "Not always. While many people with tinnitus also have hearing loss, it can occur even in those with normal hearing. A hearing test will determine whether hearing loss is a factor."}]}, {"_type": "block", "_key": "b002037", "style": "h4", "children": [{"_type": "span", "_key": "s002036", "text": "Do hearing aids really help?"}]}, {"_type": "block", "_key": "b002039", "style": "normal", "children": [{"_type": "span", "_key": "s002038", "text": "Yes. Hearing aids improve overall sound clarity and often include features designed to mask tinnitus, making it less noticeable."}]}, {"_type": "block", "_key": "b002041", "style": "h4", "children": [{"_type": "span", "_key": "s002040", "text": "Can earwax cause tinnitus?"}]}, {"_type": "block", "_key": "b002043", "style": "normal", "children": [{"_type": "span", "_key": "s002042", "text": "Yes. Blocked ear canals can cause ringing or buzzing. Professional removal often provides quick relief."}]}, {"_type": "block", "_key": "b002045", "style": "h2", "children": [{"_type": "span", "_key": "s002044", "text": "Tinnitus Management in Virginia"}]}, {"_type": "block", "_key": "b002047", "style": "normal", "children": [{"_type": "span", "_key": "s002046", "text": "Audiologists and hearing instrument specialists at Maico Audiological Services provide thorough Tinnitus management options to help you take control of your hearing health."}]}, {"_type": "block", "_key": "b002049", "style": "normal", "children": [{"_type": "span", "_key": "s002048", "text": "Don’t let tinnitus keep you from enjoying life."}]}, {"_type": "block", "_key": "b002051", "style": "normal", "children": [{"_type": "span", "_key": "s002050", "text": "Call us today to schedule your tinnitus evaluation in Newport News, Chesapeake, or Smithfield, VA."}]}]','Tinnitus Support | Maico Audiological Services','Maico Audiological Services provides expert tinnitus support in Virginia.');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M7V5C9AAWKPRNG26DGE','hearing-aids-products','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M7VMG8M7ER6Q4XDAREW',NULL,'en','01KS5Y1M7V5C9AAWKPRNG26DGE','Hearing Aids & Products','[{"_type": "block", "_key": "b002053", "style": "normal", "children": [{"_type": "span", "_key": "s002052", "text": "Maico Audiological Services provides quality hearing aids and products in Newport News, VA, Chesapeake, VA, and Smithfield, VA.", "marks": ["em", "strong"]}]}, {"_type": "block", "_key": "b002055", "style": "normal", "children": [{"_type": "span", "_key": "s002054", "text": "At Maico Audiological Services, we believe that when you hear better, you live better. That’s why we are proud to offer and service many of today’s most trusted hearing aid brands. Whether you already wear hearing aids or are just starting to explore your options, our caring audiologist, hearing instrument specialist, and audiology team are here to guide you. We’ll take the time to understand your needs, lifestyle, and comfort to help you find the hearing solution that’s right for you."}]}, {"_type": "block", "_key": "b002057", "style": "h2", "children": [{"_type": "span", "_key": "s002056", "text": "Hearing Aid Brands We Trust"}]}, {"_type": "block", "_key": "b002059", "style": "h3", "children": [{"_type": "span", "_key": "s002058", "text": "Oticon"}]}, {"_type": "block", "_key": "b002061", "style": "normal", "children": [{"_type": "span", "_key": "s002060", "text": "Oticon has been helping people hear for more than 100 years. Their BrainHearing™ technology helps your brain process sound naturally so listening feels easier. Models like Oticon Intent and Oticon Real include Bluetooth, tinnitus relief, and a natural sound experience."}]}, {"_type": "block", "_key": "b002063", "style": "h3", "children": [{"_type": "span", "_key": "s002062", "text": "Widex"}]}, {"_type": "block", "_key": "b002065", "style": "normal", "children": [{"_type": "span", "_key": "s002064", "text": "Widex is known for sound that feels pure and natural. Popular models like Widex Moment and Widex SmartRIC work with smartphones and offer Zen Therapy for tinnitus relief. Their newest model, Widex Allure, uses cloud-based fitting software for even better results."}]}, {"_type": "block", "_key": "b002067", "style": "h3", "children": [{"_type": "span", "_key": "s002066", "text": "Phonak"}]}, {"_type": "block", "_key": "b002069", "style": "normal", "children": [{"_type": "span", "_key": "s002068", "text": "Phonak is a worldwide leader in hearing aids. Models like Phonak Lumity make speech easier to understand, while Naída offers strong power for severe hearing loss. The Audéo Sphere Infinio uses advanced AI for excellent clarity in noise. The newest Infinio custom models include Virto Titanium Infinio for a discreet and powerful option."}]}, {"_type": "block", "_key": "b002071", "style": "h3", "children": [{"_type": "span", "_key": "s002070", "text": "Starkey"}]}, {"_type": "block", "_key": "b002073", "style": "normal", "children": [{"_type": "span", "_key": "s002072", "text": "Starkey combines clear sound with wellness features like fall detection, fitness tracking, and tinnitus support. Models such as Genesis AI and Evolv AI include hands-free calling, app control, and rechargeability. The Edge AI line uses smart sound processing for clearer conversations in real time."}]}, {"_type": "block", "_key": "b002075", "style": "h3", "children": [{"_type": "span", "_key": "s002074", "text": "ReSound"}]}, {"_type": "block", "_key": "b002077", "style": "normal", "children": [{"_type": "span", "_key": "s002076", "text": "ReSound hearing aids provide natural sound and easy connectivity. Models like ReSound ONE and ReSound Vivia offer rechargeable batteries, streaming to phones, and tinnitus management. The new ReSound Vivia uses artificial intelligence to improve hearing in noise. For severe hearing loss, the ReSound Enzo IA is a powerful, rechargeable option."}]}, {"_type": "block", "_key": "b002079", "style": "h3", "children": [{"_type": "span", "_key": "s002078", "text": "Unitron"}]}, {"_type": "block", "_key": "b002081", "style": "normal", "children": [{"_type": "span", "_key": "s002080", "text": "Unitron focuses on comfort and simplicity. Their Blu line adapts automatically to your surroundings, while the new Smile platform uses AI-powered tuning and improved Bluetooth for an easier listening experience."}]}, {"_type": "block", "_key": "b002083", "style": "h3", "children": [{"_type": "span", "_key": "s002082", "text": "Signia"}]}, {"_type": "block", "_key": "b002085", "style": "normal", "children": [{"_type": "span", "_key": "s002084", "text": "Signia is known for stylish design and high performance. Models like Pure Charge&Go and Silk X are small and discreet but still powerful. Features like Own Voice Processing (OVP) make your own voice sound more natural. The Integrated Xperience (IX) platform offers advanced models like Styletto AX and Motion Charge&Go X."}]}, {"_type": "block", "_key": "b002087", "style": "h2", "children": [{"_type": "span", "_key": "s002086", "text": "Custom Hearing Protection"}]}, {"_type": "block", "_key": "b002089", "style": "normal", "children": [{"_type": "span", "_key": "s002088", "text": "We also create custom earplugs for hunting, work, hobbies, or daily comfort. Whether you’re a hunter, musician, construction worker, or just want a quieter night’s sleep, custom plugs provide the right level of protection without blocking everything out."}]}, {"_type": "block", "_key": "b002091", "style": "h3", "children": [{"_type": "span", "_key": "s002090", "text": "Custom Ear Molds"}]}, {"_type": "block", "_key": "b002093", "style": "normal", "children": [{"_type": "span", "_key": "s002092", "text": "Custom ear molds are shaped to your ears for a perfect fit. They can be used for hearing aids, music in-ear monitors, headsets, or swim and sleep plugs. A proper mold gives you less whistling, more comfort, and confidence that your device will stay in place all day."}]}, {"_type": "block", "_key": "b002095", "style": "h2", "children": [{"_type": "span", "_key": "s002094", "text": "Assistive Listening Devices (ALDs)"}]}, {"_type": "block", "_key": "b002097", "style": "normal", "children": [{"_type": "span", "_key": "s002096", "text": "If you find it hard to hear clearly on the phone, in noisy settings, or while watching TV, our assistive listening devices can help. We offer solutions like CaptionCall phones that display real-time captions, making conversations easier to follow. Enjoy clearer hearing at home, at work, or on the go with ALDs tailored to your needs."}]}, {"_type": "block", "_key": "b002099", "style": "h3", "children": [{"_type": "span", "_key": "s002098", "text": "FAQs"}]}, {"_type": "block", "_key": "b002101", "style": "h4", "children": [{"_type": "span", "_key": "s002100", "text": "Which hearing aids are the most advanced?"}]}, {"_type": "block", "_key": "b002103", "style": "normal", "children": [{"_type": "span", "_key": "s002102", "text": "The best hearing aid depends on your needs, but many newer models include Bluetooth, rechargeable batteries, and noise reduction."}]}, {"_type": "block", "_key": "b002105", "style": "h4", "children": [{"_type": "span", "_key": "s002104", "text": "Which brands help with tinnitus?"}]}, {"_type": "block", "_key": "b002107", "style": "normal", "children": [{"_type": "span", "_key": "s002106", "text": "Oticon, Widex, and Starkey have special sound therapy programs."}]}, {"_type": "block", "_key": "b002109", "style": "h4", "children": [{"_type": "span", "_key": "s002108", "text": "How long do custom ear molds last?"}]}, {"_type": "block", "_key": "b002111", "style": "normal", "children": [{"_type": "span", "_key": "s002110", "text": "Custom ear molds typically last 2 to 5 years. Their lifespan depends on how well you care for them and whether your ears change shape over time."}]}, {"_type": "block", "_key": "b002113", "style": "h4", "children": [{"_type": "span", "_key": "s002112", "text": "How do I clean my custom earplugs or ear molds?"}]}, {"_type": "block", "_key": "b002115", "style": "normal", "children": [{"_type": "span", "_key": "s002114", "text": "Wipe them each day with a soft, dry cloth. For a deeper cleaning, you can use mild soap and warm water. Make sure they are completely dry before wearing them again. Avoid using harsh chemicals, as these can damage the material and shorten their lifespan."}]}, {"_type": "block", "_key": "b002117", "style": "h2", "children": [{"_type": "span", "_key": "s002116", "text": "Hearing Aids in Virginia"}]}, {"_type": "block", "_key": "b002119", "style": "normal", "children": [{"_type": "span", "_key": "s002118", "text": "At Maico Audiological Services, our mission is simple: to help you hear clearly, comfortably, and with confidence. From trusted hearing aids to custom ear protection and assistive devices, we’ll help you choose the right solution for your life."}]}, {"_type": "block", "_key": "b002121", "style": "normal", "children": [{"_type": "span", "_key": "s002120", "text": "We offer a wide selection of quality hearing aids in Newport News, VA, Chesapeake, VA, and Smithfield, VA."}]}, {"_type": "block", "_key": "b002123", "style": "normal", "children": [{"_type": "span", "_key": "s002122", "text": "Call us today to schedule your appointment!"}]}]','Hearing Aids & Products | Maico Audiological Services','Maico Audiological Services provides quality hearing aids and products in Virginia. Contact us to learn more!');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M8KZJ8ZYY2VQS028TF6','hearing-aids-products/hearing-aid-alternatives','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M8K6G5Z4N3PAHQMH7T4',NULL,'en','01KS5Y1M8KZJ8ZYY2VQS028TF6','Hearing Aid Alternatives: Assistive Listening Devices','[{"_type": "block", "_key": "b002125", "style": "normal", "children": [{"_type": "span", "_key": "s002124", "text": "Maico Audiological Services offers assistive listening devices in Newport News, VA, Chesapeake, VA, and Smithfield, VA.", "marks": ["strong", "em"]}]}, {"_type": "block", "_key": "b002127", "style": "normal", "children": [{"_type": "span", "_key": "s002126", "text": "At Maico Audiological Services, we know that even the best hearing aids may sometimes need a little extra help. Busy restaurants, large meeting rooms, churches, or even watching TV at home can still be tough listening situations. That’s where Assistive Listening Devices (ALDs) come in."}]}, {"_type": "block", "_key": "b002129", "style": "normal", "children": [{"_type": "span", "_key": "s002128", "text": "ALDs are special tools that make sound clearer in noisy places, across long distances, or in tricky environments. They can be used with your hearing aids or on their own. With the right device, you can follow conversations with confidence, enjoy your favorite shows, and stay connected without straining to hear."}]}, {"_type": "block", "_key": "b002131", "style": "h2", "children": [{"_type": "span", "_key": "s002130", "text": "Why Use an Assistive Listening Device?"}]}, {"_type": "block", "_key": "b002133", "style": "normal", "children": [{"_type": "span", "_key": "s002132", "text": "Hearing aids do an amazing job in most day-to-day settings, but certain situations are still challenging. ALDs are designed to give you an extra boost in those moments by:"}]}, {"_type": "block", "_key": "b002135", "style": "normal", "children": [{"_type": "span", "_key": "s002134", "text": "Making speech clearer in noisy spaces"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002137", "style": "normal", "children": [{"_type": "span", "_key": "s002136", "text": "Helping you hear better from a distance, like in a classroom or church"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002139", "style": "normal", "children": [{"_type": "span", "_key": "s002138", "text": "Reducing background distractions so you can focus on what matters"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002141", "style": "normal", "children": [{"_type": "span", "_key": "s002140", "text": "Making TV, phone calls, and public announcements easier to understand"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002143", "style": "normal", "children": [{"_type": "span", "_key": "s002142", "text": "In short, ALDs help you enjoy life more fully, with less effort and more comfort."}]}, {"_type": "block", "_key": "b002145", "style": "h2", "children": [{"_type": "span", "_key": "s002144", "text": "Common Types of Assistive Listening Devices"}]}, {"_type": "block", "_key": "b002147", "style": "h3", "children": [{"_type": "span", "_key": "s002146", "text": "Hearing Loop Systems"}]}, {"_type": "block", "_key": "b002149", "style": "normal", "children": [{"_type": "span", "_key": "s002148", "text": "These systems send sound directly to hearing aids or implants with a telecoil (T-coil). They are often used in churches, theaters, and auditoriums, giving you clear sound without background noise."}]}, {"_type": "block", "_key": "b002151", "style": "h3", "children": [{"_type": "span", "_key": "s002150", "text": "Infrared Systems"}]}, {"_type": "block", "_key": "b002153", "style": "normal", "children": [{"_type": "span", "_key": "s002152", "text": "Infrared systems send sound using light waves to a personal receiver with headphones or a neck loop. These are great for private listening, such as watching TV at home or in courtrooms, because the signal doesn’t travel through walls."}]}, {"_type": "block", "_key": "b002155", "style": "h3", "children": [{"_type": "span", "_key": "s002154", "text": "FM Systems"}]}, {"_type": "block", "_key": "b002157", "style": "normal", "children": [{"_type": "span", "_key": "s002156", "text": "FM systems send sound through radio waves. A speaker wears a microphone, and the listener uses a receiver. These are very popular in classrooms and meetings because they bring the speaker’s voice straight to you, even across the room."}]}, {"_type": "block", "_key": "b002159", "style": "h3", "children": [{"_type": "span", "_key": "s002158", "text": "Personal Amplifiers"}]}, {"_type": "block", "_key": "b002161", "style": "normal", "children": [{"_type": "span", "_key": "s002160", "text": "Small and portable, these devices use a microphone and headphones to boost nearby sounds. They’re handy for one-on-one conversations or watching TV without turning up the volume for everyone else."}]}, {"_type": "block", "_key": "b002163", "style": "h3", "children": [{"_type": "span", "_key": "s002162", "text": "TV Listening Systems"}]}, {"_type": "block", "_key": "b002165", "style": "normal", "children": [{"_type": "span", "_key": "s002164", "text": "TV listening systems stream sound directly from your TV to your hearing aids or wireless headphones. They can use Bluetooth, infrared, or radio frequency, and give you clear sound without blasting the TV."}]}, {"_type": "block", "_key": "b002167", "style": "h3", "children": [{"_type": "span", "_key": "s002166", "text": "CaptionCall"}]}, {"_type": "block", "_key": "b002169", "style": "normal", "children": [{"_type": "span", "_key": "s002168", "text": "For phone calls, CaptionCall is a life-changing tool. These phones display real-time captions of what the other person is saying, while also letting you hear their voice. This makes phone conversations clearer and less stressful. If you struggle to follow calls, these captioned phones can keep you connected with loved ones and work without frustration."}]}, {"_type": "block", "_key": "b002171", "style": "normal", "children": [{"_type": "span", "_key": "s002170", "text": "Talk to our audiologist or hearing instrument specialist to know more about CaptionCall."}]}, {"_type": "block", "_key": "b002173", "style": "h3", "children": [{"_type": "span", "_key": "s002172", "text": "Alerting Devices"}]}, {"_type": "block", "_key": "b002175", "style": "normal", "children": [{"_type": "span", "_key": "s002174", "text": "These devices use flashing lights, vibrations, or loud tones to signal alarms, doorbells, or other important sounds. Some connect to smartphones or smart home systems for extra convenience."}]}, {"_type": "block", "_key": "b002177", "style": "h3", "children": [{"_type": "span", "_key": "s002176", "text": "FAQs About Assistive Listening Devices"}]}, {"_type": "block", "_key": "b002179", "style": "h4", "children": [{"_type": "span", "_key": "s002178", "text": "What is the most commonly used ALD?"}]}, {"_type": "block", "_key": "b002181", "style": "normal", "children": [{"_type": "span", "_key": "s002180", "text": "FM systems are very popular, especially in classrooms or group events, because they send the speaker’s voice directly to you."}]}, {"_type": "block", "_key": "b002183", "style": "h4", "children": [{"_type": "span", "_key": "s002182", "text": "Can ALDs replace hearing aids?"}]}, {"_type": "block", "_key": "b002185", "style": "normal", "children": [{"_type": "span", "_key": "s002184", "text": "No. ALDs can help people with mild hearing needs, but they aren’t a replacement for hearing aids if you have moderate to severe hearing loss. Most people get the best results using them together."}]}, {"_type": "block", "_key": "b002187", "style": "h4", "children": [{"_type": "span", "_key": "s002186", "text": "Why use an ALD if I already have hearing aids?"}]}, {"_type": "block", "_key": "b002189", "style": "normal", "children": [{"_type": "span", "_key": "s002188", "text": "Even great hearing aids can struggle in noise or large spaces. ALDs focus on the exact sound you want to hear, making listening clearer and less tiring."}]}, {"_type": "block", "_key": "b002191", "style": "h4", "children": [{"_type": "span", "_key": "s002190", "text": "Are ALDs easy to use?"}]}, {"_type": "block", "_key": "b002193", "style": "normal", "children": [{"_type": "span", "_key": "s002192", "text": "Yes. Most are user-friendly and come with simple instructions. Our audiologist or hearing instrument specialist will show you exactly how to set them up and use them."}]}, {"_type": "block", "_key": "b002195", "style": "h4", "children": [{"_type": "span", "_key": "s002194", "text": "Can I take my ALD anywhere?"}]}, {"_type": "block", "_key": "b002197", "style": "normal", "children": [{"_type": "span", "_key": "s002196", "text": "Many ALDs are portable and can go with you, while some (like hearing loops) are installed in specific places. We’ll help you choose what fits your lifestyle best."}]}, {"_type": "block", "_key": "b002199", "style": "h2", "children": [{"_type": "span", "_key": "s002198", "text": "Assistive Listening Devices in Virginia"}]}, {"_type": "block", "_key": "b002201", "style": "normal", "children": [{"_type": "span", "_key": "s002200", "text": "If you want to make listening easier in tough environments, Maico Audiological Services is here to help. Our audiologist or hearing instrument specialist will walk you through your options and recommend solutions that fit your daily life."}]}, {"_type": "block", "_key": "b002203", "style": "normal", "children": [{"_type": "span", "_key": "s002202", "text": "Call us today to learn more about assistive listening devices in Newport News, VA, Chesapeake, VA, and Smithfield, VA."}]}]','Assistive Listening Devices | Maico Audiological Services','Maico Audiological Services offers assistive listening devices in Virginia. Contact us today!');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1M9B9P1PKSGPAM3SGFD2','hearing-aids-products/hearing-aid-batteries','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1M9BRNQHSG64177Q4ZCR',NULL,'en','01KS5Y1M9B9P1PKSGPAM3SGFD2','Hearing Aid Batteries','[{"_type": "block", "_key": "b002205", "style": "normal", "children": [{"_type": "span", "_key": "s002204", "text": "Maico Audiological Services provides hearing aid batteries in Newport News, VA, Chesapeake, VA, and Smithfield, VA to ensure that your hearing devices always function at their best.", "marks": ["em", "strong"]}]}, {"_type": "block", "_key": "b002207", "style": "normal", "children": [{"_type": "span", "_key": "s002206", "text": "Hearing aid batteries give your devices the power they need to work. Without them, your hearing aids couldn’t help you hear conversations, stream music, connect through Bluetooth, or ease ringing in the ears (tinnitus). Choosing the right battery and caring for it properly makes a big difference in how well your hearing aids perform each day."}]}, {"_type": "block", "_key": "b002209", "style": "normal", "children": [{"_type": "span", "_key": "s002208", "text": "At Maico Audiological Services, our team can guide you through your options and help you get the most out of your batteries."}]}, {"_type": "block", "_key": "b002211", "style": "h2", "children": [{"_type": "span", "_key": "s002210", "text": "Types of Hearing Aid Batteries"}]}, {"_type": "block", "_key": "b002213", "style": "h3", "children": [{"_type": "span", "_key": "s002212", "text": "Disposable Zinc-Air Batteries"}]}, {"_type": "block", "_key": "b002215", "style": "normal", "children": [{"_type": "span", "_key": "s002214", "text": "These small round “button” batteries are the most common type used in hearing aids. They are lightweight, last for several days, and have a long shelf life when stored properly. They are color-coded by size to make them easy to recognize:"}]}, {"_type": "block", "_key": "b002217", "style": "normal", "children": [{"_type": "span", "_key": "s002216", "text": "Size 10 – Yellow"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002219", "style": "normal", "children": [{"_type": "span", "_key": "s002218", "text": "Size 312 – Brown"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002221", "style": "normal", "children": [{"_type": "span", "_key": "s002220", "text": "Size 13 – Orange"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002223", "style": "normal", "children": [{"_type": "span", "_key": "s002222", "text": "Size 675 – Blue"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002225", "style": "h3", "children": [{"_type": "span", "_key": "s002224", "text": "Rechargeable Lithium-Ion Batteries"}]}, {"_type": "block", "_key": "b002227", "style": "normal", "children": [{"_type": "span", "_key": "s002226", "text": "Many of today’s new hearing aids come with built-in rechargeable batteries. With one overnight charge, they can provide all-day power, often lasting 18 to 30 hours depending on usage. These are a great choice for people who don’t want to change batteries often, or who may have trouble handling the small disposable ones. They’re also a more eco-friendly option since you don’t need to throw them away every few days."}]}, {"_type": "block", "_key": "b002229", "style": "h3", "children": [{"_type": "span", "_key": "s002228", "text": "Silver-Zinc Rechargeable Batteries"}]}, {"_type": "block", "_key": "b002231", "style": "normal", "children": [{"_type": "span", "_key": "s002230", "text": "These are less common now but are still found in some hearing aids. They can be removed and replaced when needed. Most companies have shifted to lithium-ion technology because it tends to last longer and be more convenient."}]}, {"_type": "block", "_key": "b002233", "style": "h3", "children": [{"_type": "span", "_key": "s002232", "text": "Which Battery Is Best for You?"}]}, {"_type": "block", "_key": "b002235", "style": "normal", "children": [{"_type": "span", "_key": "s002234", "text": "The right battery depends on your hearing aid model, your daily routine, and what feels easiest for you to use. If you’re not sure, our hearing instrument specialist at Maico Audiological Services can help you choose the best option for your needs and lifestyle."}]}, {"_type": "block", "_key": "b002237", "style": "h2", "children": [{"_type": "span", "_key": "s002236", "text": "Tips for Making Batteries Last Longer"}]}, {"_type": "block", "_key": "b002239", "style": "h3", "children": [{"_type": "span", "_key": "s002238", "text": "For Disposable Batteries:"}]}, {"_type": "block", "_key": "b002241", "style": "normal", "children": [{"_type": "span", "_key": "s002240", "text": "Wait 5 minutes after removing the sticker tab before inserting them."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002243", "style": "normal", "children": [{"_type": "span", "_key": "s002242", "text": "Store them in a cool, dry place (not the fridge)."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002245", "style": "normal", "children": [{"_type": "span", "_key": "s002244", "text": "Open the battery door at night to save power."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002247", "style": "normal", "children": [{"_type": "span", "_key": "s002246", "text": "Keep them clean and dry."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002249", "style": "normal", "children": [{"_type": "span", "_key": "s002248", "text": "Carry spares in their case, not loose in your pocket."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002251", "style": "h3", "children": [{"_type": "span", "_key": "s002250", "text": "For Rechargeable Batteries:"}]}, {"_type": "block", "_key": "b002253", "style": "normal", "children": [{"_type": "span", "_key": "s002252", "text": "Charge your hearing aids every night."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002255", "style": "normal", "children": [{"_type": "span", "_key": "s002254", "text": "Always use the charger made for your devices."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002257", "style": "normal", "children": [{"_type": "span", "_key": "s002256", "text": "Keep the charger and hearing aids dry."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002259", "style": "normal", "children": [{"_type": "span", "_key": "s002258", "text": "Turn them off if you’re not using them for an extended time."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002261", "style": "h2", "children": [{"_type": "span", "_key": "s002260", "text": "How to Know When It’s Time to Change a Battery"}]}, {"_type": "block", "_key": "b002263", "style": "normal", "children": [{"_type": "span", "_key": "s002262", "text": "Your hearing aids may beep, flash a small light, or give you a spoken warning when the battery is running low. You might also notice sounds becoming weak, distorted, or cutting in and out. If your hearing aids suddenly stop working, it may be time to insert a fresh battery or recharge."}]}, {"_type": "block", "_key": "b002265", "style": "h2", "children": [{"_type": "span", "_key": "s002264", "text": "Troubleshooting Battery Problems"}]}, {"_type": "block", "_key": "b002267", "style": "normal", "children": [{"_type": "span", "_key": "s002266", "text": "If your hearing aid isn’t working properly, try these quick checks:"}]}, {"_type": "block", "_key": "b002269", "style": "normal", "children": [{"_type": "span", "_key": "s002268", "text": "Is the battery the correct size?"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002271", "style": "normal", "children": [{"_type": "span", "_key": "s002270", "text": "Is the battery door closed all the way?"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002273", "style": "normal", "children": [{"_type": "span", "_key": "s002272", "text": "Are the battery contacts clean and dry?"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002275", "style": "normal", "children": [{"_type": "span", "_key": "s002274", "text": "Is the battery fresh or fully charged?"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002277", "style": "normal", "children": [{"_type": "span", "_key": "s002276", "text": "If the problem continues, bring your hearing aid to your hearing aid provider for a quick check-up."}]}, {"_type": "block", "_key": "b002279", "style": "h3", "children": [{"_type": "span", "_key": "s002278", "text": "Frequently Asked Questions"}]}, {"_type": "block", "_key": "b002281", "style": "h4", "children": [{"_type": "span", "_key": "s002280", "text": "Which type lasts longer?"}]}, {"_type": "block", "_key": "b002283", "style": "normal", "children": [{"_type": "span", "_key": "s002282", "text": "Disposable batteries work for several days before replacement, while rechargeable batteries last all day and can be recharged nightly for years."}]}, {"_type": "block", "_key": "b002285", "style": "h4", "children": [{"_type": "span", "_key": "s002284", "text": "Are rechargeables better for the environment?"}]}, {"_type": "block", "_key": "b002287", "style": "normal", "children": [{"_type": "span", "_key": "s002286", "text": "Yes. Since they don’t need to be replaced every few days, they reduce the number of batteries that end up in landfills."}]}, {"_type": "block", "_key": "b002289", "style": "h4", "children": [{"_type": "span", "_key": "s002288", "text": "Can I switch my hearing aids from disposable to rechargeable?"}]}, {"_type": "block", "_key": "b002291", "style": "normal", "children": [{"_type": "span", "_key": "s002290", "text": "It depends on your hearing aid model. Our audiologist or hearing instrument specialist can check and let you know if your devices can be upgraded."}]}, {"_type": "block", "_key": "b002293", "style": "h2", "children": [{"_type": "span", "_key": "s002292", "text": "Hearing Aid Batteries in Virginia"}]}, {"_type": "block", "_key": "b002295", "style": "normal", "children": [{"_type": "span", "_key": "s002294", "text": "Need batteries for your hearing aids? Maico Audiological Services offers both disposable and rechargeable options for many models. Our team can help you choose the right type, show you how to get the best performance, and answer any questions you may have."}]}, {"_type": "block", "_key": "b002297", "style": "normal", "children": [{"_type": "span", "_key": "s002296", "text": "Call or visit us today to stock up on hearing aid batteries and keep your devices working at their best!"}]}, {"_type": "block", "_key": "b002299", "style": "normal", "children": [{"_type": "span", "_key": "s002298", "text": "Our offices are located in Newport News, VA, Chesapeake, VA, and Smithfield, VA."}]}]','Hearing Aid Batteries | Maico Audiological Services','Maico Audiological Services provides hearing aid batteries in Virginia to ensure that your hearing devices always function at their best. Visit us today!');
INSERT INTO "ec_services" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS5Y1MA3BRWPBAW6GHB4HP3X','custom-hearing-protection','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T02:51:25.000Z','2026-05-21 19:47:27','2026-05-22T02:51:25.000Z',NULL,NULL,1,'01KS5Y1MA3T7EDK4H3E4JMS90Y',NULL,'en','01KS5Y1MA3BRWPBAW6GHB4HP3X','Custom Hearing Protection','[{"_type": "block", "_key": "b002301", "style": "normal", "children": [{"_type": "span", "_key": "s002300", "text": "Maico Audiological Services provides custom hearing protection in Newport News, VA, Chesapeake, VA and Smithfield, VA.", "marks": ["strong"]}]}, {"_type": "block", "_key": "b002303", "style": "normal", "children": [{"_type": "span", "_key": "s002302", "text": "At Maico Audiological Services, we believe that protecting your hearing is just as important as treating hearing loss. Once hearing is damaged, it cannot grow back naturally. That’s why taking steps to protect your ears now is one of the best investments you can make in your lifelong hearing health. Whether you work around loud machines, enjoy live concerts, go on hunting trips, swim often, or just want a quiet night’s sleep, the right hearing protection can make a big difference. Our audiologist or hearing instrument specialist can help you choose the best hearing protection designed for comfort, safety, and your lifestyle needs. From advanced digital shooting protection to simple sleep plugs, we’ll help you choose the solution that’s right for you."}]}, {"_type": "block", "_key": "b002305", "style": "h2", "children": [{"_type": "span", "_key": "s002304", "text": "Types of Hearing Protection We Offer"}]}, {"_type": "block", "_key": "b002307", "style": "h3", "children": [{"_type": "span", "_key": "s002306", "text": "Ready-Made Hearing Protection"}]}, {"_type": "block", "_key": "b002309", "style": "normal", "children": [{"_type": "span", "_key": "s002308", "text": "These affordable, pre-formed options are quick to use and good for many everyday situations:"}]}, {"_type": "block", "_key": "b002311", "style": "normal", "children": [{"_type": "span", "_key": "s002310", "text": "Earplugs – Fit into the ear canal to reduce noise at concerts, sports games, or busy events."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002313", "style": "normal", "children": [{"_type": "span", "_key": "s002312", "text": "Semi-Insert Earplugs – Connected by a band and rest at the ear canal entrance, making them easy to remove."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002315", "style": "normal", "children": [{"_type": "span", "_key": "s002314", "text": "Earmuffs – Cover the whole ear to block outside noise."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002317", "style": "normal", "children": [{"_type": "span", "_key": "s002316", "text": "Note: While ready-made options are convenient, they may not fit as securely or comfortably as custom-made products.", "marks": ["em"]}]}, {"_type": "block", "_key": "b002319", "style": "h3", "children": [{"_type": "span", "_key": "s002318", "text": "Custom Hearing Protection"}]}, {"_type": "block", "_key": "b002321", "style": "normal", "children": [{"_type": "span", "_key": "s002320", "text": "Custom options are made to fit the exact shape of your ears, offering a perfect fit, comfort, and stronger protection."}]}, {"_type": "block", "_key": "b002323", "style": "normal", "children": [{"_type": "span", "_key": "s002322", "text": "Custom Earplugs – Ideal for musicians, workers, and anyone regularly around loud sounds."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002325", "style": "normal", "children": [{"_type": "span", "_key": "s002324", "text": "Impulse Filter Earplugs – Great for hunting or shooting. They block sudden gunshot noise but let you hear softer sounds like voices."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002327", "style": "normal", "children": [{"_type": "span", "_key": "s002326", "text": "Sleep Plugs – Soft plugs that reduce snoring and nighttime noise so you can rest peacefully."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002329", "style": "normal", "children": [{"_type": "span", "_key": "s002328", "text": "In-Ear Monitors (IEMs) – Used by musicians and performers to enjoy clear sound without harmful volume levels."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002331", "style": "normal", "children": [{"_type": "span", "_key": "s002330", "text": "Digital Hearing Protection (SoundGear) – Advanced devices for hunters, shooters, and workers that respond instantly to sudden loud sounds."}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002333", "style": "h2", "children": [{"_type": "span", "_key": "s002332", "text": "Types of Custom Ear Mold Materials"}]}, {"_type": "block", "_key": "b002335", "style": "normal", "children": [{"_type": "span", "_key": "s002334", "text": "Custom ear molds can be made from different materials depending on your comfort and needs:"}]}, {"_type": "block", "_key": "b002337", "style": "normal", "children": [{"_type": "span", "_key": "s002336", "text": "Acrylic"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002339", "style": "normal", "children": [{"_type": "span", "_key": "s002338", "text": "Vinyl"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002341", "style": "normal", "children": [{"_type": "span", "_key": "s002340", "text": "Silicone"}], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "b002343", "style": "h3", "children": [{"_type": "span", "_key": "s002342", "text": "FAQs About Custom Hearing Protection"}]}, {"_type": "block", "_key": "b002345", "style": "h4", "children": [{"_type": "span", "_key": "s002344", "text": "How long do custom earplugs last?"}]}, {"_type": "block", "_key": "b002347", "style": "normal", "children": [{"_type": "span", "_key": "s002346", "text": "With good care, custom earplugs can last 3 to 5 years. Their lifespan depends on how often you use them, how you clean them, and whether your ears change shape over time. We recommend occasional fit checks to make sure they’re still working well."}]}, {"_type": "block", "_key": "b002349", "style": "h4", "children": [{"_type": "span", "_key": "s002348", "text": "How do I clean my custom earplugs or molds?"}]}, {"_type": "block", "_key": "b002351", "style": "normal", "children": [{"_type": "span", "_key": "s002350", "text": "Wipe them with a soft, dry cloth after each use. For a deeper clean, use mild soap and warm water, then let them dry completely. Avoid harsh cleaners."}]}, {"_type": "block", "_key": "b002353", "style": "h4", "children": [{"_type": "span", "_key": "s002352", "text": "Can I wear custom plugs with helmets or other gear?"}]}, {"_type": "block", "_key": "b002355", "style": "normal", "children": [{"_type": "span", "_key": "s002354", "text": "Yes. Since custom plugs fit inside the ear, they work well with helmets, headsets, and other protective gear."}]}, {"_type": "block", "_key": "b002357", "style": "h4", "children": [{"_type": "span", "_key": "s002356", "text": "Will custom plugs block all sound?"}]}, {"_type": "block", "_key": "b002359", "style": "normal", "children": [{"_type": "span", "_key": "s002358", "text": "No. They are made to lower harmful noise while still allowing you to hear safe sounds, speech, and alarms."}]}, {"_type": "block", "_key": "b002361", "style": "h2", "children": [{"_type": "span", "_key": "s002360", "text": "Hearing Protection in Virginia"}]}, {"_type": "block", "_key": "b002363", "style": "normal", "children": [{"_type": "span", "_key": "s002362", "text": "At Maico Audiological Services, we offer both ready-made and custom solutions designed just for your needs and comfort. Call us today to schedule your appointment and explore your options for hearing protection in Newport News, VA, Chesapeake, VA and Smithfield, VA."}]}]','Custom Hearing Protection | Maico Audiological Services','Maico Audiological Services provides custom hearing protection in Virginia. Contact us today!');
INSERT INTO "ec_team" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","name","location","biography","featured_image","meta_title","meta_description","team_title") VALUES('01KS70BJZN72S0MH8601TNT9C1','hearing-instrument-specialist/jenny-flamini','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T12:51:03.000Z','2026-05-22T13:21:02.000Z','2026-05-22T13:21:02.000Z',NULL,NULL,3,'01KS722FSKTAXVKZ8QZBD5HDDF',NULL,'en','01KS70BJZN72S0MH8601TNT9C1','Jennifer Flamini, H.I.S, CDP','Chesapeake, VA, Smithfield, VA','[{"_type": "block", "_key": "01ks722fsj9ddgthhqkxrr3rqa", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsj5wf94b0gvnvb1gz7", "text": "Jenny Flamini is a hearing instrument specialist providing hearing tests, hearing aids, and professional hearing services in Smithfield, VA and Chesapeake,VA. ", "marks": ["strong", "em"]}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsjf8352xn3rk4kxyew", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsjbhn5v05dhdj9t53n", "text": "Jennifer Flamini, H.I.S., CDP, is a licensed Hearing Instrument Specialist and Certified Dementia Practitioner at Maico Audiological Services in Smithfield, VA. She is a passionate advocate for hearing health and is dedicated to improving the lives of those experiencing hearing loss.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsj0qwarm01193qbctk", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fsjfm8kv4gpx3194f2b", "text": "Journey into Hearing Healthcare", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsjg84br7zwfykjgrwh", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsjw3he8wg6bbe9gr08", "text": "Jennifer’s interest in hearing care began with her own family and friends. After accompanying loved ones to appointments for hearing loss, she witnessed firsthand the powerful impact hearing aids can have. These personal experiences inspired her to pursue training, licensure, and hands-on work in hearing healthcare, transforming her concern for family into a lifelong passion for helping others hear better.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsjq6thbzmpvyhn9d0g", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fsj3813dagscgcq98dp", "text": "Patient Care Philosophy", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsj8kphxkt2m13mvhk3", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsjjz0b348eqqnbpza2", "text": "Her mission is simple: to help as many people as possible achieve optimal hearing, enhancing their daily lives and strengthening connections with family and friends. She strives to provide a welcoming, supportive environment and the best possible care for each individual she serves.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsjhqq5g3kh6sggpr45", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fsjy3adx9zkh3t1a819", "text": "Personal Interests", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fsj1zyajg25y9avezzx", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fsjy7q43122n53rned4", "text": "Outside of her professional role, Jennifer enjoys photography, landscaping, DIY home projects, and spending time with her family, friends, and beloved pets.", "marks": []}], "markDefs": []}]','{"id": "01KS5SXE8CE2YDYYTQ1H1JVXZ0", "src": "/_emdash/api/media/file/01KS5SXE77YRAEAQ42VRSC5N0Q.webp", "alt": "", "width": 788, "height": 1024}','Jenny Flamini, H.I.S, CDP | Maico Audiological Services','Jenny Flamini is a hearing instrument specialist providing hearing tests, hearing aids, and professional hearing services in Smithfield, VA.','Hearing Instrument Specialist');
INSERT INTO "ec_team" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","name","location","biography","featured_image","meta_title","meta_description","team_title") VALUES('01KS70BK17MFTKKJD2RXDWFV42','audiologist/stephanie-howard','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T12:51:03.000Z','2026-05-22T13:21:02.000Z','2026-05-22T13:21:02.000Z',NULL,NULL,3,'01KS722FTTT2R27HCD85H0N8Q1',NULL,'en','01KS70BK17MFTKKJD2RXDWFV42','Stephanie Howard, M.A., CCC-A','Chesapeake, VA','[{"_type": "block", "_key": "01ks722ftsf9z6mcqw01j49n9b", "style": "normal", "children": [{"_type": "span", "_key": "01ks722ftstndzvmwnp324rpyv", "text": "Stephanie R. Howard is an audiologist providing hearing tests, hearing aids, sensorineural hearing loss treatment and evaluation, tinnitus evaluation and treatment in Chesapeake, VA.", "marks": ["strong", "em"]}], "markDefs": []}, {"_type": "block", "_key": "01ks722fts9j9w7qm134nr3tca", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fts9xs7zjqd39sc2afb", "text": "Stephanie Howard began her academic journey in audiology at East Carolina University, where she earned her Bachelor of Science degree. She went on to complete her Master of Arts degree in Audiology at the University of Tennessee–Knoxville.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722ftsyeyemt3mc5vvatx4", "style": "h2", "children": [{"_type": "span", "_key": "01ks722ftspa79k4f22fydr1zr", "text": "Professional Credentials", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fts0gwvh5gh3782kx49", "style": "normal", "children": [{"_type": "span", "_key": "01ks722ftsfvhhd5g2d8wf3qx3", "text": "With more than 30 years of professional experience, Stephanie holds multiple credentials that highlight her dedication to the field of audiology:", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722ftskh75j0dvhmey4qbx", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fts6gtgppdmfyyvyc3d", "text": "Certificate of Clinical Competence in Audiology (CCC-A)", "marks": ["strong"]}, {"_type": "span", "_key": "01ks722fts412akbywgf5f8q7b", "text": " from the American Speech-Language-Hearing Association (ASHA)", "marks": []}], "markDefs": [], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "01ks722fts58yfbc20gasec8td", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fts67hj6ey5y5kpn10y", "text": "Licensed Audiologist and Hearing Aid Specialist", "marks": ["strong"]}, {"_type": "span", "_key": "01ks722fts9hhzh24rcn64tez9", "text": " in the Commonwealth of Virginia", "marks": []}], "markDefs": [], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "01ks722ftsvg66kh4w8j337j95", "style": "normal", "children": [{"_type": "span", "_key": "01ks722fts7spyyefw3m1mafz0", "text": "Fellow", "marks": ["strong"]}, {"_type": "span", "_key": "01ks722ftsdxxjabk6azyej68v", "text": " of the American Academy of Audiology (AAA)", "marks": []}], "markDefs": [], "listItem": "bullet", "level": 1}, {"_type": "block", "_key": "01ks722fts1w5zx97fzhbtw546", "style": "h2", "children": [{"_type": "span", "_key": "01ks722ftsej5d813f3a45e110", "text": "Career Experience", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722fts773kaxp9t582tm52", "style": "normal", "children": [{"_type": "span", "_key": "01ks722ftsrnkkscs5xmbqn4hz", "text": "Stephanie has been serving the Tidewater area for over 25 years, offering expert audiological care and hearing aid services to patients of all ages. Prior to joining MAICO in April 2019, she spent decades working alongside ENT physicians as a clinical audiologist, where she specialized in diagnostic hearing evaluations and advanced hearing aid fittings for infants, children, and adults.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722ftsh2gqneb3nqx19aw0", "style": "h2", "children": [{"_type": "span", "_key": "01ks722fts8fc9c25rb0y51h74", "text": "Commitment to Patient Care", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks722ftsjk4gmxdv7788emjf", "style": "normal", "children": [{"_type": "span", "_key": "01ks722ftschbbew8jbpm6vd6c", "text": "With her extensive background and compassionate approach, Stephanie is dedicated to helping patients improve their hearing health and overall quality of life. She combines her technical expertise with genuine care, ensuring each patient receives personalized solutions that meet their unique needs.", "marks": []}], "markDefs": []}]','{"id": "01KS5SXFVX4PABGR737S1QKSFF", "src": "/_emdash/api/media/file/01KS5SXFTQ7EBMC2YDMDTGREA0.webp", "alt": "", "width": 683, "height": 1024}','Stephanie R. Howard, M.A., CCC-A | Maico Audiological Services','Stephanie R. Howard is an audiologist providing hearing tests, hearing aids, and professional audiology services in Chesapeake, VA.','Audiologist');
INSERT INTO "ec_team" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","name","location","biography","featured_image","meta_title","meta_description","team_title") VALUES('01KS70BK2E3KASZK6EV0GGT446','audiologist/tracey-hudson','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T12:51:03.000Z','2026-05-22T13:55:37.000Z','2026-05-22T13:21:02.000Z',NULL,NULL,5,'01KS73RJYXAWVCS2HTSW5PCQGV',NULL,'en','01KS70BK2E3KASZK6EV0GGT446','Tracey E. Hudson, Au.D., CCC-A','Newport News, VA','[{"_type":"block","_key":"01ks722fw0f0se8xwfe826111a","style":"normal","children":[{"_type":"span","_key":"01ks722fw04gcm5aa2s0d1dvz0","text":"Tracey E. Hudson is an audiologist providing hearing tests, hearing aids, sensorineural hearing loss treatment and evaluation, tinnitus evaluation and treatment in Newport News, VA.","marks":["strong","em"]}],"markDefs":[]},{"_type":"block","_key":"01ks722fw0h3wg1drdgbcc4w7f","style":"normal","children":[{"_type":"span","_key":"01ks722fw0g4m2s5r9fc2em9rf","text":"Tracey E. Hudson, Au.D., CCC-A, began her journey in audiology at East Carolina University in Greenville, North Carolina, where she completed her undergraduate degree. Motivated by her passion for helping others and her growing interest in hearing health, she went on to earn her Doctor of Audiology degree from Texas Tech University Health Sciences Center in 2013.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks722fw0w6cch7b1c4eaff5w","style":"h2","children":[{"_type":"span","_key":"01ks722fw02cx276eyhknhkz1k","text":"Professional Commitment","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks722fw0k5y0amz1c264hq7n","style":"normal","children":[{"_type":"span","_key":"01ks722fw073r95knmm12xwqnh","text":"As an audiologist and healthcare provider, Dr. Hudson is deeply committed to ensuring her patients never miss the important moments in life because of hearing loss. She believes in providing compassionate, individualized care that improves not only hearing but also overall quality of life.","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks722fw06gzb0jmn1jj9vahz","style":"h2","children":[{"_type":"span","_key":"01ks722fw0ajdy4qkvmfqdnnjy","text":"Areas of Expertise","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks722fw08tz7v09fb0dts57x","style":"normal","children":[{"_type":"span","_key":"01ks722fw0jt50jrawtxevvvq2","text":"Dr. Hudson’s extensive knowledge, advanced training, and clinical experience allow her to provide comprehensive evaluation and treatment for a wide range of auditory system disorders, including:","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks722fw04ab2ky71rqnzkd0a","style":"normal","children":[{"_type":"span","_key":"01ks722fw0v3q1d5b1xh9cvc6p","text":"Hearing Loss – helping patients of all ages find effective hearing solutions.","marks":[]}],"markDefs":[],"listItem":"bullet","level":1},{"_type":"block","_key":"01ks722fw0jkjkexn4gh2xwyj6","style":"normal","children":[{"_type":"span","_key":"01ks722fw04wf9k43v6cpq9wdf","text":"Tinnitus – offering evaluation and management strategies to reduce the impact of ringing in the ears.","marks":[]}],"markDefs":[],"listItem":"bullet","level":1},{"_type":"block","_key":"01ks722fw0bbdxqm43edm0hqth","style":"normal","children":[{"_type":"span","_key":"01ks722fw0evatza9fy44tmqfe","text":"Balance Disorders – assessing and treating vestibular issues that affect stability and daily activities.","marks":[]}],"markDefs":[],"listItem":"bullet","level":1},{"_type":"block","_key":"01ks722fw0gxwv3vcd1sm792tc","style":"h2","children":[{"_type":"span","_key":"01ks722fw0vnkcf9ychpspjrms","text":"Patient Care Philosophy","marks":[]}],"markDefs":[]},{"_type":"block","_key":"01ks722fw0cerkf7qw9r4fs4qa","style":"normal","children":[{"_type":"span","_key":"01ks722fw0879ym5apqd3mq59q","text":"Dr. Hudson cares for patients across all stages of life, from newborns and children to adults and seniors. Her approach emphasizes not only addressing hearing and balance concerns but also supporting patients in staying connected, engaged, and confident in their daily lives.","marks":[]}],"markDefs":[]}]','{"id": "01KS5SXAR48BYJVP0MPA4N733F", "src": "/_emdash/api/media/file/01KS5SXAP7QZKCZ4ASS2F7G2FJ.png", "alt": "Professional headshot of woman with brown hair wearing blue patterned top", "width": 300, "height": 299}','Tracey E. Hudson, Au.D., CCC-A | Maico Audiological Services','Tracey E. Hudson is an audiologist providing hearing tests, hearing aids abd professional audiology services in Newport News, VA.','Audiologist');
