INSERT INTO "ec_utility_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content","meta_title","meta_description") VALUES('01KS69M9J8BP07S9CZWYR5E5BS','insurance','published','01KS5S2H9D5GVDNPH6HQ00BNCN',NULL,'2026-05-22T06:13:51.000Z','2026-05-22T06:13:51.000Z','2026-05-22T06:13:51.000Z',NULL,NULL,1,'01KS69M9J84C4MQMMR5B7B78D7',NULL,'en','01KS69M9J8BP07S9CZWYR5E5BS','Insurance and Billing FAQs','[{"_type": "block", "_key": "01ks69m9j81h0589051dvrbqfa", "style": "normal", "children": [{"_type": "span", "_key": "01ks69m9j86pzep1yb34r91f05", "text": "At Maico Audiological Services, we are dedicated to helping patients in Newport News, Chesapeake, and Smithfield, VA find the right hearing aids at affordable prices. In addition to offering a wide variety of hearing aids to fit every budget, we provide flexible payment options, including insurance, credit cards, and financing plans. Our goal is to make better hearing accessible to everyone.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j809v27262yqm5z3fv", "style": "h2", "children": [{"_type": "span", "_key": "01ks69m9j8nbjq34nrajjqyfp2", "text": "Using Insurance to Pay for Hearing Aids", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8p5ea3bw9b4stdj4d", "style": "normal", "children": [{"_type": "span", "_key": "01ks69m9j847yc0kmn0dx42p2m", "text": "We accept a wide variety of insurance plans and have a dedicated team of insurance experts who will verify your benefits prior to your appointment. This ensures you clearly understand your coverage and all available options at the time of your visit.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8s8a9v31jacvmwc6n", "style": "h2", "children": [{"_type": "span", "_key": "01ks69m9j8fj4mhynw5qx1vmc7", "text": "Hearing Aid Financing Options", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8my6bvqf2c91444fp", "style": "h3", "children": [{"_type": "span", "_key": "01ks69m9j82dv71djbekaxreh6", "text": "CareCredit®", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8gx9f13w89qs56j3k", "style": "normal", "children": [{"_type": "span", "_key": "01ks69m9j8x6xmbcmc5c438sfr", "text": "We proudly accept CareCredit, a healthcare credit card designed for medical expenses, including hearing services, hearing tests, and hearing aids. CareCredit offers special financing options, helping you spread payments over time for costs not covered by insurance.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8knxyk6h2mgrak0ww", "style": "h3", "children": [{"_type": "span", "_key": "01ks69m9j8advtx4gbwct50j9p", "text": "Allegro Credit®", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8587k7sxxzst7j6ar", "style": "normal", "children": [{"_type": "span", "_key": "01ks69m9j85k7p3xyp6szpzqez", "text": "We also accept Allegro Credit, which provides flexible payment plans without application fees, prepayment penalties, or hidden charges. This option makes financing your hearing aids simple and transparent.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8qkperafgtxs8f1n8", "style": "h2", "children": [{"_type": "span", "_key": "01ks69m9j8d669xzc4hk09b9t1", "text": "Find the Best Payment Option for You", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8w73v5we9avhyt9kt", "style": "normal", "children": [{"_type": "span", "_key": "01ks69m9j8wzs71r4jmdwcr2mb", "text": "Whether through insurance, credit card, or financing, our team is here to help you choose the best payment method for your needs. We’re committed to making hearing care affordable and accessible so you never miss out on life’s important moments.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j85z6yz5kjqakew6fp", "style": "normal", "children": [{"_type": "span", "_key": "01ks69m9j83cdkyqzqtj3jjt5t", "text": "Call or text us today to explore your coverage and payment options.", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8kyj4e568we22gnts", "style": "h2", "children": [{"_type": "span", "_key": "01ks69m9j8x8pm4m9sw91qz17z", "text": "Questions? We’re Here to Help!", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8nk9gqcbm1ykqack4", "style": "normal", "children": [{"_type": "span", "_key": "01ks69m9j8caaxcn0edqywar4z", "text": "If you have any questions about your insurance, billing, or financing options, don’t hesitate to contact us. ", "marks": []}], "markDefs": []}, {"_type": "block", "_key": "01ks69m9j8zzqfw5aytm1aps6e", "style": "normal", "children": [{"_type": "span", "_key": "01ks69m9j8h26hp34a760ssmv4", "text": "Call us today to learn more or to schedule an appointment!", "marks": []}], "markDefs": []}]','Insurance and Billing | Maico Audiological Services','Learn more about Maico Audiological Services accepted insurance plans, billing, and payments.');
